use std::io::{self, Read, Write};
use std::collections::HashMap;
use rayon::prelude::*;

#[derive(Clone)]
struct Dsu {
    parent: Vec<usize>,
    weight: Vec<u8>,
    rank: Vec<u8>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n).collect(),
            weight: vec![0; n],
            rank: vec![0; n],
        }
    }

    fn find(&mut self, i: usize) -> (usize, u8) {
        if self.parent[i] != i {
            let (root, w) = self.find(self.parent[i]);
            self.parent[i] = root;
            self.weight[i] ^= w;
        }
        (self.parent[i], self.weight[i])
    }

    fn union(&mut self, i: usize, j: usize, rel: u8) -> bool {
        let (root_i, w_i) = self.find(i);
        let (root_j, w_j) = self.find(j);
        if root_i != root_j {
            let w_edge = w_i ^ w_j ^ rel;
            if self.rank[root_i] < self.rank[root_j] {
                self.parent[root_i] = root_j;
                self.weight[root_i] = w_edge;
            } else {
                self.parent[root_j] = root_i;
                self.weight[root_j] = w_edge;
                if self.rank[root_i] == self.rank[root_j] {
                    self.rank[root_i] += 1;
                }
            }
            true
        } else {
            (w_i ^ w_j) == rel
        }
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_whitespace();

    let m_str = iter.next();
    if m_str.is_none() { return; }
    let m: usize = m_str.unwrap().parse().unwrap();
    let n: usize = iter.next().unwrap().parse().unwrap();

    struct Obs<'a> {
        u: &'a str,
        v: &'a str,
        rel: u8,
    }

    let mut observations = Vec::with_capacity(m);
    for _ in 0..m {
        let u = iter.next().unwrap();
        let v = iter.next().unwrap();
        let type_str = iter.next().unwrap();
        let rel = if type_str == "parallel" { 0 } else { 1 };
        observations.push(Obs { u, v, rel });
    }

    let mut queries = Vec::with_capacity(n);
    for _ in 0..n {
        let u = iter.next().unwrap();
        let v = iter.next().unwrap();
        queries.push((u, v));
    }

    let mut name_to_id = HashMap::new();
    let mut next_id = 0;

    for obs in &observations {
        if !name_to_id.contains_key(obs.u) {
            name_to_id.insert(obs.u, next_id);
            next_id += 1;
        }
        if !name_to_id.contains_key(obs.v) {
            name_to_id.insert(obs.v, next_id);
            next_id += 1;
        }
    }

    let num_obs_nodes = next_id;
    let mut dsu = Dsu::new(num_obs_nodes);

    for obs in &observations {
        let u_id = name_to_id[obs.u];
        let v_id = name_to_id[obs.v];
        if !dsu.union(u_id, v_id, obs.rel) {
            println!("Waterloo");
            return;
        }
    }

    // Flatten DSU for parallel read-only access
    for i in 0..num_obs_nodes {
        dsu.find(i);
    }

    let results: Vec<&str> = queries.par_iter().map(|(u_name, v_name)| {
        if u_name == v_name {
            return "parallel";
        }

        let u_opt = name_to_id.get(*u_name);
        let v_opt = name_to_id.get(*v_name);

        match (u_opt, v_opt) {
            (Some(&u_id), Some(&v_id)) => {
                let root_u = dsu.parent[u_id];
                let root_v = dsu.parent[v_id];

                if root_u != root_v {
                    "unknown"
                } else {
                    let w = dsu.weight[u_id] ^ dsu.weight[v_id];
                    if w == 0 { "parallel" } else { "intersect" }
                }
            },
            _ => "unknown"
        }
    }).collect();

    let mut out = io::stdout().lock();
    for res in results {
        writeln!(out, "{}", res).unwrap();
    }
}

