    fn write(&mut self, bytes: &[u8]) {
        for &byte in bytes {
            self.hash = (self.hash.rotate_left(5) ^ (byte as u64)).wrapping_mul(0x517cc1b727220a95);
        }
    }
    fn finish(&self) -> u64 {
        self.hash
    }
}

type FastMap<K, V> = HashMap<K, V, BuildHasherDefault<FxHasher>>;

struct Dsu {
    parent: Vec<usize>,
    rel: Vec<u8>,
}

impl Dsu {
    fn new(capacity: usize) -> Self {
        Dsu {
            parent: Vec::with_capacity(capacity),
            rel: Vec::with_capacity(capacity),
        }
    }

    fn add_node(&mut self) -> usize {
        let id = self.parent.len();
        self.parent.push(id);
        self.rel.push(0);
        id
    }

    // Returns (root, rel_to_root)
    // Uses path compression. Requires a mutable buffer 'path' to avoid allocations.
    fn find(&mut self, mut i: usize, path: &mut Vec<usize>) -> (usize, u8) {
        path.clear();
        while self.parent[i] != i {
            path.push(i);
            i = self.parent[i];
        }
        let root = i;

        // Path compression with relationship update
        // Iterate in reverse to propagate relationships from root downwards
        for &node in path.iter().rev() {
            let p = self.parent[node];
            let r_p = self.rel[p];
            self.parent[node] = root;
            self.rel[node] ^= r_p;
        }

        (root, if path.is_empty() { 0 } else { self.rel[path[0]] })
    }

    fn union(&mut self, u: usize, v: usize, type_val: u8, path: &mut Vec<usize>) -> bool {
        let (root_u, rel_u) = self.find(u, path);
        let (root_v, rel_v) = self.find(v, path);

        if root_u != root_v {
            self.parent[root_u] = root_v;
            self.rel[root_u] = rel_u ^ rel_v ^ type_val;
            true
        } else {
            (rel_u ^ rel_v) == type_val
        }
    }

    // Flatten the DSU so that every node points directly to its root.
    // This allows O(1) read-only access in the parallel phase.
    fn flatten(&mut self) {
        let mut path = Vec::with_capacity(64);
        let len = self.parent.len();
        for i in 0..len {
            self.find(i, &mut path);
        }
    }
}

