// High-performance hasher optimized for small keys
#[derive(Default)]
struct FxHasher {
    hash: u64,
}

impl Hasher for FxHasher {
    #[inline]
    fn write(&mut self, mut bytes: &[u8]) {
        while bytes.len() >= 8 {
            let n = u64::from_ne_bytes(bytes[..8].try_into().unwrap());
            self.hash = (self.hash.rotate_left(5) ^ n).wrapping_mul(0x517cc1b727220a95);
            bytes = &bytes[8..];
        }
        for &byte in bytes {
            self.hash = (self.hash.rotate_left(5) ^ (byte as u64)).wrapping_mul(0x517cc1b727220a95);
        }
    }
    #[inline]
    fn finish(&self) -> u64 {
        self.hash
    }
}

type FastMap<'a> = HashMap<&'a [u8], u32, BuildHasherDefault<FxHasher>>;

struct Tokenizer<'a> {
    data: &'a [u8],
    pos: usize,
}

impl<'a> Tokenizer<'a> {
    fn new(data: &'a [u8]) -> Self {
        Self { data, pos: 0 }
    }

    #[inline(always)]
    fn next(&mut self) -> Option<&'a [u8]> {
        if self.pos >= self.data.len() { return None; }
        while self.pos < self.data.len() && self.data[self.pos] <= b' ' {
            self.pos += 1;
        }
        if self.pos >= self.data.len() { return None; }
        let start = self.pos;
        while self.pos < self.data.len() && self.data[self.pos] > b' ' {
            self.pos += 1;
        }
        Some(&self.data[start..self.pos])
    }

    fn next_usize(&mut self) -> Option<usize> {
        let s = self.next()?;
        let mut v = 0;
        for &b in s {
            if b >= b'0' && b <= b'9' {
                v = v * 10 + (b - b'0') as usize;
            }
        }
        Some(v)
    }
}

fn main() {
    let mut input = Vec::new();
    let stdin = io::stdin();
    if stdin.lock().read_to_end(&mut input).is_err() { return; }

    let mut tokenizer = Tokenizer::new(&input);
    let m = tokenizer.next_usize().unwrap_or(0);
    let n = tokenizer.next_usize().unwrap_or(0);

    // Capacity estimation
    let cap = (m * 2).max(100);
    let mut name_to_id = FastMap::with_capacity_and_hasher(cap, BuildHasherDefault::default());

    // dsu[i] stores (parent << 1) | relation_to_parent
    let mut dsu: Vec<u32> = Vec::with_capacity(cap);
    let mut rank: Vec<u8> = Vec::with_capacity(cap);
    let mut next_id = 0u32;

    let mut path_buf = Vec::with_capacity(64);

    for _ in 0..m {
        let u_name = tokenizer.next().unwrap();
        let v_name = tokenizer.next().unwrap();
        let type_str = tokenizer.next().unwrap();

        let u = if let Some(&id) = name_to_id.get(u_name) {
            id
        } else {
            let id = next_id;
            next_id += 1;
            name_to_id.insert(u_name, id);
            dsu.push(id << 1);
            rank.push(0);
            id
        };

        let v = if let Some(&id) = name_to_id.get(v_name) {
            id
        } else {
            let id = next_id;
            next_id += 1;
            name_to_id.insert(v_name, id);
            dsu.push(id << 1);
            rank.push(0);
            id
        };

