        // Find U
        path_buf.clear();
        let mut curr = u;
        while (dsu[curr as usize] >> 1) != curr {
            path_buf.push(curr);
            curr = dsu[curr as usize] >> 1;
        }
        let root_u = curr;

        // Compress U
        for &node in path_buf.iter().rev() {
            let entry = dsu[node as usize];
            let p = entry >> 1;
            let rel_node_p = (entry & 1) as u8;
            let rel_p_root = (dsu[p as usize] & 1) as u8;
            dsu[node as usize] = (root_u << 1) | ((rel_node_p ^ rel_p_root) as u32);
