#[derive(Clone)]
struct Dsu {
    parent: Vec<usize>,
    diff: Vec<u8>,
    rank: Vec<u8>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n).collect(),
            diff: vec![0; n],
            rank: vec![0; n],
        }
    }

    fn find(&mut self, i: usize) -> (usize, u8) {
        let mut path = Vec::new();
        let mut curr = i;
        while self.parent[curr] != curr {
            path.push(curr);
            curr = self.parent[curr];
        }
        let root = curr;

        while let Some(node) = path.pop() {
            let p = self.parent[node];
            self.diff[node] ^= self.diff[p];
            self.parent[node] = root;
        }
        (root, self.diff[i])
    }

    fn union(&mut self, i: usize, j: usize, d: u8) -> bool {
        let (root_i, diff_i) = self.find(i);
        let (root_j, diff_j) = self.find(j);
        if root_i != root_j {
            let new_diff = diff_i ^ diff_j ^ d;
            if self.rank[root_i] < self.rank[root_j] {
                self.parent[root_i] = root_j;
                self.diff[root_i] = new_diff;
            } else {
                self.parent[root_j] = root_i;
                self.diff[root_j] = new_diff;
                if self.rank[root_i] == self.rank[root_j] {
                    self.rank[root_i] += 1;
                }
            }
            true
        } else {
            (diff_i ^ diff_j) == d
        }
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut tokens = input.split_ascii_whitespace();

    let m_str = tokens.next();
    let n_str = tokens.next();

    if m_str.is_none() || n_str.is_none() {
        return;
    }

    let m: usize = m_str.unwrap().parse().unwrap();
    let n: usize = n_str.unwrap().parse().unwrap();

    let mut name_to_id: HashMap<&str, usize> = HashMap::new();
    let mut next_id = 0;

    let mut raw_obs = Vec::with_capacity(m);
    for _ in 0..m {
        let u = tokens.next().unwrap();
        let v = tokens.next().unwrap();
        let t = tokens.next().unwrap();
        raw_obs.push((u, v, t));
    }

    let mut raw_queries = Vec::with_capacity(n);
    for _ in 0..n {
        let u = tokens.next().unwrap();
        let v = tokens.next().unwrap();
        raw_queries.push((u, v));
    }

    for (u, v, _) in &raw_obs {
        if !name_to_id.contains_key(u) { name_to_id.insert(u, next_id); next_id += 1; }
        if !name_to_id.contains_key(v) { name_to_id.insert(v, next_id); next_id += 1; }
    }
    for (u, v) in &raw_queries {
        if !name_to_id.contains_key(u) { name_to_id.insert(u, next_id); next_id += 1; }
        if !name_to_id.contains_key(v) { name_to_id.insert(v, next_id); next_id += 1; }
    }

    let mut dsu = Dsu::new(next_id);

    for (u_str, v_str, t_str) in raw_obs {
        let u = name_to_id[u_str];
        let v = name_to_id[v_str];
        let d = if t_str == "intersect" { 1 } else { 0 };

        if !dsu.union(u, v, d) {
            println!("Waterloo");
            return;
        }
    }

    for i in 0..next_id {
        dsu.find(i);
    }

    let parents = dsu.parent;
    let diffs = dsu.diff;

    let query_indices: Vec<(usize, usize)> = raw_queries.iter().map(|(u, v)| {
        (name_to_id[u], name_to_id[v])
    }).collect();

    let results: Vec<&str> = query_indices.into_par_iter().map(|(u, v)| {
        let root_u = parents[u];
        let root_v = parents[v];

        if root_u != root_v {
            "unknown"
        } else {
            if (diffs[u] ^ diffs[v]) == 0 {
                "parallel"
            } else {
                "intersect"
            }
        }
    }).collect();

    let stdout = io::stdout();
    let mut handle = io::BufWriter::new(stdout.lock());
    for res in results {
        writeln!(handle, "{}", res).unwrap();
    }
}

