use std::io::{self, Read, Write};
use std::collections::HashMap;
use std::hash::{BuildHasherDefault, Hasher};
use std::convert::TryInto;
use rayon::prelude::*;

// High-performance hasher optimized for small keys
#[derive(Default)]
struct FxHasher {
    hash: u64,
}

impl Hasher for FxHasher {
    #[inline]
    fn write(&mut self, mut bytes: &[u8]) {
        while bytes.len() >= 8 {
            let n = u64::from_ne_bytes(bytes[..8].try_into().unwrap());
            self.hash = (self.hash.rotate_left(5) ^ n).wrapping_mul(0x517cc1b727220a95);
            bytes = &bytes[8..];
        }
        for &byte in bytes {
            self.hash = (self.hash.rotate_left(5) ^ (byte as u64)).wrapping_mul(0x517cc1b727220a95);
        }
    }
    #[inline]
    fn finish(&self) -> u64 {
        self.hash
    }
}

type FastMap<'a> = HashMap<&'a [u8], u32, BuildHasherDefault<FxHasher>>;

struct Tokenizer<'a> {
    data: &'a [u8],
    pos: usize,
}

impl<'a> Tokenizer<'a> {
    fn new(data: &'a [u8]) -> Self {
        Self { data, pos: 0 }
    }

    #[inline(always)]
    fn next(&mut self) -> Option<&'a [u8]> {
        if self.pos >= self.data.len() { return None; }
        while self.pos < self.data.len() && self.data[self.pos] <= b' ' {
            self.pos += 1;
        }
        if self.pos >= self.data.len() { return None; }
        let start = self.pos;
        while self.pos < self.data.len() && self.data[self.pos] > b' ' {
            self.pos += 1;
        }
        Some(&self.data[start..self.pos])
    }

    fn next_usize(&mut self) -> Option<usize> {
        let s = self.next()?;
        let mut v = 0;
        for &b in s {
            if b >= b'0' && b <= b'9' {
                v = v * 10 + (b - b'0') as usize;
            }
        }
        Some(v)
    }
}

fn main() {
    let mut input = Vec::new();
    let stdin = io::stdin();
    if stdin.lock().read_to_end(&mut input).is_err() { return; }

    let mut tokenizer = Tokenizer::new(&input);
    let m = tokenizer.next_usize().unwrap_or(0);
    let n = tokenizer.next_usize().unwrap_or(0);

    // Capacity estimation
    let cap = (m * 2).max(100);
    let mut name_to_id = FastMap::with_capacity_and_hasher(cap, BuildHasherDefault::default());

    // dsu[i] stores (parent << 1) | relation_to_parent
    let mut dsu: Vec<u32> = Vec::with_capacity(cap);
    let mut rank: Vec<u8> = Vec::with_capacity(cap);
    let mut next_id = 0u32;

    let mut path_buf = Vec::with_capacity(64);

    for _ in 0..m {
        let u_name = tokenizer.next().unwrap();
        let v_name = tokenizer.next().unwrap();
        let type_str = tokenizer.next().unwrap();

        let u = if let Some(&id) = name_to_id.get(u_name) {
            id
        } else {
            let id = next_id;
            next_id += 1;
            name_to_id.insert(u_name, id);
            dsu.push(id << 1);
            rank.push(0);
            id
        };

        let v = if let Some(&id) = name_to_id.get(v_name) {
            id
        } else {
            let id = next_id;
            next_id += 1;
            name_to_id.insert(v_name, id);
            dsu.push(id << 1);
            rank.push(0);
            id
        };

        let relation = if type_str[0] == b'p' { 0 } else { 1 };

        // Find U
        path_buf.clear();
        let mut curr = u;
        while (dsu[curr as usize] >> 1) != curr {
            path_buf.push(curr);
            curr = dsu[curr as usize] >> 1;
        }
        let root_u = curr;

        // Compress U
        for &node in path_buf.iter().rev() {
            let entry = dsu[node as usize];
            let p = entry >> 1;
            let rel_node_p = (entry & 1) as u8;
            let rel_p_root = (dsu[p as usize] & 1) as u8;
            dsu[node as usize] = (root_u << 1) | ((rel_node_p ^ rel_p_root) as u32);
        }
        let val_u = (dsu[u as usize] & 1) as u8;

        // Find V
        path_buf.clear();
        let mut curr = v;
        while (dsu[curr as usize] >> 1) != curr {
            path_buf.push(curr);
            curr = dsu[curr as usize] >> 1;
        }
        let root_v = curr;

        // Compress V
        for &node in path_buf.iter().rev() {
            let entry = dsu[node as usize];
            let p = entry >> 1;
            let rel_node_p = (entry & 1) as u8;
            let rel_p_root = (dsu[p as usize] & 1) as u8;
            dsu[node as usize] = (root_v << 1) | ((rel_node_p ^ rel_p_root) as u32);
        }
        let val_v = (dsu[v as usize] & 1) as u8;

        if root_u != root_v {
            let r_u = rank[root_u as usize];
            let r_v = rank[root_v as usize];
            let new_rel = val_u ^ val_v ^ relation;

            if r_u < r_v {
                dsu[root_u as usize] = (root_v << 1) | (new_rel as u32);
            } else {
                dsu[root_v as usize] = (root_u << 1) | (new_rel as u32);
                if r_u == r_v {
                    rank[root_u as usize] += 1;
                }
            }
        } else {
            if (val_u ^ val_v) != relation {
                println!("Waterloo");
                return;
            }
        }
    }

    // Flatten DSU
    for i in 0..next_id {
        let mut curr = i;
        if (dsu[curr as usize] >> 1) == curr { continue; }

        path_buf.clear();
        while (dsu[curr as usize] >> 1) != curr {
            path_buf.push(curr);
            curr = dsu[curr as usize] >> 1;
        }
        let root = curr;
        for &node in path_buf.iter().rev() {
            let entry = dsu[node as usize];
            let p = entry >> 1;
            let rel_node_p = (entry & 1) as u8;
            let rel_p_root = (dsu[p as usize] & 1) as u8;
            dsu[node as usize] = (root << 1) | ((rel_node_p ^ rel_p_root) as u32);
        }
    }

    let mut queries = Vec::with_capacity(n);
    for _ in 0..n {
        queries.push((tokenizer.next().unwrap(), tokenizer.next().unwrap()));
    }

    let dsu = &dsu;
    let name_to_id = &name_to_id;

    let results: Vec<&[u8]> = queries.par_iter().map(|&(u_name, v_name)| {
        if u_name == v_name {
            return b"parallel".as_slice();
        }

        if let (Some(&u), Some(&v)) = (name_to_id.get(u_name), name_to_id.get(v_name)) {
            let entry_u = unsafe { *dsu.get_unchecked(u as usize) };
            let entry_v = unsafe { *dsu.get_unchecked(v as usize) };

            let root_u = entry_u >> 1;
            let root_v = entry_v >> 1;

            if root_u != root_v {
                b"unknown"
            } else {
                if (entry_u & 1) == (entry_v & 1) {
                    b"parallel"
                } else {
                    b"intersect"
                }
            }
        } else {
            b"unknown"
        }
    }).collect();

    let stdout = io::stdout();
    let mut out = io::BufWriter::new(stdout.lock());
    for res in results {
        out.write_all(res).unwrap();
        out.write_all(b"\n").unwrap();
    }
}

