struct Dsu {
    parent: Vec<usize>,
    weight: Vec<u8>,
    rank: Vec<u8>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n).collect(),
            weight: vec![0; n],
            rank: vec![0; n],
        }
    }

    fn find(&mut self, i: usize) -> (usize, u8) {
        if self.parent[i] != i {
            let (root, w) = self.find(self.parent[i]);
            self.parent[i] = root;
            self.weight[i] ^= w;
        }
        (self.parent[i], self.weight[i])
    }

    fn union(&mut self, i: usize, j: usize, rel: u8) -> bool {
        let (root_i, w_i) = self.find(i);
        let (root_j, w_j) = self.find(j);
        if root_i != root_j {
            let w_edge = w_i ^ w_j ^ rel;
            if self.rank[root_i] < self.rank[root_j] {
                self.parent[root_i] = root_j;
                self.weight[root_i] = w_edge;
            } else {
                self.parent[root_j] = root_i;
                self.weight[root_j] = w_edge;
                if self.rank[root_i] == self.rank[root_j] {
                    self.rank[root_i] += 1;
                }
            }
            true
        } else {
            (w_i ^ w_j) == rel
        }
    }
}

