use std::io::{self, Read};
use rayon::prelude::*;

fn main() {
    let mut input = String::new();
    // Read all input from stdin
    io::stdin().read_to_string(&mut input).unwrap();

    let mut lines = input.lines();

    // Find the first non-empty line to get dimensions
    let first_line = loop {
        match lines.next() {
            Some(l) => {
                let trimmed = l.trim();
                if !trimmed.is_empty() {
                    break trimmed;
                }
            }
            None => return,
        }
    };

    let mut dims = first_line.split_whitespace();
    let n_str = dims.next();
    let m_str = dims.next();

    if n_str.is_none() || m_str.is_none() {
        return;
    }

    let n: usize = n_str.unwrap().parse().unwrap();
    let m: usize = m_str.unwrap().parse().unwrap();

    // Collect the grid rows, filtering out any empty lines
    let rows: Vec<&str> = lines
        .map(|l| l.trim())
        .filter(|l| !l.is_empty())
        .take(n)
        .collect();

    // Parallel processing to compute the target index for each cell
    // edges[i] will store the index of the cell that cell i points to.
    let edges: Vec<usize> = rows.par_iter()
        .enumerate()
        .flat_map(|(r, row_str)| {
            // Process each row to produce a vector of targets
            row_str.chars().enumerate().map(move |(c, ch)| {
                let (dr, dc) = match ch {
                    'N' => (-1, 0),
                    'S' => (1, 0),
                    'E' => (0, 1),
                    'W' => (0, -1),
                    _ => (0, 0),
                };

                // Calculate neighbor coordinates
                // We assume the input ensures cats stay within the city boundaries
                let nr = (r as isize + dr) as usize;
                let nc = (c as isize + dc) as usize;

                nr * m + nc
            }).collect::<Vec<usize>>()
        })
        .collect();

    let total_nodes = n * m;

    // Initialize DSU parent array in parallel
    let mut parent: Vec<usize> = (0..total_nodes).into_par_iter().collect();

    // Sequential DSU execution
    // We iterate through all edges and union the sets of the source and target nodes.
    // The number of traps is equal to the number of connected components in this functional graph.
    // We limit the loop to edges.len() to handle potential input truncation gracefully.
    for i in 0..edges.len() {
        let target = edges[i];

        // Iterative find with path halving for i
        let mut root_i = i;
        while root_i != parent[root_i] {
            parent[root_i] = parent[parent[root_i]];
            root_i = parent[root_i];
        }

        // Iterative find with path halving for target
        let mut root_target = target;
        while root_target != parent[root_target] {
            parent[root_target] = parent[parent[root_target]];
            root_target = parent[root_target];
        }

        // Union sets
        if root_i != root_target {
            parent[root_i] = root_target;
        }
    }

    // Count the number of disjoint sets (roots) in parallel
    // A node i is a root if parent[i] == i
    let num_traps = parent.par_iter()
        .enumerate()
        .filter(|(i, &p)| *i == p)
        .count();

    println!("{}", num_traps);
}

