fn main() {
    let mut input = String::new();
    if io::stdin().read_to_string(&mut input).is_err() {
        return;
    }

    let mut tokens = input.split_whitespace();
    let n_str = tokens.next();
    let m_str = tokens.next();

    if n_str.is_none() || m_str.is_none() {
        return;
    }

    let n: usize = n_str.unwrap().parse().unwrap();
    let m: usize = m_str.unwrap().parse().unwrap();

    // Collect all grid characters from the remaining tokens.
    // This handles both dense strings and space-separated characters.
    let grid_chars: Vec<u8> = tokens.flat_map(|s| s.bytes()).collect();

    if grid_chars.len() != n * m {
        // Fallback or error handling if input is malformed, 
        // though problem statement guarantees valid input.
        return;
    }

    // Parallel edge generation
    // Each cell (u) has a directed edge to the cell (v) indicated by the character.
    let edges: Vec<(u32, u32)> = grid_chars.par_iter().enumerate().map(|(i, &byte)| {
        let u = i as u32;
        let r = i / m;
        let c = i % m;

        let (dr, dc) = match byte {
            b'N' => (-1, 0),
            b'S' => (1, 0),
            b'E' => (0, 1),
            b'W' => (0, -1),
            _ => (0, 0),
        };

        let nr = (r as isize + dr) as usize;
        let nc = (c as isize + dc) as usize;

        let v = (nr * m + nc) as u32;
        (u, v)
    }).collect();

    let num_nodes = (n * m) as u32;
    // Initialize DSU parent array. Each node is its own parent initially.
    let parent: Vec<AtomicU32> = (0..num_nodes).into_par_iter()
        .map(|i| AtomicU32::new(i))
        .collect();

    // Parallel DSU loop (Shiloach-Vishkin style approximation)
    loop {
        let changed = AtomicBool::new(false);

        // Hooking phase: Connect roots of different components
        edges.par_iter().for_each(|&(u, v)| {
            let root_u = get_root(&parent, u);
            let root_v = get_root(&parent, v);

            if root_u != root_v {
                // Determine direction of merge: larger ID to smaller ID to prevent cycles
                let (src, dst) = if root_u > root_v {
                    (root_u, root_v)
                } else {
                    (root_v, root_u)
                };

                // Attempt to link src to dst.
                // We use compare_exchange to ensure we only update if src is still a root.
                if parent[src as usize].compare_exchange(
                    src,
                    dst,
                    Ordering::SeqCst,
                    Ordering::Relaxed
                ).is_ok() {
                    changed.store(true, Ordering::Relaxed);
                }
            }
        });

        // Compression phase: Pointer jumping to flatten trees
        let comp_changed = AtomicBool::new(false);
        parent.par_iter().for_each(|p_atomic| {
            let p = p_atomic.load(Ordering::Relaxed);
            let pp = parent[p as usize].load(Ordering::Relaxed);
            if p != pp {
                p_atomic.store(pp, Ordering::Relaxed);
                comp_changed.store(true, Ordering::Relaxed);
            }
        });

        // Terminate if no structural changes occurred
        if !changed.load(Ordering::Relaxed) && !comp_changed.load(Ordering::Relaxed) {
            break;
        }
    }

    // Count the number of disjoint sets (roots)
    // A node i is a root if parent[i] == i.
    let num_traps = parent.par_iter().enumerate()
        .filter(|(i, p_atomic)| {
            let p = p_atomic.load(Ordering::Relaxed);
            *i as u32 == p
        })
        .count();

    println!("{}", num_traps);
}

// Helper to find the representative of a node
fn get_root(parent: &[AtomicU32], mut node: u32) -> u32 {
    let mut p = parent[node as usize].load(Ordering::Relaxed);
    while p != node {
        node = p;
        p = parent[node as usize].load(Ordering::Relaxed);
    }
    node
}

