    pos: usize,
}

impl Cursor {
    fn new(buf: Vec<u8>) -> Self {
        Self { buf, pos: 0 }
    }

    #[inline(always)]
    fn next_u32(&mut self) -> u32 {
        let len = self.buf.len();
        while self.pos < len && self.buf[self.pos] <= b' ' {
            self.pos += 1;
        }
        let mut res = 0;
        while self.pos < len && self.buf[self.pos] >= b'0' {
            res = res * 10 + (self.buf[self.pos] & 0x0F) as u32;
            self.pos += 1;
        }
        res
    }
}

