    size: Vec<u32>,
    edges: Vec<u32>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        // Initialize DSU with capacity n + 1. 1-based indexing.
        let parent = (0..=n as u32).collect();
        let size = vec![1; n + 1];
        let edges = vec![0; n + 1];
        Dsu { parent, size, edges }
    }

    fn find(&mut self, i: u32) -> u32 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    fn union(&mut self, i: u32, j: u32) {
        let root_i = self.find(i);
        let root_j = self.find(j);
