struct Dsu {
    parent: Vec<u32>,
    size: Vec<u32>,
    edges: Vec<u32>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        // Initialize DSU with capacity n + 1. 1-based indexing.
        let parent = (0..=n as u32).collect();
        let size = vec![1; n + 1];
        let edges = vec![0; n + 1];
        Dsu { parent, size, edges }
    }

    fn find(&mut self, i: u32) -> u32 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    fn union(&mut self, i: u32, j: u32) {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            // Merge component j into i
            self.parent[root_j as usize] = root_i;
            self.size[root_i as usize] += self.size[root_j as usize];
            self.edges[root_i as usize] += self.edges[root_j as usize] + 1;
        } else {
            // Edge within the same component (forms a cycle)
            self.edges[root_i as usize] += 1;
        }
    }
}

