struct StaticDsu {
    parent: Vec<u32>,
    size: Vec<u32>,
}

impl StaticDsu {
    fn new(n: usize) -> Self {
        Self {
            parent: (0..n as u32).collect(),
            size: vec![1; n],
        }
    }

    fn find(&mut self, i: u32) -> u32 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    fn union(&mut self, i: u32, j: u32) {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            if self.size[root_i as usize] < self.size[root_j as usize] {
                self.parent[root_i as usize] = root_j;
                self.size[root_j as usize] += self.size[root_i as usize];
            } else {
                self.parent[root_j as usize] = root_i;
                self.size[root_i as usize] += self.size[root_j as usize];
            }
        }
    }
}

fn gcd(mut a: u32, mut b: u32) -> u32 {
    while b != 0 {
        let t = b;
        b = a % b;
        a = t;
    }
    a
}

