fn main() {
    let mut scanner = Scanner::new();
    if scanner.buffer.is_empty() { return; }

    let n = scanner.next_u32() as usize;
    if n == 0 {
        println!("0");
        return;
    }

    let total_nodes = n * n;

    let mut h = vec![0u32; total_nodes];
    for i in 0..total_nodes {
        h[i] = scanner.next_u32();
    }

    let mut v = vec![0u32; total_nodes];
    for i in 0..total_nodes {
        v[i] = scanner.next_u32();
    }

    let mut static_dsu = StaticDsu::new(total_nodes);

    let mut check_static = |u: usize, next: usize, dsu: &mut StaticDsu| {
        if h[u] == h[next] && v[u] == v[next] {
            dsu.union(u as u32, next as u32);
        }
    };

    // Horizontal static connections
    for r in 0..n {
        let row_start = r * n;
        for c in 0..n - 1 {
            check_static(row_start + c, row_start + c + 1, &mut static_dsu);
        }
    }
    // Vertical static connections
    for r in 0..n - 1 {
        let row_start = r * n;
        let next_row_start = (r + 1) * n;
        for c in 0..n {
            check_static(row_start + c, next_row_start + c, &mut static_dsu);
        }
    }

    let mut comp_id = vec![0u32; total_nodes];
    let mut static_sizes = vec![0u32; total_nodes];
    let mut max_static_size = 0;

    for i in 0..total_nodes {
        let root = static_dsu.find(i as u32);
        comp_id[i] = root;
    }

    for i in 0..total_nodes {
        let root = comp_id[i] as usize;
        if i == root {
            let s = static_dsu.size[i];
            static_sizes[i] = s;
            if s > max_static_size {
                max_static_size = s;
            }
        }
    }

    // Dynamic Edge Collection
    let mut edges = Vec::with_capacity(2 * total_nodes);

    let mut add_edge = |u: usize, next: usize, edges: &mut Vec<Edge>| {
        let c1 = comp_id[u];
        let c2 = comp_id[next];

        if c1 != c2 {
            let v1 = v[u] as i32;
            let v2 = v[next] as i32;
            let mut dv = v1 - v2;

            if dv != 0 {
                let h1 = h[u] as i32;
                let h2 = h[next] as i32;
                let mut dh = h2 - h1;

                // We need t = dh/dv >= 0. Normalize dv > 0.
                if dv < 0 {
                    dv = -dv;
                    dh = -dh;
                }

                if dh >= 0 {
                    let common = gcd(dh as u32, dv as u32);
                    edges.push(Edge {
                        num: (dh as u32) / common,
                        den: (dv as u32) / common,
                        u: c1,
                        v: c2,
                    });
                }
            }
        }
    };

    for r in 0..n {
        let row_start = r * n;
        for c in 0..n - 1 {
            add_edge(row_start + c, row_start + c + 1, &mut edges);
        }
    }
    for r in 0..n - 1 {
        let row_start = r * n;
        let next_row_start = (r + 1) * n;
        for c in 0..n {
            add_edge(row_start + c, next_row_start + c, &mut edges);
        }
    }

    if edges.is_empty() {
        println!("{}", max_static_size);
        return;
    }

    // Parallel Sort by time (num/den)
    edges.par_sort_unstable_by(|a, b| {
        let lhs = (a.num as u64) * (b.den as u64);
        let rhs = (b.num as u64) * (a.den as u64);
        lhs.cmp(&rhs)
    });

    // Group edges by equal time
    let mut ranges = Vec::new();
    let mut start = 0;
    for i in 1..edges.len() {
        if edges[i].num != edges[i-1].num || edges[i].den != edges[i-1].den {
            ranges.push(start..i);
            start = i;
        }
    }
    ranges.push(start..edges.len());

    // Process groups in parallel
    let max_dynamic = ranges.into_par_iter().map_with(Worker::new(), |worker, range| {
        let group = &edges[range];

        // Optimization: Single edge case
        if group.len() == 1 {
            let e = &group[0];
            return static_sizes[e.u as usize] + static_sizes[e.v as usize];
        }

        // Coordinate Compression: Collect unique nodes involved
        worker.nodes.clear();
        for e in group {
            worker.nodes.push(e.u);
            worker.nodes.push(e.v);
        }
        worker.nodes.sort_unstable();
        worker.nodes.dedup();

        let k = worker.nodes.len();

        // Initialize Local DSU
        worker.parent.clear();
        worker.parent.extend(0..k as u32);

        worker.sizes.clear();
        worker.sizes.extend(worker.nodes.iter().map(|&id| static_sizes[id as usize]));

        let mut current_max = 0;
        for &s in &worker.sizes {
            if s > current_max {
                current_max = s;
            }
        }

        // Process edges in the group
        for e in group {
            // Map global ID to local index
            // Use unwrap because construction guarantees existence
            let u_idx = worker.nodes.binary_search(&e.u).unwrap() as u32;
            let v_idx = worker.nodes.binary_search(&e.v).unwrap() as u32;

            // DSU Union
            let mut root_u = u_idx;
            while root_u != worker.parent[root_u as usize] {
                let p = worker.parent[root_u as usize];
                worker.parent[root_u as usize] = worker.parent[p as usize];
                root_u = worker.parent[root_u as usize];
            }

            let mut root_v = v_idx;
            while root_v != worker.parent[root_v as usize] {
                let p = worker.parent[root_v as usize];
                worker.parent[root_v as usize] = worker.parent[p as usize];
                root_v = worker.parent[root_v as usize];
            }

            if root_u != root_v {
                if worker.sizes[root_u as usize] < worker.sizes[root_v as usize] {
                    worker.parent[root_u as usize] = root_v;
                    worker.sizes[root_v as usize] += worker.sizes[root_u as usize];
                    if worker.sizes[root_v as usize] > current_max {
                        current_max = worker.sizes[root_v as usize];
                    }
                } else {
                    worker.parent[root_v as usize] = root_u;
                    worker.sizes[root_u as usize] += worker.sizes[root_v as usize];
                    if worker.sizes[root_u as usize] > current_max {
                        current_max = worker.sizes[root_u as usize];
                    }
                }
            }
        }
        current_max
    }).max().unwrap_or(0);

    println!("{}", std::cmp::max(max_static_size, max_dynamic));
}

