        }
    }

    #[inline(always)]
    fn next_u32(&mut self) -> u32 {
        self.skip_whitespace();
        let mut n = 0;
        while self.cursor < self.buffer.len() {
            let b = self.buffer[self.cursor];
            if b < b'0' || b > b'9' {
                break;
            }
            n = n * 10 + (b - b'0') as u32;
            self.cursor += 1;
        }
        n
    }
}

