// Disjoint Set Union (DSU)
struct Dsu {
    parent: Vec<u32>,
    size: Vec<u32>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Self {
            parent: (0..n as u32).collect(),
            size: vec![1; n],
        }
    }

    fn find(&mut self, i: u32) -> u32 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    fn union(&mut self, i: u32, j: u32) {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            if self.size[root_i as usize] < self.size[root_j as usize] {
                self.parent[root_i as usize] = root_j;
                self.size[root_j as usize] += self.size[root_i as usize];
            } else {
                self.parent[root_j as usize] = root_i;
                self.size[root_i as usize] += self.size[root_j as usize];
            }
        }
    }
}

fn gcd(mut a: u32, mut b: u32) -> u32 {
    while b != 0 {
        let t = b;
        b = a % b;
        a = t;
    }
    a
}

// Thread-local worker for parallel processing
#[derive(Clone)]
struct Worker {
    mapping: Vec<u32>,
    modified: Vec<u32>,
    parent: Vec<u32>,
    sizes: Vec<u32>,
}

impl Worker {
    fn new(total_nodes: usize) -> Self {
        Self {
            mapping: vec![u32::MAX; total_nodes],
            modified: Vec::with_capacity(1024),
            parent: Vec::with_capacity(1024),
            sizes: Vec::with_capacity(1024),
        }
    }

    #[inline(always)]
    fn get_local(&mut self, global: u32, static_sizes: &[u32]) -> u32 {
        let g_idx = global as usize;
        let mut local = self.mapping[g_idx];
        if local == u32::MAX {
            local = self.parent.len() as u32;
            self.mapping[g_idx] = local;
            self.modified.push(global);
            self.parent.push(local);
            self.sizes.push(static_sizes[g_idx]);
        }
        local
    }

    #[inline(always)]
    fn find(&mut self, i: u32) -> u32 {
        let mut root = i;
        while self.parent[root as usize] != root {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u32, j: u32) -> u32 {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            let s_i = self.sizes[root_i as usize];
            let s_j = self.sizes[root_j as usize];
            if s_i < s_j {
                self.parent[root_i as usize] = root_j;
                self.sizes[root_j as usize] += s_i;
                return self.sizes[root_j as usize];
            } else {
                self.parent[root_j as usize] = root_i;
                self.sizes[root_i as usize] += s_j;
                return self.sizes[root_i as usize];
            }
        }
        self.sizes[root_i as usize]
    }

    #[inline(always)]
    fn reset(&mut self) {
        for &g in &self.modified {
            self.mapping[g as usize] = u32::MAX;
        }
        self.modified.clear();
        self.parent.clear();
        self.sizes.clear();
    }
}

fn main() {
    let mut scanner = Scanner::new();
    if scanner.buffer.is_empty() { return; }

    let n = scanner.next_u32() as usize;
    if n == 0 {
        println!("0");
        return;
    }

    let total_nodes = n * n;

    let mut h = vec![0u32; total_nodes];
    for i in 0..total_nodes { h[i] = scanner.next_u32(); }

    let mut v = vec![0u32; total_nodes];
    for i in 0..total_nodes { v[i] = scanner.next_u32(); }

    // 1. Static Components
    let mut static_dsu = Dsu::new(total_nodes);
    let mut check_static = |u: usize, next: usize, dsu: &mut Dsu| {
        if h[u] == h[next] && v[u] == v[next] {
            dsu.union(u as u32, next as u32);
        }
    };

    for r in 0..n {
        let row_start = r * n;
        for c in 0..n - 1 {
            let u = row_start + c;
            check_static(u, u + 1, &mut static_dsu);
        }
    }
    for r in 0..n - 1 {
        let row_start = r * n;
        let next_row_start = (r + 1) * n;
        for c in 0..n {
            let u = row_start + c;
            check_static(u, next_row_start + c, &mut static_dsu);
        }
    }

    let mut comp_id = vec![0u32; total_nodes];
    let mut static_sizes = vec![0u32; total_nodes];
    let mut max_static = 0;

    for i in 0..total_nodes {
        let root = static_dsu.find(i as u32);
        comp_id[i] = root;
    }
    for i in 0..total_nodes {
        let root = comp_id[i] as usize;
        if i == root {
            let s = static_dsu.size[i];
            static_sizes[i] = s;
            if s > max_static {
                max_static = s;
            }
        }
    }

    // 2. Dynamic Edges
    let mut edges: Vec<Edge> = Vec::with_capacity(2 * total_nodes);

    let mut add_edge = |u: usize, next: usize, edges: &mut Vec<Edge>| {
        let c1 = comp_id[u];
        let c2 = comp_id[next];
        if c1 != c2 {
            let v1 = v[u] as i32;
            let v2 = v[next] as i32;
            let dv = v1 - v2;
            if dv != 0 {
                let h1 = h[u] as i32;
                let h2 = h[next] as i32;
                let mut dh = h2 - h1;
                let mut d_v = dv;
                if d_v < 0 {
                    d_v = -d_v;
                    dh = -dh;
                }
                if dh >= 0 {
                    let g = gcd(dh as u32, d_v as u32);
                    edges.push(Edge {
                        num: (dh as u32) / g,
                        den: (d_v as u32) / g,
                        u: c1,
                        v: c2,
                    });
                }
            }
        }
    };

    for r in 0..n {
        let row_start = r * n;
        for c in 0..n - 1 {
            let u = row_start + c;
            add_edge(u, u + 1, &mut edges);
        }
        if r < n - 1 {
            let next_row_start = (r + 1) * n;
            for c in 0..n {
                let u = row_start + c;
                add_edge(u, next_row_start + c, &mut edges);
            }
        }
    }

    if edges.is_empty() {
        println!("{}", max_static);
        return;
    }

    // 3. Parallel Sort
    edges.par_sort_unstable_by(|a, b| {
        let lhs = (a.num as u64) * (b.den as u64);
        let rhs = (b.num as u64) * (a.den as u64);
        lhs.cmp(&rhs)
    });

    // 4. Grouping
    let mut ranges = Vec::new();
    let mut start = 0;
    for i in 1..edges.len() {
        if edges[i].num != edges[i-1].num || edges[i].den != edges[i-1].den {
            ranges.push(start..i);
            start = i;
        }
    }
    ranges.push(start..edges.len());

    // 5. Process groups
    let max_dynamic = ranges.into_par_iter().map_with(Worker::new(total_nodes), |worker, range| {
        let group = &edges[range];
        worker.reset();

        let mut local_max = 0;
        for e in group {
            let u_loc = worker.get_local(e.u, &static_sizes);
            let v_loc = worker.get_local(e.v, &static_sizes);
            let s = worker.union(u_loc, v_loc);
            if s > local_max {
                local_max = s;
            }
        }

        // If local_max is 0 (unlikely for non-empty edges unless redundant), 
        // we should at least check size of one node.
        if local_max == 0 && !group.is_empty() {
             let u_loc = worker.get_local(group[0].u, &static_sizes);
             let root = worker.find(u_loc);
             local_max = worker.sizes[root as usize];
        }

        local_max
    }).max().unwrap_or(0);

    println!("{}", std::cmp::max(max_static, max_dynamic));
}

