fn main() {
    let mut input = String::new();
    if io::stdin().read_to_string(&mut input).is_err() {
        return;
    }
    let mut iter = input.split_whitespace();

    let n_str = match iter.next() {
        Some(s) => s,
        None => return,
    };
    let n: usize = n_str.parse().unwrap();
    if n == 0 {
        println!("0");
        return;
    }

    let num_cells = n * n;
    let h: Vec<i32> = (0..num_cells).map(|_| iter.next().unwrap().parse().unwrap()).collect();
    let v: Vec<i32> = (0..num_cells).map(|_| iter.next().unwrap().parse().unwrap()).collect();

    let mut dsu = Dsu::new(num_cells);
    let mut edges = Vec::with_capacity(2 * num_cells);

    // Process all edges
    for r in 0..n {
        for c in 0..n {
            let u = r * n + c;

            // Right
            if c + 1 < n {
                let neighbor = u + 1;
                process_pair(u, neighbor, &h, &v, &mut dsu, &mut edges);
            }

            // Down
            if r + 1 < n {
                let neighbor = u + n;
                process_pair(u, neighbor, &h, &v, &mut dsu, &mut edges);
            }
        }
    }

    let mut max_comp = 1;
    let mut node_roots = vec![0u32; num_cells];
    for i in 0..num_cells {
        let root = dsu.find(i as u32);
        node_roots[i] = root;
        let s = dsu.size[root as usize];
        if s > max_comp {
            max_comp = s;
        }
    }

    if edges.is_empty() {
        println!("{}", max_comp);
        return;
    }

    // Parallel sort
    edges.par_sort_unstable_by(|a, b| a.t.cmp(&b.t));

    // Reusable structures for processing groups
    let mut map_gen = vec![0u32; num_cells];
    let mut node_map = vec![0u32; num_cells];
    let mut current_gen = 0;

    let mut adj: Vec<Vec<u32>> = Vec::new();
    let mut comp_sizes: Vec<u32> = Vec::new();
    let mut visited = Vec::new();
    let mut stack = Vec::new();

    let mut i = 0;
    while i < edges.len() {
        let current_t = edges[i].t;
        let start = i;
        while i < edges.len() && edges[i].t == current_t {
            i += 1;
        }
        let end = i;

        current_gen += 1;
        if current_gen == 0 {
            map_gen.fill(0);
            current_gen = 1;
        }

        let mut node_count = 0;

        for k in start..end {
            let u_orig = edges[k].u;
            let v_orig = edges[k].v;

            let root_u = node_roots[u_orig as usize];
            let root_v = node_roots[v_orig as usize];

            if root_u == root_v {
                continue;
            }

            // Map root_u
            let u_idx = if map_gen[root_u as usize] == current_gen {
                node_map[root_u as usize]
            } else {
                map_gen[root_u as usize] = current_gen;
                node_map[root_u as usize] = node_count;
                if node_count as usize >= adj.len() {
                    adj.push(Vec::new());
                    comp_sizes.push(0);
                }
                adj[node_count as usize].clear();
                comp_sizes[node_count as usize] = dsu.size[root_u as usize];
                node_count += 1;
                node_count - 1
            };

            // Map root_v
            let v_idx = if map_gen[root_v as usize] == current_gen {
                node_map[root_v as usize]
            } else {
                map_gen[root_v as usize] = current_gen;
                node_map[root_v as usize] = node_count;
                if node_count as usize >= adj.len() {
                    adj.push(Vec::new());
                    comp_sizes.push(0);
                }
                adj[node_count as usize].clear();
                comp_sizes[node_count as usize] = dsu.size[root_v as usize];
                node_count += 1;
                node_count - 1
            };

            adj[u_idx as usize].push(v_idx);
            adj[v_idx as usize].push(u_idx);
        }

        if visited.len() < node_count as usize {
            visited.resize(node_count as usize, false);
        }
        for k in 0..node_count as usize {
            visited[k] = false;
        }

        for k in 0..node_count {
            if !visited[k as usize] {
                visited[k as usize] = true;
                stack.clear();
                stack.push(k);
                let mut current_size = 0;

                while let Some(curr) = stack.pop() {
                    current_size += comp_sizes[curr as usize];
                    for &nxt in &adj[curr as usize] {
                        if !visited[nxt as usize] {
                            visited[nxt as usize] = true;
                            stack.push(nxt);
                        }
                    }
                }
                if current_size > max_comp {
                    max_comp = current_size;
                }
            }
        }
    }

    println!("{}", max_comp);
}

fn process_pair(u: usize, neighbor: usize, h: &[i32], v: &[i32], dsu: &mut Dsu, edges: &mut Vec<Edge>) {
    let h1 = h[u];
    let v1 = v[u];
    let h2 = h[neighbor];
    let v2 = v[neighbor];

    if v1 == v2 {
        if h1 == h2 {
            dsu.union(u as u32, neighbor as u32);
        }
    } else {
        let dh = h2 - h1;
        let dv = v1 - v2;
        // t = dh / dv. require t >= 0
        if (dh >= 0 && dv > 0) || (dh <= 0 && dv < 0) {
            let num = dh.abs() as u64;
            let den = dv.abs() as u64;
            let g = gcd(num, den);
            edges.push(Edge { 
                u: u as u32, 
                v: neighbor as u32, 
                t: Fraction { n: num / g, d: den / g } 
            });
        }
    }
}

