fn main() {
    let mut scanner = Scanner::new();
    if scanner.cursor >= scanner.buffer.len() { return; }

    let n = scanner.next_u32() as usize;
    if n == 0 {
        println!("0");
        return;
    }

    let total_nodes = n * n;

    let mut h = vec![0u32; total_nodes];
    for i in 0..total_nodes {
        h[i] = scanner.next_u32();
    }

    let mut v = vec![0u32; total_nodes];
    for i in 0..total_nodes {
        v[i] = scanner.next_u32();
    }

    let mut static_dsu = StaticDsu::new(total_nodes);

    // Horizontal connections
    for r in 0..n {
        let row_start = r * n;
        for c in 0..n - 1 {
            let u = row_start + c;
            let next = u + 1;
            if h[u] == h[next] && v[u] == v[next] {
                static_dsu.union(u as u32, next as u32);
            }
        }
    }
    // Vertical connections
    for r in 0..n - 1 {
        let row_start = r * n;
        let next_row_start = (r + 1) * n;
        for c in 0..n {
            let u = row_start + c;
            let next = next_row_start + c;
            if h[u] == h[next] && v[u] == v[next] {
                static_dsu.union(u as u32, next as u32);
            }
        }
    }

    let mut comp_id = vec![0u32; total_nodes];
    let mut static_sizes = vec![0u32; total_nodes];
    let mut max_static_size = 0;

    for i in 0..total_nodes {
        let root = static_dsu.find(i as u32);
        comp_id[i] = root;
    }

    for i in 0..total_nodes {
        let root = comp_id[i] as usize;
        if i == root {
            let s = static_dsu.size[i];
            static_sizes[i] = s;
            if s > max_static_size {
                max_static_size = s;
            }
        }
    }

    // Dynamic Edge Collection
    // Using parallel iterator to collect edges
    let mut edges: Vec<Edge> = (0..n).into_par_iter().map(|r| {
        let mut local_edges = Vec::new();
        let row_start = r * n;

        // Horizontal
        for c in 0..n - 1 {
            let u = row_start + c;
            let next = u + 1;
            let c1 = comp_id[u];
            let c2 = comp_id[next];

            if c1 != c2 {
                let v1 = v[u] as i32;
                let v2 = v[next] as i32;
                let mut dv = v1 - v2;

                if dv != 0 {
                    let h1 = h[u] as i32;
                    let h2 = h[next] as i32;
                    let mut dh = h2 - h1;

                    // Normalize so dv > 0
                    if dv < 0 {
                        dv = -dv;
                        dh = -dh;
                    }

                    // t = dh/dv >= 0 => dh >= 0
                    if dh >= 0 {
                        let g = gcd(dh as u32, dv as u32);
                        local_edges.push(Edge {
                            num: (dh as u32) / g,
                            den: (dv as u32) / g,
                            u: c1,
                            v: c2,
                        });
                    }
                }
            }
        }

        // Vertical
        if r < n - 1 {
            let next_row_start = (r + 1) * n;
            for c in 0..n {
                let u = row_start + c;
                let next = next_row_start + c;
                let c1 = comp_id[u];
                let c2 = comp_id[next];

                if c1 != c2 {
                    let v1 = v[u] as i32;
                    let v2 = v[next] as i32;
                    let mut dv = v1 - v2;

                    if dv != 0 {
                        let h1 = h[u] as i32;
                        let h2 = h[next] as i32;
                        let mut dh = h2 - h1;

                        if dv < 0 {
                            dv = -dv;
                            dh = -dh;
                        }

                        if dh >= 0 {
                            let g = gcd(dh as u32, dv as u32);
                            local_edges.push(Edge {
                                num: (dh as u32) / g,
                                den: (dv as u32) / g,
                                u: c1,
                                v: c2,
                            });
                        }
                    }
                }
            }
        }
        local_edges
