                }
            }

            if !found {
                stack.pop();
                if incoming != u32::MAX {
                    if incoming < edges.len() as u32 {
                        if toggle {
                            set1.push(edges[incoming as usize]);
                        } else {
                            set2.push(edges[incoming as usize]);
