use std::cmp::max;
use std::io::{self, Read, Write, BufWriter};
use std::ptr;
use rayon::prelude::*;

// Define a struct for edges that includes the original index
#[derive(Clone, Copy, Debug)]
struct Edge {
    u: u32,
    v: u32,
    id: u32,
}

// Thread-safe output buffer allowing concurrent writes to disjoint indices.
// We use a raw pointer to avoid mutable borrowing issues across threads.
// Safety: Each edge ID is unique and processed by exactly one recursion branch.
struct SharedOutput {
    data: *mut u32,
}

unsafe impl Send for SharedOutput {}
unsafe impl Sync for SharedOutput {}

impl SharedOutput {
    fn new(size: usize) -> (Self, Vec<u32>) {
        let mut v = vec![0u32; size];
        let ptr = v.as_mut_ptr();
        (Self { data: ptr }, v)
    }

    unsafe fn set(&self, index: usize, val: u32) {
        *self.data.add(index) = val;
    }
}

// Fast scanner for efficient input parsing
struct Scanner<'a> {
    iter: std::str::SplitAsciiWhitespace<'a>,
}

impl<'a> Scanner<'a> {
    fn new(s: &'a str) -> Self {
        Self {
            iter: s.split_ascii_whitespace(),
        }
    }
    fn next<T: std::str::FromStr>(&mut self) -> T {
        self.iter.next().unwrap().parse().ok().unwrap()
    }
}

fn solve(
    edges: Vec<Edge>,
    k: u32,
    color_offset: u32,
    l_limit: u32,
    output: &SharedOutput,
) {
    if edges.is_empty() {
        return;
    }

    // Base Case: If only 1 color is available, paint all edges with it.
    if k == 1 {
        for e in edges {
            unsafe { output.set(e.id as usize, color_offset); }
        }
        return;
    }

    // Optimization: If number of edges is small enough, assign unique colors directly.
    // This avoids overhead of constructing graphs for small subsets.
    if edges.len() <= k as usize {
        for (i, e) in edges.iter().enumerate() {
            unsafe { output.set(e.id as usize, color_offset + i as u32); }
        }
        return;
    }

    // Coordinate Compression
    // Collect all involved nodes to map sparse IDs to a dense range 0..N
    let mut nodes = Vec::with_capacity(edges.len() * 2);
    for e in &edges {
        nodes.push(e.u);
        nodes.push(e.v);
    }

    // Sort and deduplicate. Use parallel sort for performance on large datasets.
    if nodes.len() > 2000 {
        nodes.par_sort_unstable();
    } else {
        nodes.sort_unstable();
    }
    nodes.dedup();

    let n = nodes.len();
    let dl = n;     // Dummy Left Node index
    let dr = n + 1; // Dummy Right Node index
    let num_nodes_local = n + 2;

    // Build Graph
    // Adjacency list: adj[u] = [(v, local_edge_index), ...]
    // local_edge_index < edges.len() -> real edge
    // local_edge_index >= edges.len() -> dummy edge
    let mut adj = vec![Vec::new(); num_nodes_local];
    let mut degree = vec![0; num_nodes_local];

    // Helper to get local index from global ID
    let get_id = |val: u32| -> usize {
        nodes.binary_search(&val).unwrap()
    };

    // Add real edges to the local graph
    for (i, e) in edges.iter().enumerate() {
        let u = get_id(e.u);
        let v = get_id(e.v);

        adj[u].push((v as u32, i as u32));
        adj[v].push((u as u32, i as u32));
        degree[u] += 1;
        degree[v] += 1;
    }

    // Identify odd degree nodes and add dummy edges to make the graph Eulerian
    // Strategy:
    // - Connect odd degree Left nodes to Dummy Right (dr)
    // - Connect odd degree Right nodes to Dummy Left (dl)
    // - If dl/dr end up with odd degree, connect them together
    let mut dummy_edge_idx = edges.len() as u32;
    let mut dl_deg_change = 0;

    for (i, &orig_val) in nodes.iter().enumerate() {
        if degree[i] % 2 != 0 {
            // Check if original node is from Left side (u < l_limit)
            if orig_val < l_limit {
                // Connect to Dummy Right
                adj[i].push((dr as u32, dummy_edge_idx));
                adj[dr].push((i as u32, dummy_edge_idx));
            } else {
                // Connect to Dummy Left
                adj[i].push((dl as u32, dummy_edge_idx));
                adj[dl].push((i as u32, dummy_edge_idx));
                dl_deg_change += 1;
            }
            dummy_edge_idx += 1;
        }
    }

    // If Dummy Left has odd degree (from added edges), connect to Dummy Right
    if dl_deg_change % 2 != 0 {
        adj[dl].push((dr as u32, dummy_edge_idx));
        adj[dr].push((dl as u32, dummy_edge_idx));
        dummy_edge_idx += 1;
    }

    // Euler Tour Split
    // We split edges into two sets by alternating edges along the Euler tour.
    // This ensures that for each node, the degree is roughly halved in each subset.
    let total_local_edges = dummy_edge_idx as usize;
    let mut visited_edge = vec![false; total_local_edges];
    let mut ptr = vec![0usize; num_nodes_local]; // Current pointer into adj[u] to avoid O(deg^2)

    let mut set1 = Vec::with_capacity(edges.len() / 2 + 1);
    let mut set2 = Vec::with_capacity(edges.len() / 2 + 1);

    // Iterative DFS (Hierholzer's algorithm)
    let mut stack = Vec::new();

    for start_node in 0..num_nodes_local {
        // Skip nodes that are already fully processed
        if ptr[start_node] >= adj[start_node].len() {
            continue;
        }

        stack.clear();
        stack.push((start_node as u32, u32::MAX));

        let mut toggle = false;

        while let Some(&(u, incoming_edge)) = stack.last() {
            let u_idx = u as usize;
            let mut found = false;

            // Find next unvisited edge
            while ptr[u_idx] < adj[u_idx].len() {
                let (v, eid) = adj[u_idx][ptr[u_idx]];
                ptr[u_idx] += 1;

                if !visited_edge[eid as usize] {
                    visited_edge[eid as usize] = true;
                    stack.push((v, eid));
                    found = true;
                    break;
                }
            }

            if !found {
                stack.pop();
                // Backtracking from u via incoming_edge implies incoming_edge is part of the tour
                if incoming_edge != u32::MAX {
                    // If it's a real edge (not dummy), assign to a set
                    if incoming_edge < edges.len() as u32 {
                        if toggle {
                            set1.push(edges[incoming_edge as usize]);
                        } else {
                            set2.push(edges[incoming_edge as usize]);
                        }
                    }
                    toggle = !toggle;
                }
            }
        }
    }

    // Recursive Calls
    // Split the color range [color_offset, color_offset + k) into two halves.
    let next_k = k / 2;

    // Use Rayon for parallelism if the subproblem size is significant
    if edges.len() > 2000 {
        rayon::join(
            || solve(set1, next_k, color_offset, l_limit, output),
            || solve(set2, next_k, color_offset + next_k, l_limit, output)
        );
    } else {
        solve(set1, next_k, color_offset, l_limit, output);
        solve(set2, next_k, color_offset + next_k, l_limit, output);
    }
