use std::cell::UnsafeCell;
use std::io::{self, Read, Write, BufWriter};
use std::cmp::max;
use rayon::prelude::*;

// SharedOutput allows safe concurrent writes to the output array.
// This is safe because each recursion branch processes a disjoint set of edge IDs.
struct SharedOutput {
    data: *mut u32,
}

unsafe impl Send for SharedOutput {}
unsafe impl Sync for SharedOutput {}

impl SharedOutput {
    fn set(&self, index: usize, val: u32) {
        unsafe {
            *self.data.add(index) = val;
        }
    }
}

#[derive(Clone, Copy)]
struct Edge {
    u: u32,
    v: u32,
    id: u32,
}

struct Scanner<'a> {
    iter: std::str::SplitAsciiWhitespace<'a>,
}

impl<'a> Scanner<'a> {
    fn new(s: &'a str) -> Self {
        Self {
            iter: s.split_ascii_whitespace(),
        }
    }
    fn next<T: std::str::FromStr>(&mut self) -> T {
        self.iter.next().unwrap().parse().ok().unwrap()
    }
}

fn solve(
    edges: Vec<Edge>,
    k: u32,
    color_offset: u32,
    l_limit: u32,
    output: &SharedOutput,
) {
    if edges.is_empty() {
        return;
    }

    // Base case: if K=1, assign the single available color to all edges.
    if k == 1 {
        for e in edges {
            output.set(e.id as usize, color_offset);
        }
        return;
    }

    // Coordinate Compression: Map sparse global IDs to dense local IDs 0..N
    let (nodes, n) = {
        let mut nodes = Vec::with_capacity(edges.len() * 2);
        for e in &edges {
            nodes.push(e.u);
            nodes.push(e.v);
        }
        // Use parallel sort for large datasets
        if nodes.len() > 2000 {
            nodes.par_sort_unstable();
        } else {
            nodes.sort_unstable();
        }
        nodes.dedup();
        let n = nodes.len();
        (nodes, n)
    };

    // Dummy nodes indices
    let dl = n;     // Dummy Left (connected to Right nodes)
    let dr = n + 1; // Dummy Right (connected to Left nodes)
    let num_nodes = n + 2;

    // Build Graph
    // Adjacency list: nodes -> [(neighbor_idx, edge_index)]
    // Real edges have indices < edges.len(), dummy edges >= edges.len()
    let mut adj = vec![Vec::new(); num_nodes];
    let mut deg = vec![0; n];

    // Helper to find local index
    let get_local = |val: u32| -> usize {
        nodes.binary_search(&val).unwrap()
    };

    for (i, e) in edges.iter().enumerate() {
        let u = get_local(e.u);
        let v = get_local(e.v);

        adj[u].push((v as u32, i as u32));
        adj[v].push((u as u32, i as u32));
        deg[u] += 1;
        deg[v] += 1;
    }

    // Add dummy edges to make graph Eulerian (all degrees even)
    let mut next_eid = edges.len() as u32;
    let mut dl_deg_parity = 0;

    for (i, &gid) in nodes.iter().enumerate() {
        if deg[i] % 2 != 0 {
            if gid < l_limit {
                // Left node (odd) -> connect to Dummy Right
                adj[i].push((dr as u32, next_eid));
                adj[dr].push((i as u32, next_eid));
            } else {
                // Right node (odd) -> connect to Dummy Left
                adj[i].push((dl as u32, next_eid));
                adj[dl].push((i as u32, next_eid));
                dl_deg_parity ^= 1;
            }
            next_eid += 1;
        }
    }

    // If Dummy Left has odd degree, connect DL and DR
    if dl_deg_parity != 0 {
        adj[dl].push((dr as u32, next_eid));
        adj[dr].push((dl as u32, next_eid));
        next_eid += 1;
    }

    // Euler Tour Split
    // Decompose into edge-disjoint circuits and alternate edges
    let total_edges = next_eid as usize;
    let mut visited = vec![false; total_edges];
    let mut ptr = vec![0; num_nodes]; // Current pointer in adj list

    let mut set1 = Vec::with_capacity(edges.len() / 2 + 1);
    let mut set2 = Vec::with_capacity(edges.len() / 2 + 1);

    let mut stack = Vec::new();

    for start_node in 0..num_nodes {
        // Skip fully processed nodes
        if ptr[start_node] >= adj[start_node].len() {
            continue;
        }

        stack.clear();
        stack.push((start_node as u32, u32::MAX));

        let mut tour_counter = 0;

        // Iterative DFS (Hierholzer's)
        while let Some(&(u, incoming_edge)) = stack.last() {
            let u_idx = u as usize;
            let mut found = false;

            while ptr[u_idx] < adj[u_idx].len() {
                let (v, eid) = adj[u_idx][ptr[u_idx]];
                ptr[u_idx] += 1;

                if !visited[eid as usize] {
                    visited[eid as usize] = true;
                    stack.push((v, eid));
                    found = true;
                    break;
                }
            }

            if !found {
                stack.pop();
                // Backtracking: edge `incoming_edge` is part of the tour
                if incoming_edge != u32::MAX {
                    if incoming_edge < edges.len() as u32 {
                        if tour_counter % 2 == 0 {
                            set1.push(edges[incoming_edge as usize]);
                        } else {
                            set2.push(edges[incoming_edge as usize]);
                        }
                    }
                    tour_counter += 1;
                }
            }
        }
    }

    let next_k = k / 2;
    // Recurse in parallel for large subproblems
    if edges.len() > 2000 {
        rayon::join(
            || solve(set1, next_k, color_offset, l_limit, output),
            || solve(set2, next_k, color_offset + next_k, l_limit, output)
        );
    } else {
        solve(set1, next_k, color_offset, l_limit, output);
        solve(set2, next_k, color_offset + next_k, l_limit, output);
    }
}

fn run() {
    let mut input = String::new();
    if io::stdin().read_to_string(&mut input).is_err() { return; }
    if input.trim().is_empty() { return; }

