// CSR Graph structure for memory efficiency and fast traversal
struct Graph {
    offsets: Vec<usize>,
    edges: Vec<u32>,
}

impl Graph {
    fn new(n: usize, edges_list: &[(u32, u32)]) -> Self {
        let mut degrees = vec![0; n];
        for &(u, v) in edges_list {
            degrees[u as usize] += 1;
            degrees[v as usize] += 1;
        }

        let mut offsets = vec![0; n + 1];
        for i in 0..n {
            offsets[i + 1] = offsets[i] + degrees[i];
        }

        let mut edges = vec![0u32; offsets[n]];
        let mut current_pos = offsets.clone();

        for &(u, v) in edges_list {
            edges[current_pos[u as usize]] = v;
            current_pos[u as usize] += 1;

            edges[current_pos[v as usize]] = u;
            current_pos[v as usize] += 1;
        }

        Graph { offsets, edges }
    }
}

fn main() {
    // 1. Fast Input Reading
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_whitespace();

    let n_str = iter.next();
    if n_str.is_none() { return; }
    let n: usize = n_str.unwrap().parse().unwrap();

    let m_str = iter.next();
    let m: usize = if let Some(s) = m_str { s.parse().unwrap() } else { 0 };

    let mut raw_edges = Vec::with_capacity(m);
    for _ in 0..m {
        // Convert 1-based indices to 0-based
        let u: u32 = iter.next().unwrap().parse::<u32>().unwrap() - 1;
        let v: u32 = iter.next().unwrap().parse::<u32>().unwrap() - 1;
        raw_edges.push((u, v));
    }

    // 2. Build Graph
    let graph = Graph::new(n, &raw_edges);

    // 3. Find Connected Components (Iterative DFS)
    let mut visited = vec![false; n];
    let mut components = Vec::new();
    let mut stack = Vec::new();

    for i in 0..n {
        if !visited[i] {
            let mut component = Vec::new();
            visited[i] = true;
            stack.push(i as u32);

            while let Some(u) = stack.pop() {
                component.push(u);

                let start = graph.offsets[u as usize];
                let end = graph.offsets[u as usize + 1];

                for k in start..end {
                    let v = graph.edges[k];
                    if !visited[v as usize] {
                        visited[v as usize] = true;
                        stack.push(v);
                    }
                }
            }
            components.push(component);
        }
    }

    // 4. Calculate Sum of Diameters in Parallel
    // We use map_init to allocate reuseable buffers for BFS per thread
    let total_diameter: u64 = components.par_iter()
        .map_init(
            || (vec![u32::MAX; n], Vec::with_capacity(1024)), 
            | (dist, queue), comp | {
                if comp.is_empty() { return 0; }
                if comp.len() == 1 { return 1; }

                // BFS helper to find the farthest node and its distance
                let get_farthest = |start_node: u32, comp_nodes: &Vec<u32>, dist_arr: &mut Vec<u32>, q: &mut Vec<u32>| -> (u32, u32) {
                    // Reset distances only for nodes in the current component
                    // Nodes from other components are untouched and their values don't matter 
                    // because we only traverse edges within the component.
                    for &node in comp_nodes {
                        dist_arr[node as usize] = u32::MAX;
                    }

                    q.clear();
                    q.push(start_node);
                    dist_arr[start_node as usize] = 0;

                    let mut max_d = 0;
                    let mut farthest = start_node;

                    let mut head = 0;
                    while head < q.len() {
                        let u = q[head];
                        head += 1;

                        let d = dist_arr[u as usize];
                        if d > max_d {
                            max_d = d;
                            farthest = u;
                        }

                        let start_edge = graph.offsets[u as usize];
                        let end_edge = graph.offsets[u as usize + 1];

                        for k in start_edge..end_edge {
                            let v = graph.edges[k];
                            // Visit if not visited (u32::MAX)
                            if dist_arr[v as usize] == u32::MAX {
                                dist_arr[v as usize] = d + 1;
                                q.push(v);
                            }
                        }
                    }
                    (farthest, max_d)
                };

                // Double BFS to find diameter
                // 1. Find one endpoint (u) of the diameter
                let (u, _) = get_farthest(comp[0], comp, dist, queue);
                // 2. Find the other endpoint and the distance (diameter in edges)
                let (_, d) = get_farthest(u, comp, dist, queue);

                // Diameter in nodes is edges + 1
                (d + 1) as u64
            }
        )
        .sum();

    println!("{}", total_diameter);
}

