fn bfs(start: usize, adj: &Vec<Vec<usize>>) -> (usize, usize) {
    let mut dist = HashMap::new();
    let mut q = VecDeque::new();

    dist.insert(start, 0);
    q.push_back(start);

    let mut max_node = start;
    let mut max_d = 0;

    while let Some(u) = q.pop_front() {
        let d = dist[&u];
        if d > max_d {
            max_d = d;
            max_node = u;
        }

        for &v in &adj[u] {
            if !dist.contains_key(&v) {
                dist.insert(v, d + 1);
                q.push_back(v);
            }
        }
    }
    (max_node, max_d)
