use std::io::{self, Read};
use rayon::prelude::*;

// High-performance scanner using raw pointers for maximum speed
struct Scanner {
    buffer: Vec<u8>,
    cursor: usize,
}

impl Scanner {
    fn new() -> Self {
        let mut buffer = Vec::new();
        io::stdin().read_to_end(&mut buffer).unwrap();
        Self { buffer, cursor: 0 }
    }

    #[inline(always)]
    fn next_u32(&mut self) -> Option<u32> {
        let ptr = self.buffer.as_ptr();
        let len = self.buffer.len();
        if self.cursor >= len {
            return None;
        }

        let mut n = 0;
        let mut started = false;

        unsafe {
            let mut curr = ptr.add(self.cursor);
            let end = ptr.add(len);

            // Fast forward to digit
            while curr < end {
                let b = *curr;
                if b >= b'0' && b <= b'9' {
                    break;
                }
                curr = curr.add(1);
            }

            if curr == end {
                self.cursor = len;
                return None;
            }

            // Parse integer
            while curr < end {
                let b = *curr;
                if b < b'0' || b > b'9' {
                    break;
                }
                n = n * 10 + (b - b'0') as u32;
                started = true;
                curr = curr.add(1);
            }

            self.cursor = curr.offset_from(ptr) as usize;
        }

        if started { Some(n) } else { None }
    }
}

fn main() {
    let mut scanner = Scanner::new();

    // Read N (number of bacteria)
    let n = match scanner.next_u32() {
        Some(x) => x as usize,
        None => return,
    };

    if n == 0 {
        println!("0");
        return;
    }

    // Read M (number of edges)
    let m = scanner.next_u32().unwrap_or(0) as usize;

    // Use flat vector for edges to optimize cache and allocation
    let mut raw_edges = Vec::with_capacity(m * 2);
    let mut degrees = vec![0u32; n];

    for _ in 0..m {
        // Convert 1-based indices to 0-based
        let u = scanner.next_u32().unwrap() - 1;
        let v = scanner.next_u32().unwrap() - 1;
        raw_edges.push(u);
        raw_edges.push(v);
        unsafe {
            *degrees.get_unchecked_mut(u as usize) += 1;
            *degrees.get_unchecked_mut(v as usize) += 1;
        }
    }

    // Build CSR (Compressed Sparse Row) Graph
    let mut head = vec![0u32; n + 1];
    let mut acc = 0;
    for i in 0..n {
        head[i] = acc;
        acc += degrees[i];
    }
    head[n] = acc;

    let mut adj = vec![0u32; acc as usize];
    let mut curr = head.clone();

    for i in 0..m {
        let u = raw_edges[2 * i];
        let v = raw_edges[2 * i + 1];
        unsafe {
            let pu = *curr.get_unchecked(u as usize) as usize;
            *adj.get_unchecked_mut(pu) = v;
            *curr.get_unchecked_mut(u as usize) += 1;

            let pv = *curr.get_unchecked(v as usize) as usize;
            *adj.get_unchecked_mut(pv) = u;
            *curr.get_unchecked_mut(v as usize) += 1;
        }
    }

    drop(raw_edges);
    drop(degrees);
    drop(curr);

    // Pass 1: Identify connected components and find one endpoint of the diameter for each
    let mut visited = vec![false; n];
    let mut endpoints = Vec::with_capacity(n);
    let mut singletons = 0u64;
    let mut stack = Vec::with_capacity(n);

    for i in 0..n {
        unsafe {
            if *visited.get_unchecked(i) {
                continue;
            }

            // Optimization: check for singleton (degree 0)
            let start = *head.get_unchecked(i);
            let end = *head.get_unchecked(i + 1);
            if start == end {
                singletons += 1;
                *visited.get_unchecked_mut(i) = true;
                continue;
            }

            *visited.get_unchecked_mut(i) = true;
            stack.clear();
            stack.push((i as u32, 0));

            let mut max_dist = 0;
            let mut farthest = i as u32;

            // DFS to traverse component and find farthest node from i
            while let Some((u, dist)) = stack.pop() {
                if dist > max_dist {
                    max_dist = dist;
                    farthest = u;
                }

                let u_idx = u as usize;
                let s = *head.get_unchecked(u_idx) as usize;
                let e = *head.get_unchecked(u_idx + 1) as usize;

                for k in s..e {
                    let v = *adj.get_unchecked(k);
                    let v_idx = v as usize;
                    if !*visited.get_unchecked(v_idx) {
                        *visited.get_unchecked_mut(v_idx) = true;
                        stack.push((v, dist + 1));
                    }
                }
            }
            endpoints.push(farthest);
        }
    }

    drop(visited);
    drop(stack);

    let head_ref = &head;
    let adj_ref = &adj;

    // Pass 2: Calculate diameter for each component in parallel
    // Start DFS from the endpoint found in Pass 1 to find the other endpoint
    let total_diameter: u64 = endpoints.par_iter()
        .map_init(
            || Vec::with_capacity(1024), // Thread-local stack
            |stack, &start_node| {
                stack.clear();
                // (node, distance, parent) - use parent to avoid cycles in tree
                stack.push((start_node, 0, u32::MAX));

                let mut max_dist = 0;

                while let Some((u, dist, p)) = stack.pop() {
                    if dist > max_dist {
                        max_dist = dist;
                    }

                    let u_idx = u as usize;
                    unsafe {
                        let s = *head_ref.get_unchecked(u_idx) as usize;
                        let e = *head_ref.get_unchecked(u_idx + 1) as usize;

                        for k in s..e {
                            let v = *adj_ref.get_unchecked(k);
                            if v != p {
                                stack.push((v, dist + 1, u));
                            }
                        }
                    }
                }
                // Diameter in nodes is edge distance + 1
                (max_dist + 1) as u64
            }
        ).sum();

    println!("{}", total_diameter + singletons);
}

