fn solve_component(comp: &Component, global: &GlobalData) -> Option<Vec<(usize, f64)>> {
    let mut l_bound = f64::NEG_INFINITY;
    let mut r_bound = f64::INFINITY;
    let mut sum_sigma_c = 0.0;

    // Determine bounds for x (radius variable)
    for &u in &comp.nodes {
        let s = global.sigma[u];
        let val = global.c[u];

        // r_i = sigma * x + c >= 0
        if s == 1 {
            // x >= -c
            if -val > l_bound { l_bound = -val; }
        } else {
            // x <= c
            if val < r_bound { r_bound = val; }
        }
        sum_sigma_c += (s as f64) * val;
    }

    if l_bound > r_bound + EPS {
        return None;
    }

    let mut fixed_x: Option<f64> = None;

    for &(u, v, dist) in &comp.constraints {
        let s_u = global.sigma[u] as i32;
        let c_u = global.c[u];
        let s_v = global.sigma[v] as i32;
        let c_v = global.c[v];

        // r_u + r_v = dist
        let s_sum = s_u + s_v;
        let rhs = dist - c_u - c_v;

        if s_sum == 0 {
            // Even cycle or tree consistency: 0 = rhs
            if rhs.abs() > EPS {
                return None;
            }
        } else {
            // Odd cycle: +/- 2 * x = rhs
            let x_val = rhs / (s_sum as f64);
            if let Some(fx) = fixed_x {
                if (fx - x_val).abs() > EPS {
                    return None;
                }
            } else {
                fixed_x = Some(x_val);
            }
        }
    }

    let final_x;
    if let Some(fx) = fixed_x {
        if fx < l_bound - EPS || fx > r_bound + EPS {
            return None;
        }
        // Clamp to bounds to handle precision noise
        if fx < l_bound { final_x = l_bound; }
        else if fx > r_bound { final_x = r_bound; }
        else { final_x = fx; }
    } else {
        // Minimize sum(r^2): vertex of parabola
        let count = comp.nodes.len() as f64;
        let optimal = -sum_sigma_c / count;

        if optimal < l_bound { final_x = l_bound; }
        else if optimal > r_bound { final_x = r_bound; }
        else { final_x = optimal; }
    }

    let mut radii = Vec::with_capacity(comp.nodes.len());
    for &u in &comp.nodes {
        let r = (global.sigma[u] as f64) * final_x + global.c[u];
        if r < -1e-4 {
             return None;
        }
        radii.push((u, r.max(0.0)));
    }

    Some(radii)
}

