    // Key: global index, Value: Param
    let mut params = HashMap::with_capacity(k);
    let root = comp_nodes[0];
    params.insert(root, Param { sigma: 1, c: 0.0 });

    let mut stack = vec![root];
    let mut fixed_x: Option<f64> = None;

    while let Some(u) = stack.pop() {
        let p_u = *params.get(&u).unwrap();

        for edge in &adj[u] {
            if let Some(&p_v) = params.get(&edge.to) {
                // Node already visited, check consistency
                let sigma_sum = (p_u.sigma + p_v.sigma) as i32;
                let rhs = edge.dist - p_u.c - p_v.c;

                if sigma_sum == 0 {
                    // Bipartite constraint (even cycle or parallel paths with different parity)
                    if rhs.abs() > EPS {
                        return None;
                    }
                } else {
                    // Odd cycle or parity conflict fixing x
                    let val = rhs / (sigma_sum as f64);
                    if let Some(fx) = fixed_x {
