fn solve_component(comp_nodes: &[usize], adj: &[Vec<Edge>]) -> Option<Vec<(usize, f64)>> {
    let k = comp_nodes.len();
    if k == 0 {
        return Some(Vec::new());
    }

    // Map global indices to local component indices (0..k)
    let mut global_to_local = HashMap::with_capacity(k);
    for (i, &u) in comp_nodes.iter().enumerate() {
        global_to_local.insert(u, i);
    }

    // params[i] stores (sigma, c) meaning r_i = sigma * x + c
    let mut params: Vec<Option<Param>> = vec![None; k];

    // Start traversal from the first node in the component
    let root_local = 0;
    params[root_local] = Some(Param { sigma: 1, c: 0.0 });

    let mut stack = vec![root_local];
    let mut fixed_x: Option<f64> = None;

    while let Some(u_local) = stack.pop() {
        let u_global = comp_nodes[u_local];
        let p_u = params[u_local].unwrap();

        for edge in &adj[u_global] {
            // Check if neighbor is in component (always true by definition)
            if let Some(&v_local) = global_to_local.get(&edge.to) {
                if let Some(p_v) = params[v_local] {
                    // Edge to already visited node: check consistency
                    // Constraint: r_u + r_v = dist
                    // (sigma_u * x + c_u) + (sigma_v * x + c_v) = dist
                    // (sigma_u + sigma_v) * x = dist - c_u - c_v

                    let sigma_sum = (p_u.sigma + p_v.sigma) as i32;
                    let rhs = edge.dist - p_u.c - p_v.c;

                    if sigma_sum == 0 {
                        // Bipartite constraint (even cycle or parallel paths with different parity)
                        // 0 = rhs. If rhs is not 0, it's impossible.
                        if rhs.abs() > EPS {
                            return None;
                        }
                    } else {
                        // Odd cycle or parity conflict fixing x
                        // +/- 2 * x = rhs
                        let val = rhs / (sigma_sum as f64);
                        if let Some(fx) = fixed_x {
                            if (fx - val).abs() > EPS {
                                return None; // Contradiction in fixed x
                            }
                        } else {
                            fixed_x = Some(val);
                        }
                    }
                } else {
                    // Visit new node
                    // r_v = dist - r_u = dist - (sigma_u * x + c_u) = -sigma_u * x + (dist - c_u)
                    let p_v = Param {
                        sigma: -p_u.sigma,
                        c: edge.dist - p_u.c,
                    };
                    params[v_local] = Some(p_v);
                    stack.push(v_local);
                }
            }
        }
    }

    // Determine valid range [l_bound, r_bound] for x such that r_i >= 0 for all i
    let mut l_bound = f64::NEG_INFINITY;
    let mut r_bound = f64::INFINITY;
    let mut sum_sigma_c = 0.0;

    for i in 0..k {
        let p = params[i].unwrap();
        // Constraint: sigma * x + c >= 0
        if p.sigma == 1 {
            // x >= -c
            if -p.c > l_bound {
                l_bound = -p.c;
            }
        } else {
            // -x + c >= 0 => x <= c
            if p.c < r_bound {
                r_bound = p.c;
            }
        }
        sum_sigma_c += (p.sigma as f64) * p.c;
    }

    if l_bound > r_bound + EPS {
        return None;
    }

    let final_x;
    if let Some(fx) = fixed_x {
        // x is fixed by geometry constraints
        if fx < l_bound - EPS || fx > r_bound + EPS {
            return None;
        }
        // Clamp to bounds to handle floating point noise
        if fx < l_bound { final_x = l_bound; }
        else if fx > r_bound { final_x = r_bound; }
        else { final_x = fx; }
    } else {
        // x is free, minimize cost = sum(area) ~ sum(r^2)
        // minimize sum((sigma*x + c)^2)
        // The vertex of the parabola is at x = - sum(sigma * c) / k
        let optimal = -sum_sigma_c / (k as f64);

        if optimal < l_bound {
            final_x = l_bound;
        } else if optimal > r_bound {
            final_x = r_bound;
        } else {
            final_x = optimal;
        }
    }

    let mut component_results = Vec::with_capacity(k);
    for i in 0..k {
        let p = params[i].unwrap();
        let r = (p.sigma as f64) * final_x + p.c;
        if r < -1e-3 { return None; }
        component_results.push((comp_nodes[i], r.max(0.0)));
    }

    Some(component_results)
