    edges: Vec<Vec<Edge>>,
    raw_edges: Vec<(u32, u32, u32, u32)>, // u, v, w, id
}

struct Solution {
    count: usize,
    indices: Vec<u32>,
}

const MOD1: u64 = 1_000_000_007;
const MOD2: u64 = 1_000_000_009;
const INF: u64 = u64::MAX;

fn solve_case(tc: &TestCase) -> Solution {
    let n = tc.n;
    let start_node = 1;
    let end_node = n as u32;

    let (dist_s, ways_s1, ways_s2) = dijkstra_ways(n, start_node, &tc.edges);

    // For T, we need reverse edges. But graph is undirected, so same edges.
    let (dist_t, ways_t1, ways_t2) = dijkstra_ways(n, end_node, &tc.edges);

    let shortest_path_len = dist_s[end_node as usize];
    if shortest_path_len == INF {
        return Solution { count: 0, indices: vec![] };
    }

    let total_ways1 = ways_s1[end_node as usize];
    let total_ways2 = ways_s2[end_node as usize];

    // Identify critical edges
    let mut critical_edges = Vec::new();
    let mut edge_rank = vec![0; tc.m + 1];

    for (u, v, w, id) in &tc.raw_edges {
        // Check u -> v
        let u_idx = *u as usize;
        let v_idx = *v as usize;
        let w_u64 = *w as u64;

        if dist_s[u_idx] != INF && dist_t[v_idx] != INF {
            if dist_s[u_idx] + w_u64 + dist_t[v_idx] == shortest_path_len {
                let w1 = (ways_s1[u_idx] * ways_t1[v_idx]) % MOD1;
                let w2 = (ways_s2[u_idx] * ways_t2[v_idx]) % MOD2;
                if w1 == total_ways1 && w2 == total_ways2 {
                    critical_edges.push((*u, *v, *id, dist_s[u_idx]));
                }
            }
        }
        // Check v -> u
        if dist_s[v_idx] != INF && dist_t[u_idx] != INF {
            if dist_s[v_idx] + w_u64 + dist_t[u_idx] == shortest_path_len {
                let w1 = (ways_s1[v_idx] * ways_t1[u_idx]) % MOD1;
                let w2 = (ways_s2[v_idx] * ways_t2[u_idx]) % MOD2;
                if w1 == total_ways1 && w2 == total_ways2 {
                    critical_edges.push((*v, *u, *id, dist_s[v_idx]));
                }
            }
        }
    }

    critical_edges.sort_by(|a, b| a.3.cmp(&b.3));
    let num_critical = critical_edges.len();

    if num_critical == 0 {
         return Solution { count: 0, indices: vec![] };
    }

    for (i, item) in critical_edges.iter().enumerate() {
        edge_rank[item.2 as usize] = i + 1;
    }

