    // P[u] = min over parents x of (if (x,u) is crit ? rank : P[x])
    let mut nodes_by_dist_s: Vec<usize> = (1..=n).collect();
    nodes_by_dist_s.sort_by(|&a, &b| dist_s[a].cmp(&dist_s[b]));

    let mut p = vec![usize::MAX; n + 1];
    p[start_node as usize] = 0;

    for &u in &nodes_by_dist_s {
        if dist_s[u] == INF { break; } 
        let pu = p[u];
        if pu == usize::MAX { continue; } 

        for edge in &tc.edges[u] {
            let v = edge.to as usize;
            let w = edge.weight as u64;
            if dist_s[v] == dist_s[u] + w {
                let rank = edge_rank[edge.id as usize];
                let val = if rank > 0 { rank } else { pu };
                if val < p[v] {
                    p[v] = val;
                }
            }
        }
    }

