    // S[u] = max over children v of (if (u,v) is crit ? rank : S[v])
    // Use reverse order of dist_t to process
    let mut nodes_by_dist_t: Vec<usize> = (1..=n).collect();
    nodes_by_dist_t.sort_by(|&a, &b| dist_t[a].cmp(&dist_t[b]));

