            let w = edge.weight as u64;
            if dist_t[v] == dist_t[u] + w {
                let rank = edge_rank[edge.id as usize];
                let val = if rank > 0 { rank } else { su };
                if val > s[v] {
                    s[v] = val;
                }
            }
        }
    }

    let mut diff = vec![0i32; num_critical + 2];

    for (u, v, w, _) in &tc.raw_edges {
        let u_idx = *u as usize;
        let v_idx = *v as usize;
        let w_u64 = *w as u64;

        // Try u -> v
        if dist_s[u_idx] != INF && dist_t[v_idx] != INF {
            if dist_s[u_idx] + w_u64 + dist_t[v_idx] == shortest_path_len + 1 {
                if p[u_idx] != usize::MAX && s[v_idx] != 0 {
                    let l = p[u_idx] + 1;
                    let r = s[v_idx] - 1;
                    if l <= r {
                        diff[l] += 1;
                        if r + 1 <= num_critical {
                            diff[r + 1] -= 1;
                        }
                    }
                }
            }
        }
        // Try v -> u
        if dist_s[v_idx] != INF && dist_t[u_idx] != INF {
            if dist_s[v_idx] + w_u64 + dist_t[u_idx] == shortest_path_len + 1 {
                if p[v_idx] != usize::MAX && s[u_idx] != 0 {
                    let l = p[v_idx] + 1;
