        let n = scanner.next_u32().unwrap() as usize;
        let m = scanner.next_u32().unwrap() as usize;

        let mut edges = vec![Vec::new(); n];
        let mut raw_edges = Vec::with_capacity(m);

        for i in 0..m {
            let u = scanner.next_u32().unwrap() - 1;
            let v = scanner.next_u32().unwrap() - 1;
            let w = scanner.next_u32().unwrap();
            let id = (i + 1) as u32;

            edges[u as usize].push(Edge { to: v, weight: w, id });
            edges[v as usize].push(Edge { to: u, weight: w, id });
            raw_edges.push(RawEdge { u, v, weight: w, id });
        }
        test_cases.push((n, m, edges, raw_edges));
    }

    let solutions: Vec<Solution> = test_cases.into_par_iter()
        .map(|(n, m, edges, raw_edges)| solve_case(n, m, edges, raw_edges))
        .collect();

    for sol in solutions {
        writeln!(out, "{}", sol.count).ok();
        for (i, val) in sol.indices.iter().enumerate() {
            if i > 0 {
                write!(out, " ").ok();
            }
            write!(out, "{}", val).ok();
        }
        writeln!(out).ok();
    }
}

