const INF64: u64 = 1_000_000_000_000_000_000; // 1e18

// Fast Dijkstra
fn dijkstra(n: usize, start: usize, adj: &Vec<Vec<Edge>>) -> Vec<u64> {
    let mut dist = vec![INF64; n];
