        if dist_s[u] == INF64 { continue; }
        let w1 = ways_s_1[u];
        let w2 = ways_s_2[u];
        if w1 == 0 && w2 == 0 { continue; }

        for e in &edges[u] {
            let v = e.to as usize;
            if dist_s[v] == dist_s[u] + e.weight as u64 {
                ways_s_1[v] = (ways_s_1[v] + w1) % MOD1;
                ways_s_2[v] = (ways_s_2[v] + w2) % MOD2;
            }
        }
    }

    // Backward path counting
    let mut ways_t_1 = vec![0u64; n];
    let mut ways_t_2 = vec![0u64; n];
    ways_t_1[end_node] = 1;
    ways_t_2[end_node] = 1;

    let mut nodes_by_dist_t: Vec<usize> = (0..n).collect();
    nodes_by_dist_t.sort_unstable_by(|&a, &b| dist_t[a].cmp(&dist_t[b]));

    for &u in &nodes_by_dist_t {
        if dist_t[u] == INF64 { continue; }
        let w1 = ways_t_1[u];
        let w2 = ways_t_2[u];
        if w1 == 0 && w2 == 0 { continue; }

        for e in &edges[u] {
            let v = e.to as usize;
            if dist_t[v] == dist_t[u] + e.weight as u64 {
                ways_t_1[v] = (ways_t_1[v] + w1) % MOD1;
                ways_t_2[v] = (ways_t_2[v] + w2) % MOD2;
            }
        }
    }

    let total_ways_1 = ways_s_1[end_node];
    let total_ways_2 = ways_s_2[end_node];

    // Identify critical edges
    let mut critical_edges = Vec::new();
    let mut edge_rank = vec![0; m + 1];

    for r in &raw_edges {
        let u = r.u as usize;
        let v = r.v as usize;
        let w = r.weight as u64;
        let id = r.id as usize;

        // Check u -> v
        if dist_s[u] != INF64 && dist_t[v] != INF64 && dist_s[u] + w + dist_t[v] == shortest_path_len {
             let w1 = (ways_s_1[u] * ways_t_1[v]) % MOD1;
             let w2 = (ways_s_2[u] * ways_t_2[v]) % MOD2;
             if w1 == total_ways_1 && w2 == total_ways_2 {
                 critical_edges.push((u, v, id, dist_s[u]));
             }
        }
        // Check v -> u
        else if dist_s[v] != INF64 && dist_t[u] != INF64 && dist_s[v] + w + dist_t[u] == shortest_path_len {
             let w1 = (ways_s_1[v] * ways_t_1[u]) % MOD1;
             let w2 = (ways_s_2[v] * ways_t_2[u]) % MOD2;
             if w1 == total_ways_1 && w2 == total_ways_2 {
                 critical_edges.push((v, u, id, dist_s[v]));
             }
        }
    }

    critical_edges.sort_unstable_by(|a, b| a.3.cmp(&b.3));
    let num_critical = critical_edges.len();
    for (i, item) in critical_edges.iter().enumerate() {
        edge_rank[item.2] = (i + 1) as i32;
    }

    // Compute P[u] (max_crit_S)
    let mut p = vec![-1i32; n];
    p[start_node] = 0;

    // Process in topological order (by distance)
    for &u in &nodes_by_dist_s {
        if dist_s[u] == INF64 { continue; }
        if u != start_node && p[u] == -1 { continue; }

        let pu = p[u];

        for e in &edges[u] {
            let v = e.to as usize;
            if dist_s[v] == dist_s[u] + e.weight as u64 {
                let rank = edge_rank[e.id as usize];
                let val = if rank > 0 { rank } else { pu };

                if p[v] == -1 {
                    p[v] = val;
                } else {
                    p[v] = std::cmp::min(p[v], val);
                }
            }
        }
    }

    // Compute S[u] (min_crit_T)
    let mut s = vec![-1i32; n];
    s[end_node] = (num_critical + 1) as i32;

    // Process in reverse topological order (by distance from T)
    for &u in &nodes_by_dist_t {
        if dist_t[u] == INF64 { continue; }
        if u != end_node && s[u] == -1 { continue; }

        let su = s[u];

        for e in &edges[u] {
            let v = e.to as usize;
            if dist_t[v] == dist_t[u] + e.weight as u64 {
                let rank = edge_rank[e.id as usize];
                let val = if rank > 0 { rank } else { su };

                if s[v] == -1 {
                    s[v] = val;
                } else {
                    s[v] = std::cmp::max(s[v], val);
                }
            }
        }
    }

    let mut diff = vec![0i32; num_critical + 2];
    for r in &raw_edges {
        let u = r.u as usize;
        let v = r.v as usize;
        let w = r.weight as u64;

        let mut process = |u_idx: usize, v_idx: usize| {
             if dist_s[u_idx] != INF64 && dist_t[v_idx] != INF64 && dist_s[u_idx] + w + dist_t[v_idx] == shortest_path_len + 1 {
                let l = p[u_idx];
                let r_val = s[v_idx];
                if l != -1 && r_val != -1 && l < r_val - 1 {
                    diff[(l + 1) as usize] += 1;
                    diff[r_val as usize] -= 1;
                }
            }
        };

        // u -> v
        process(u, v);
        // v -> u
        process(v, u);
    }

    let mut result_indices = Vec::new();
    let mut current = 0;
    for i in 1..=num_critical {
        current += diff[i];
        if current > 0 {
            result_indices.push(critical_edges[i-1].2 as u32);
        }
    }
    result_indices.sort_unstable();
    Solution { count: result_indices.len(), indices: result_indices }
}

struct Scanner<R> {
    reader: R,
    buffer: Vec<u8>,
    pos: usize,
    bytes_read: usize,
}

impl<R: Read> Scanner<R> {
    fn new(reader: R) -> Self {
        Scanner {
            reader,
            buffer: vec![0; 1 << 16],
            pos: 0,
            bytes_read: 0,
        }
    }

    #[inline]
    fn next_u32(&mut self) -> Option<u32> {
        let mut num = 0;
        let mut started = false;
        loop {
            if self.pos >= self.bytes_read {
                self.bytes_read = self.reader.read(&mut self.buffer).ok()?;
                self.pos = 0;
                if self.bytes_read == 0 {
                    return if started { Some(num) } else { None };
                }
            }
            let b = self.buffer[self.pos];
            if b >= b'0' && b <= b'9' {
                num = num * 10 + (b - b'0') as u32;
                started = true;
                self.pos += 1;
            } else if started {
                self.pos += 1;
                return Some(num);
            } else {
                self.pos += 1;
            }
        }
    }
}

fn main() {
    let stdin = io::stdin();
    let mut scanner = Scanner::new(stdin.lock());
    let mut out = io::BufWriter::new(io::stdout().lock());

