        indices: result_indices,
    }
}

fn dijkstra_ways(n: usize, start: u32, edges: &Vec<Vec<Edge>>) -> (Vec<u64>, Vec<u64>, Vec<u64>) {
    let mut dist = vec![INF; n + 1];
    let mut ways1 = vec![0u64; n + 1];
    let mut ways2 = vec![0u64; n + 1];

    dist[start as usize] = 0;
    ways1[start as usize] = 1;
    ways2[start as usize] = 1;

    let mut pq = BinaryHeap::new();
    pq.push(Reverse((0, start)));

    while let Some(Reverse((d, u))) = pq.pop() {
        if d > dist[u as usize] { continue; }

        for e in &edges[u as usize] {
            let next_d = d + e.weight as u64;
            if next_d < dist[e.to as usize] {
                dist[e.to as usize] = next_d;
                ways1[e.to as usize] = ways1[u as usize];
                ways2[e.to as usize] = ways2[u as usize];
                pq.push(Reverse((next_d, e.to)));
            } else if next_d == dist[e.to as usize] {
                ways1[e.to as usize] = (ways1[e.to as usize] + ways1[u as usize]) % MOD1;
                ways2[e.to as usize] = (ways2[e.to as usize] + ways2[u as usize]) % MOD2;
            }
        }
    }
    (dist, ways1, ways2)
}

