                }
            }
        }
    }

    // S[u]: Min rank of a critical edge that is part of ALL shortest paths u -> T
    let mut s_val = vec![0; n];
    s_val[end_node] = num_critical + 1;

    for &u in &order_t {
        if dist_t[u] == INF64 { continue; }

        let mut max_s = 0;
        let mut found_child = false;

        for e in &edges[u] {
            let v = e.to as usize;
            let w = e.weight as u64;
            // Iterate children in SP DAG towards T
            if dist_t[u] == dist_t[v] + w {
                let rank = edge_rank[e.id as usize];
                if s_val[v] > 0 {
                    let val = if rank > 0 { rank } else { s_val[v] };
                    if val > max_s {
                        max_s = val;
                    }
                    found_child = true;
                }
            }
        }

        if found_child {
            s_val[u] = max_s;
        }
    }

    // Difference array
    let mut diff = vec![0i32; num_critical + 2];

    for raw in &raw_edges {
        let u = raw.u as usize;
        let v = raw.v as usize;
        let w = raw.weight as u64;

        let mut check_bypass = |from: usize, to: usize| {
            if dist_s[from] != INF64 && dist_t[to] != INF64 {
                if dist_s[from] + w + dist_t[to] == shortest_path_len + 1 {
                    let l = p_val[from];
                    let r = s_val[to];

                    if l < r && r > 0 {
                         let start = l + 1;
                         let end = r - 1;
                         if start <= end {
                             diff[start] += 1;
                             if end + 1 <= num_critical {
                                 diff[end + 1] -= 1;
                             }
                         }
                    }
                }
            }
        };

        check_bypass(u, v);
        check_bypass(v, u);
    }

    let mut result_indices = Vec::new();
    let mut current = 0;
    for i in 1..=num_critical {
        current += diff[i];
        if current > 0 {
            result_indices.push(critical_edges[i-1].2);
        }
    }
    result_indices.sort_unstable();

    Solution {
        count: result_indices.len(),
        indices: result_indices,
    }
}

