use std::io::{self, Read, Write};
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Reverse;

#[derive(Clone, Copy)]
struct Edge {
    to: u32,
    weight: u32,
    id: u32,
}

#[derive(Clone)]
struct RawEdge {
    u: u32,
    v: u32,
    w: u32,
    id: u32,
}

struct Solution {
    count: usize,
    indices: Vec<u32>,
}

const INF64: u64 = 1_000_000_000_000_000_000;
const MOD1: u64 = 1_000_000_007;
const MOD2: u64 = 1_000_000_009;

fn dijkstra(n: usize, start: usize, adj: &[Vec<Edge>]) -> Vec<u64> {
    let mut dist = vec![INF64; n];
    let mut pq = BinaryHeap::new();

    dist[start] = 0;
    pq.push(Reverse((0, start)));

    while let Some(Reverse((d, u))) = pq.pop() {
        if d > dist[u] { continue; }
        for e in &adj[u] {
            let next_d = d + e.weight as u64;
            let v = e.to as usize;
            if next_d < dist[v] {
                dist[v] = next_d;
                pq.push(Reverse((next_d, v)));
            }
        }
    }
    dist
}

fn solve_case(n: usize, m: usize, edges: Vec<RawEdge>, adj: Vec<Vec<Edge>>) -> Solution {
    // 1. Compute distances from Start and End
    let dist_s = dijkstra(n, 0, &adj);
    let dist_t = dijkstra(n, n - 1, &adj);

    let l = dist_s[n - 1];
    if l == INF64 {
        return Solution { count: 0, indices: vec![] };
    }

    // 2. Sort nodes by distance for DAG processing
    let mut nodes_by_s: Vec<usize> = (0..n).collect();
    nodes_by_s.sort_unstable_by(|&a, &b| dist_s[a].cmp(&dist_s[b]));

    // 3. Count ways from S and to T to identify critical edges
    let mut ways_s = vec![(0u64, 0u64); n];
    ways_s[0] = (1, 1);

    for &u in &nodes_by_s {
        if dist_s[u] == INF64 { continue; }
        let (w1, w2) = ways_s[u];
        if w1 == 0 && w2 == 0 { continue; }

        for e in &adj[u] {
            let v = e.to as usize;
            if dist_s[v] == dist_s[u] + e.weight as u64 {
                ways_s[v].0 = (ways_s[v].0 + w1) % MOD1;
                ways_s[v].1 = (ways_s[v].1 + w2) % MOD2;
            }
        }
    }

    // Backward ways (using dist_t to determine valid edges on SP)
    let mut ways_t = vec![(0u64, 0u64); n];
    ways_t[n - 1] = (1, 1);

    // We process nodes in reverse topological order (decreasing distance from S roughly corresponds to increasing distance from T on SP)
    // Using nodes_by_s in reverse is correct for SP DAG
    for &u in nodes_by_s.iter().rev() {
        if dist_t[u] == INF64 { continue; }
        let (w1, w2) = ways_t[u];
        if w1 == 0 && w2 == 0 { continue; }

        for e in &adj[u] {
            let v = e.to as usize;
            if dist_t[v] == dist_t[u] + e.weight as u64 {
                ways_t[v].0 = (ways_t[v].0 + w1) % MOD1;
                ways_t[v].1 = (ways_t[v].1 + w2) % MOD2;
            }
        }
    }

    let total_ways = ways_s[n - 1];

    // 4. Identify critical edges
    let mut critical_edges = Vec::new();
    let mut edge_rank = vec![0; m + 1];

    for r in &edges {
        let u = r.u as usize;
        let v = r.v as usize;
        let w = r.w as u64;

        // Check u -> v direction on SP
        if dist_s[u] != INF64 && dist_t[v] != INF64 && dist_s[u] + w + dist_t[v] == l {
            let (su1, su2) = ways_s[u];
            let (tv1, tv2) = ways_t[v];
            if (su1 * tv1) % MOD1 == total_ways.0 && (su2 * tv2) % MOD2 == total_ways.1 {
                critical_edges.push((u, v, r.id, dist_s[u]));
            }
        } 
        // Check v -> u direction on SP
        else if dist_s[v] != INF64 && dist_t[u] != INF64 && dist_s[v] + w + dist_t[u] == l {
            let (sv1, sv2) = ways_s[v];
            let (tu1, tu2) = ways_t[u];
            if (sv1 * tu1) % MOD1 == total_ways.0 && (sv2 * tu2) % MOD2 == total_ways.1 {
                critical_edges.push((v, u, r.id, dist_s[v]));
            }
        }
    }

    // Sort critical edges by position on path
    critical_edges.sort_unstable_by(|a, b| a.3.cmp(&b.3));
    let k = critical_edges.len();
    for (i, &(_, _, id, _)) in critical_edges.iter().enumerate() {
        edge_rank[id as usize] = (i + 1) as i32;
    }

    // 5. Compute Q[u]: Last critical edge on all SPs S -> u
    let mut q = vec![-1i32; n];
    q[0] = 0;

    for &u in &nodes_by_s {
        if dist_s[u] == INF64 { continue; }
        if q[u] == -1 { continue; } 

        let cur_q = q[u];
        for e in &adj[u] {
            let v = e.to as usize;
            if dist_s[v] == dist_s[u] + e.weight as u64 {
                let rank = edge_rank[e.id as usize];
                // If edge is critical (rank > 0), it becomes the new "latest"
                let val = if rank > 0 { rank } else { cur_q };

                if q[v] == -1 {
                    q[v] = val;
                } else {
                    q[v] = std::cmp::min(q[v], val);
                }
            }
        }
    }

    // 6. Compute R[u]: First critical edge on all SPs u -> T
    let mut nodes_by_t: Vec<usize> = (0..n).collect();
    nodes_by_t.sort_unstable_by(|&a, &b| dist_t[a].cmp(&dist_t[b]));

    let mut r_val = vec![-1i32; n];
    r_val[n - 1] = (k + 1) as i32;

    for &u in &nodes_by_t {
        if dist_t[u] == INF64 { continue; }
        if r_val[u] == -1 { continue; }

        let cur_r = r_val[u];
        for e in &adj[u] {
            let v = e.to as usize;
            if dist_t[v] == dist_t[u] + e.weight as u64 {
                let rank = edge_rank[e.id as usize];
                let val = if rank > 0 { rank } else { cur_r };

                if r_val[v] == -1 {
                    r_val[v] = val;
                } else {
                    r_val[v] = std::cmp::max(r_val[v], val);
                }
            }
        }
    }

    // 7. Find bypasses using difference array
    let mut diff = vec![0i32; k + 2];
    for edge in &edges {
        let u = edge.u as usize;
        let v = edge.v as usize;
        let w = edge.w as u64;

        // Try using u->v as bypass
        if dist_s[u] != INF64 && dist_t[v] != INF64 && dist_s[u] + w + dist_t[v] == l + 1 {
            let qu = q[u];
            let rv = r_val[v];
            if qu != -1 && rv != -1 && qu < rv - 1 {
                diff[(qu + 1) as usize] += 1;
                diff[rv as usize] -= 1;
            }
        }

        // Try using v->u as bypass
        if dist_s[v] != INF64 && dist_t[u] != INF64 && dist_s[v] + w + dist_t[u] == l + 1 {
            let qv = q[v];
            let ru = r_val[u];
            if qv != -1 && ru != -1 && qv < ru - 1 {
                diff[(qv + 1) as usize] += 1;
                diff[ru as usize] -= 1;
            }
        }
    }

    let mut ans_indices = Vec::new();
    let mut cur = 0;
    for i in 1..=k {
        cur += diff[i];
        if cur > 0 {
            ans_indices.push(critical_edges[i-1].2);
        }
    }
    ans_indices.sort_unstable();

    Solution {
        count: ans_indices.len(),
        indices: ans_indices,
    }
}

