const MOD1: u64 = 1_000_000_007;
const MOD2: u64 = 1_000_000_009;

fn dijkstra(n: usize, start: usize, adj: &Vec<Vec<Edge>>) -> Vec<u64> {
    let mut dist = vec![u64::MAX; n];
    let mut pq = BinaryHeap::new();

    dist[start] = 0;
    pq.push(Reverse((0, start)));

    while let Some(Reverse((d, u))) = pq.pop() {
        if d > dist[u] { continue; }
        for e in &adj[u] {
            let next_d = d + e.weight as u64;
            if next_d < dist[e.to] {
                dist[e.to] = next_d;
                pq.push(Reverse((next_d, e.to)));
            }
        }
    }
    dist
}

fn count_ways(n: usize, start: usize, adj: &Vec<Vec<Edge>>, dist: &Vec<u64>) -> (Vec<u64>, Vec<u64>) {
    let mut ways1 = vec![0u64; n];
    let mut ways2 = vec![0u64; n];
    ways1[start] = 1;
    ways2[start] = 1;

    let mut nodes: Vec<usize> = (0..n).collect();
    nodes.sort_by(|&a, &b| dist[a].cmp(&dist[b]));

    for &u in &nodes {
        if dist[u] == u64::MAX { continue; }
        let w1 = ways1[u];
        let w2 = ways2[u];
        if w1 == 0 && w2 == 0 { continue; }

        for e in &adj[u] {
            if dist[e.to] != u64::MAX && dist[e.to] == dist[u] + e.weight as u64 {
                ways1[e.to] = (ways1[e.to] + w1) % MOD1;
                ways2[e.to] = (ways2[e.to] + w2) % MOD2;
            }
        }
    }
    (ways1, ways2)
}

