use std::io::{self, Read, Write};
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Hashing logic using double modulo to prevent collisions
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
struct Hash(u64, u64);

const M1: u64 = 1_000_000_007;
const M2: u64 = 1_000_000_009;

impl Hash {
    #[inline(always)]
    fn new(v: u64) -> Self {
        Hash(v % M1, v % M2)
    }
    #[inline(always)]
    fn zero() -> Self {
        Hash(0, 0)
    }
    #[inline(always)]
    fn one() -> Self {
        Hash(1, 1)
    }
    #[inline(always)]
    fn add(self, other: Self) -> Self {
        Hash((self.0 + other.0) % M1, (self.1 + other.1) % M2)
    }
    #[inline(always)]
    fn sub(self, other: Self) -> Self {
        Hash((self.0 + M1 - other.0) % M1, (self.1 + M2 - other.1) % M2)
    }
    #[inline(always)]
    fn mul(self, other: Self) -> Self {
        Hash((self.0 * other.0) % M1, (self.1 * other.1) % M2)
    }
}

#[derive(Clone)]
struct Edge {
    to: u32,
    weight: u32,
    id: u32,
}

struct TestCase {
    n: usize,
    m: usize,
    adj: Vec<Vec<Edge>>,
    edges_flat: Vec<(u32, u32, u32, u32)>, // u, v, w, id
}

#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: u64,
    position: usize,
}
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other.cost.cmp(&self.cost)
    }
}
impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Standard Dijkstra's algorithm
fn dijkstra(n: usize, adj: &Vec<Vec<Edge>>, start: usize) -> Vec<u64> {
    let mut dist = vec![u64::MAX; n + 1];
    dist[start] = 0;
    let mut pq = BinaryHeap::new();
    pq.push(State { cost: 0, position: start });

    while let Some(State { cost, position }) = pq.pop() {
        if cost > dist[position] { continue; }

        for edge in &adj[position] {
            let next = edge.to as usize;
            let next_cost = cost + edge.weight as u64;
            if next_cost < dist[next] {
                dist[next] = next_cost;
                pq.push(State { cost: next_cost, position: next });
            }
        }
    }
    dist
}

// Compute number of paths of length dist[u] (counts.0) and dist[u]+1 (counts.1)
fn compute_counts(n: usize, adj: &Vec<Vec<Edge>>, dist: &Vec<u64>, start: usize) -> Vec<(Hash, Hash)> {
    let mut counts = vec![(Hash::zero(), Hash::zero()); n + 1];
    if dist[start] == u64::MAX { return counts; }
    counts[start].0 = Hash::one();

    let mut nodes: Vec<usize> = (1..=n).collect();
    nodes.retain(|&u| dist[u] != u64::MAX);
    // Sort by distance to process in topological order of shortest path DAG
    nodes.sort_unstable_by(|&a, &b| dist[a].cmp(&dist[b]));

    // Step 1: Compute c0 (shortest paths)
    for &u in &nodes {
        let c0 = counts[u].0;
        if c0 == Hash::zero() { continue; }
        for edge in &adj[u] {
            let v = edge.to as usize;
            if dist[v] == u64::MAX { continue; }
            let w = edge.weight as u64;
            if dist[u] + w == dist[v] {
                counts[v].0 = counts[v].0.add(c0);
            }
        }
    }

    // Step 2: Add c0 -> c1 contributions (paths becoming +1 due to edge weight)
    for u in 1..=n {
        if dist[u] == u64::MAX { continue; }
        let c0 = counts[u].0;
        if c0 == Hash::zero() { continue; }
        for edge in &adj[u] {
            let v = edge.to as usize;
            if dist[v] == u64::MAX { continue; }
            let w = edge.weight as u64;
            // If edge makes path length exactly dist[v]+1 relative to global start
            if dist[u] + w == dist[v] + 1 {
                counts[v].1 = counts[v].1.add(c0);
            }
        }
    }

    // Step 3: Propagate c1 -> c1 (extending +1 paths along shortest path edges)
    for &u in &nodes {
        let c1 = counts[u].1;
        if c1 == Hash::zero() { continue; }
        for edge in &adj[u] {
            let v = edge.to as usize;
            if dist[v] == u64::MAX { continue; }
            let w = edge.weight as u64;
            if dist[u] + w == dist[v] {
                counts[v].1 = counts[v].1.add(c1);
            }
        }
    }

    counts
}

fn solve(tc: &TestCase) -> (usize, Vec<u32>) {
    let n = tc.n;

    // 1. Calculate shortest distances from start (1) and end (n)
    let d_s = dijkstra(n, &tc.adj, 1);
    let d_t = dijkstra(n, &tc.adj, n);

    let l_min = d_s[n];
    if l_min == u64::MAX {
        return (0, vec![]);
    }

    // 2. Count paths of length L and L+1
    let ways_s = compute_counts(n, &tc.adj, &d_s, 1);
    let ways_t = compute_counts(n, &tc.adj, &d_t, n);

    let total_l = ways_s[n].0;
    let total_l1 = ways_s[n].1;

    // If no path of length L+1 exists, we cannot achieve L+1 by blocking an L edge
    if total_l1 == Hash::zero() {
        return (0, vec![]);
    }

    let mut ans = Vec::new();

    // 3. Check each edge
    for &(u, v, w, id) in &tc.edges_flat {
        let u = u as usize;
        let v = v as usize;
        let w = w as u64;

        let mut on_sp = false;
        let mut direction = 0; // 0: none, 1: u->v, 2: v->u

        // Check if edge is on any shortest path
        if d_s[u] != u64::MAX && d_t[v] != u64::MAX && d_s[u] + w + d_t[v] == l_min {
            let paths = ways_s[u].0.mul(ways_t[v].0);
            if paths == total_l {
                on_sp = true;
                direction = 1;
            }
        } else if d_s[v] != u64::MAX && d_t[u] != u64::MAX && d_s[v] + w + d_t[u] == l_min {
            let paths = ways_s[v].0.mul(ways_t[u].0);
            if paths == total_l {
                on_sp = true;
                direction = 2;
            }
        }

        if on_sp {
            let mut paths_l1 = Hash::zero();

            // Calculate number of L+1 paths passing through this edge
            if direction == 1 {
                // u -> v
                // Contribution from: 
                // (paths to u length d[u]+1) * (paths from v length d[v])
                // + (paths to u length d[u]) * (paths from v length d[v]+1)
                let term1 = ways_s[u].1.mul(ways_t[v].0);
                let term2 = ways_s[u].0.mul(ways_t[v].1);
                paths_l1 = term1.add(term2);
            } else {
                // v -> u
                let term1 = ways_s[v].1.mul(ways_t[u].0);
                let term2 = ways_s[v].0.mul(ways_t[u].1);
                paths_l1 = term1.add(term2);
            }

            // If total L+1 paths != L+1 paths through this edge,
            // then there exists at least one L+1 path NOT using this edge.
            if paths_l1 != total_l1 {
                ans.push(id);
            }
        }
    }

    ans.sort_unstable();
    (ans.len(), ans)
}

fn main() {
