struct Solution {
    count: usize,
    indices: Vec<u32>,
}

// Returns (dist, ways1, ways2, visit_order)
fn dijkstra(n: usize, start: usize, adj: &Vec<Vec<Edge>>) -> (Vec<u64>, Vec<u64>, Vec<u64>, Vec<usize>) {
    let mut dist = vec![INF64; n];
    let mut ways1 = vec![0u64; n];
    let mut ways2 = vec![0u64; n];
    let mut visit_order = Vec::with_capacity(n);

    dist[start] = 0;
    ways1[start] = 1;
    ways2[start] = 1;

    let mut pq = BinaryHeap::new();
    pq.push(Reverse((0, start)));

    while let Some(Reverse((d, u))) = pq.pop() {
        if d > dist[u] { continue; }
        visit_order.push(u);

        for e in &adj[u] {
            let next_d = d + e.weight as u64;
            let v = e.to as usize;

            if next_d < dist[v] {
                dist[v] = next_d;
                ways1[v] = ways1[u];
                ways2[v] = ways2[u];
                pq.push(Reverse((next_d, v)));
            } else if next_d == dist[v] {
                ways1[v] = (ways1[v] + ways1[u]) % MOD1;
                ways2[v] = (ways2[v] + ways2[u]) % MOD2;
            }
        }
    }
    (dist, ways1, ways2, visit_order)
}

fn solve_case(n: usize, m: usize, edges: Vec<Vec<Edge>>, raw_edges: Vec<RawEdge>) -> Solution {
    let start_node = 0;
    let end_node = n - 1;

    let (dist_s, ways_s1, ways_s2, visit_s) = dijkstra(n, start_node, &edges);
    let shortest_path_len = dist_s[end_node];

    if shortest_path_len == INF64 {
        return Solution { count: 0, indices: vec![] };
    }

    let (dist_t, ways_t1, ways_t2, visit_t) = dijkstra(n, end_node, &edges);

    let total_ways1 = ways_s1[end_node];
    let total_ways2 = ways_s2[end_node];

    let mut critical_edges = Vec::new();
    // Using 1-based indexing for rank, max rank is m
    let mut edge_rank = vec![0; m + 1]; 

    for r in &raw_edges {
        let u = r.u as usize;
        let v = r.v as usize;
        let w = r.weight as u64;
        let id = r.id;

        // Check u -> v
        if dist_s[u] != INF64 && dist_t[v] != INF64 {
            if dist_s[u] + w + dist_t[v] == shortest_path_len {
                let w1 = (ways_s1[u] * ways_t1[v]) % MOD1;
                let w2 = (ways_s2[u] * ways_t2[v]) % MOD2;
                if w1 == total_ways1 && w2 == total_ways2 {
                    critical_edges.push((u, v, id, dist_s[u]));
                }
            }
        }
        // Check v -> u
        if dist_s[v] != INF64 && dist_t[u] != INF64 {
            if dist_s[v] + w + dist_t[u] == shortest_path_len {
                let w1 = (ways_s1[v] * ways_t1[u]) % MOD1;
                let w2 = (ways_s2[v] * ways_t2[u]) % MOD2;
                if w1 == total_ways1 && w2 == total_ways2 {
                    critical_edges.push((v, u, id, dist_s[v]));
                }
            }
        }
    }

    critical_edges.sort_unstable_by(|a, b| a.3.cmp(&b.3));
    let num_critical = critical_edges.len();
    if num_critical == 0 {
        return Solution { count: 0, indices: vec![] };
    }

    for (i, item) in critical_edges.iter().enumerate() {
        edge_rank[item.2 as usize] = i + 1;
    }

    // Compute P[u]: Min rank of critical edges on paths 1 -> u
    let mut p = vec![num_critical + 1; n]; 
    p[start_node] = 0;

    // visit_s is topologically sorted by distance from start
    for &u in &visit_s {
        if p[u] > num_critical && u != start_node { continue; }
        let pu = p[u];

        for e in &edges[u] {
            let v = e.to as usize;
            let w = e.weight as u64;
            // Only traverse SP DAG edges
            if dist_s[v] == dist_s[u] + w {
                let rank = edge_rank[e.id as usize];
                let val = if rank > 0 { rank } else { pu };
                if val < p[v] {
                    p[v] = val;
                }
            }
        }
    }

    // Compute S[u]: Max rank of critical edges on paths u -> n
    let mut s = vec![0; n];
    s[end_node] = num_critical + 1;

    // visit_t is topologically sorted by distance from end
    for &u in &visit_t { 
        if s[u] == 0 && u != end_node { continue; }
        let su = s[u];

        for e in &edges[u] {
            let v = e.to as usize; 
            let w = e.weight as u64;
            // Reverse logic: if dist_t[v] == dist_t[u] + w, then v -> u is an edge on shortest path towards n
            // We propagate from u (closer to n) to v (further from n)
            if dist_t[v] == dist_t[u] + w {
                let rank = edge_rank[e.id as usize];
                let val = if rank > 0 { rank } else { su };
                if val > s[v] {
