                            diff[end + 1] -= 1;
                        }
                    }
                }
            }
        };

        check(u, v);
        check(v, u);
    }

    let mut result_indices = Vec::new();
    let mut current = 0;
    for i in 1..=num_critical {
        current += diff[i];
        if current > 0 {
