    let mut edge_rank = vec![0; m + 1];

    for r in &edges {
        let u = r.u as usize;
        let v = r.v as usize;
        let w = r.w as u64;

        let mut on_sp = false;
        let mut u_to_v = false;

        if dist_s[u] != INF64 && dist_t[v] != INF64 && dist_s[u] + w + dist_t[v] == l {
            on_sp = true;
            u_to_v = true;
        } else if dist_s[v] != INF64 && dist_t[u] != INF64 && dist_s[v] + w + dist_t[u] == l {
            on_sp = true;
            u_to_v = false;
        }

