    }

    for (i, &(_, _, id, _)) in critical_edges.iter().enumerate() {
        edge_rank[id as usize] = (i + 1) as i32;
    }

    let mut p = vec![k as i32 + 1; n];
    p[0] = 0;

    for &u in &nodes_by_s {
        if dist_s[u] == INF64 { continue; }
        if p[u] > k as i32 && u != 0 { continue; }

        let pu = p[u];

        for e in &adj[u] {
            let v = e.to as usize;
            if dist_s[v] == dist_s[u] + e.weight as u64 {
                let rank = edge_rank[e.id as usize];
                let val = if rank > 0 { rank } else { pu };
                if val < p[v] {
                    p[v] = val;
                }
            }
        }
    }

    let mut s = vec![0; n];
    s[n - 1] = (k + 1) as i32;

    for &u in nodes_by_s.iter().rev() {
        if dist_t[u] == INF64 { continue; }
        if s[u] == 0 && u != n - 1 { continue; }

        let su = s[u];

        for e in &adj[u] { 
            let v = e.to as usize;
            if dist_t[v] == dist_t[u] + e.weight as u64 {
                let rank = edge_rank[e.id as usize];
                let val = if rank > 0 { rank } else { su };
                if val > s[v] { 
                    s[v] = val;
                }
            }
        }
    }

    let mut diff = vec![0i32; k + 2];

    for r in &edges {
        let u = r.u as usize;
        let v = r.v as usize;
        let w = r.w as u64;

        let mut check = |from: usize, to: usize| {
            if dist_s[from] != INF64 && dist_t[to] != INF64 && dist_s[from] + w + dist_t[to] == l + 1 {
                let l_idx = p[from];
                let r_idx = s[to];
                if l_idx < r_idx - 1 {
                    diff[(l_idx + 1) as usize] += 1;
                    diff[r_idx as usize] -= 1;
                }
            }
        };

        check(u, v);
        check(v, u);
    }

    let mut ans = Vec::new();
    let mut cur = 0;
    for i in 1..=k {
        cur += diff[i];
        if cur > 0 {
            ans.push(critical_edges[i-1].2);
        }
    }
    ans.sort_unstable();

    Solution { count: ans.len(), indices: ans }
}

