    r_arr[n - 1] = (k + 1) as i32;

    for &u in &order_t {
        if r_arr[u] == -1 { continue; }
        let ru = r_arr[u];
        for e in &adj[u] {
            let v = e.to as usize;
            if dist_t[v] == dist_t[u] + e.w as u64 {
                let r = edge_rank[e.id as usize];
                let val = if r > 0 { r } else { ru };
                if r_arr[v] == -1 {
                    r_arr[v] = val;
                } else {
                    r_arr[v] = max(r_arr[v], val);
                }
            }
        }
    }

    let mut diff = vec![0i32; k + 2];
    for r in &raw_edges {
        let u = r.u as usize;
        let v = r.v as usize;
        let w = r.w as u64;

        let mut check = |from: usize, to: usize| {
            if dist_s[from] != INF && dist_t[to] != INF && dist_s[from] + w + dist_t[to] == l_path + 1 {
                let lf = l_arr[from];
                let rt = r_arr[to];
                if lf != -1 && rt != -1 && lf < rt - 1 {
                    diff[(lf + 1) as usize] += 1;
                    diff[rt as usize] -= 1;
                }
            }
        };

        check(u, v);
        check(v, u);
    }

    let mut ans = Vec::new();
    let mut cur = 0;
    for i in 1..=k {
        cur += diff[i];
        if cur > 0 {
            ans.push(critical_edges[i - 1].2);
        }
    }
    ans.sort_unstable();

    Solution {
        count: ans.len(),
        indices: ans,
    }
}

