        let mut curr_r = obstacles[by_row[0] as usize].r;
        for i in 1..k {
            let next_r = obstacles[by_row[i] as usize].r;
            if next_r != curr_r {
                row_ranges[curr_r as usize] = (start as u32, i as u32);
                start = i;
                curr_r = next_r;
            }
        }
        row_ranges[curr_r as usize] = (start as u32, k as u32);
