            UP => {
                let (s, e) = col_ranges[c as usize];
                if s == e { return None; }
                let slice = &by_col[s as usize..e as usize];
                let idx = slice.partition_point(|&id| obstacles[id as usize].r < r);
                if idx > 0 { Some(slice[idx - 1]) } else { Some(slice[slice.len() - 1]) }
