                            let mut shift = diff;
                            for k in 0..log_k {
                                if (shift >> k) & 1 == 1 {
                                    curr = up[curr][k];
                                    if curr == usize::MAX { break; }
                                }
                            }
                            if curr == v {
                                d = diff as usize;
                            } else {
                                d = usize::MAX;
                            }
                        }
                    }
                }

                if d != usize::MAX {
                    if (d as u32) + 1 < ans {
                        ans = (d as u32) + 1;
                    }
                }
            }
        }

        if ans == u32::MAX { -1 } else { ans as i32 }
    }).collect();

    let stdout = io::stdout();
    let mut handle = stdout.lock();
    for r in results {
        writeln!(handle, "{}", r).ok();
    }
