use std::io::{self, Read, Write};
use rayon::prelude::*;

const INF: u32 = u32::MAX / 2;
const LOG_K: usize = 19; 

// Directions
const UP: usize = 0;
const RIGHT: usize = 1;
const DOWN: usize = 2;
const LEFT: usize = 3;

#[derive(Clone, Copy, Debug)]
struct Obstacle {
    r: u32,
    c: u32,
    kind: u8, // 0 for L, 1 for R
    id: u32,
}

#[derive(Clone, Copy)]
struct Query {
    r1: u32, c1: u32, r2: u32, c2: u32,
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_ascii_whitespace();

    let n: u32 = iter.next().unwrap().parse().unwrap();
    let m: u32 = iter.next().unwrap().parse().unwrap();
    let k: usize = iter.next().unwrap().parse().unwrap();

    let mut obstacles = Vec::with_capacity(k);
    for i in 0..k {
        let r: u32 = iter.next().unwrap().parse().unwrap();
        let c: u32 = iter.next().unwrap().parse().unwrap();
        let s_char = iter.next().unwrap().chars().next().unwrap();
        let kind = if s_char == 'L' { 0 } else { 1 };
        obstacles.push(Obstacle { r, c, kind, id: i as u32 });
    }

    let q_count: usize = iter.next().unwrap().parse().unwrap();
    let mut queries = Vec::with_capacity(q_count);
    for _ in 0..q_count {
        queries.push(Query {
            r1: iter.next().unwrap().parse().unwrap(),
            c1: iter.next().unwrap().parse().unwrap(),
            r2: iter.next().unwrap().parse().unwrap(),
            c2: iter.next().unwrap().parse().unwrap(),
        });
    }

    // Sorted views
    let mut by_row: Vec<usize> = (0..k).collect();
    by_row.par_sort_unstable_by(|&a, &b| {
        let oa = &obstacles[a];
        let ob = &obstacles[b];
        oa.r.cmp(&ob.r).then(oa.c.cmp(&ob.c))
    });

    let mut by_col: Vec<usize> = (0..k).collect();
    by_col.par_sort_unstable_by(|&a, &b| {
        let oa = &obstacles[a];
        let ob = &obstacles[b];
        oa.c.cmp(&ob.c).then(oa.r.cmp(&ob.r))
    });

    // Helper to find next obstacle
    let get_next_obs = |r: u32, c: u32, dir: usize| -> Option<usize> {
        match dir {
            UP => {
                let start = by_col.partition_point(|&i| obstacles[i].c < c);
                let end = by_col.partition_point(|&i| obstacles[i].c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i].r < r);
                if idx > 0 { Some(slice[idx - 1]) } else { Some(slice[slice.len() - 1]) }
            },
            DOWN => {
                let start = by_col.partition_point(|&i| obstacles[i].c < c);
                let end = by_col.partition_point(|&i| obstacles[i].c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i].r <= r);
                if idx < slice.len() { Some(slice[idx]) } else { Some(slice[0]) }
            },
            LEFT => {
                let start = by_row.partition_point(|&i| obstacles[i].r < r);
                let end = by_row.partition_point(|&i| obstacles[i].r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i].c < c);
                if idx > 0 { Some(slice[idx - 1]) } else { Some(slice[slice.len() - 1]) }
            },
            RIGHT => {
                let start = by_row.partition_point(|&i| obstacles[i].r < r);
                let end = by_row.partition_point(|&i| obstacles[i].r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i].c <= c);
                if idx < slice.len() { Some(slice[idx]) } else { Some(slice[0]) }
            },
            _ => None
        }
    };

    // Build Graph
    let num_nodes = 4 * k;
    let mut next_node = vec![usize::MAX; num_nodes];

    // Parallelize graph construction
    next_node.par_chunks_mut(4).enumerate().for_each(|(obs_idx, chunk)| {
        let u = &obstacles[obs_idx];
        for dir in 0..4 {
            if let Some(v_idx) = get_next_obs(u.r, u.c, dir) {
                let v = &obstacles[v_idx];
                // L: (dir + 3) % 4, R: (dir + 1) % 4
                let new_dir = if v.kind == 0 { (dir + 3) % 4 } else { (dir + 1) % 4 };
                chunk[dir] = v_idx * 4 + new_dir;
            }
        }
    });

    // Component Analysis
    let mut cycle_id = vec![usize::MAX; num_nodes];
    let mut pos_in_cycle = vec![0u32; num_nodes];
    let mut cycle_lens = Vec::new();
    let mut depth = vec![0u32; num_nodes];
    let mut root = vec![usize::MAX; num_nodes]; // root on cycle
    let mut visited = vec![0u8; num_nodes]; // 0: unvisited, 1: visiting, 2: visited

    // Iterative traversal to find cycles and components
    for i in 0..num_nodes {
        if visited[i] != 0 { continue; }

        let mut path = Vec::new();
        let mut curr = i;
        while curr != usize::MAX && visited[curr] == 0 {
            visited[curr] = 1;
            path.push(curr);
            curr = next_node[curr];
        }

        let mut cycle_start_idx = usize::MAX;
        if curr != usize::MAX && visited[curr] == 1 {
            // Found a cycle in the current recursion stack
            for (idx, &node) in path.iter().enumerate() {
                if node == curr {
                    cycle_start_idx = idx;
                    break;
                }
            }
        }

        if cycle_start_idx != usize::MAX {
            let cid = cycle_lens.len();
            let c_len = (path.len() - cycle_start_idx) as u32;
            cycle_lens.push(c_len);

            // Mark cycle nodes
            for (k, &u) in path.iter().enumerate().skip(cycle_start_idx) {
                cycle_id[u] = cid;
                pos_in_cycle[u] = (k - cycle_start_idx) as u32;
                depth[u] = 0;
                root[u] = u;
                visited[u] = 2;
            }

            // Backtrack for tree nodes
            for k in (0..cycle_start_idx).rev() {
                let u = path[k];
                let v = next_node[u];
                depth[u] = depth[v] + 1;
                root[u] = root[v];
                cycle_id[u] = cycle_id[v];
                visited[u] = 2;
            }
        } else {
            // Merged into an existing component or dead end
            let (t_cid, t_depth, t_root) = if curr != usize::MAX {
                (cycle_id[curr], depth[curr], root[curr])
            } else {
                (usize::MAX, 0, usize::MAX)
            };

            for &u in path.iter().rev() {
                if curr != usize::MAX {
                    cycle_id[u] = t_cid;
                    let v = next_node[u];
                    depth[u] = depth[v] + 1;
                    root[u] = root[v];
                } else {
                    // Dead end path
                }
                visited[u] = 2;
            }
        }
    }

    // Binary Lifting
    let mut jump = vec![vec![usize::MAX; LOG_K]; num_nodes];
    jump.par_iter_mut().enumerate().for_each(|(u, row)| { row[0] = next_node[u]; });
    for j in 1..LOG_K {
        let prev: Vec<usize> = (0..num_nodes).map(|u| jump[u][j-1]).collect();
        jump.par_iter_mut().enumerate().for_each(|(u, row)| {
            if prev[u] != usize::MAX { row[j] = prev[prev[u]]; }
        });
    }

    let kth_ancestor = |mut node: usize, k: u32, jump: &Vec<Vec<usize>>| -> usize {
        for j in 0..LOG_K {
            if (k >> j) & 1 == 1 {
                node = jump[node][j];
                if node == usize::MAX { return usize::MAX; }
            }
        }
        node
    };

    let mut results = vec![0i32; q_count];
