                     LEFT => if q.r1 != q.r2 { INF } else { if q.c2 <= q.c1 { q.c1 - q.c2 } else { q.c1 + m - q.c2 } },
                     RIGHT => if q.r1 != q.r2 { INF } else { if q.c2 >= q.c1 { q.c2 - q.c1 } else { m - q.c1 + q.c2 } },
                     _ => INF
                 };
