        oa.r.cmp(&ob.r).then(oa.c.cmp(&ob.c))
    });

    let mut by_col: Vec<u32> = (0..k as u32).collect();
    by_col.par_sort_unstable_by(|&a, &b| {
        let oa = &obstacles[a as usize];
        let ob = &obstacles[b as usize];
        oa.c.cmp(&ob.c).then(oa.r.cmp(&ob.r))
    });

    let mut row_ranges = vec![(0u32, 0u32); n as usize];
    if k > 0 {
        let mut start = 0;
        for i in 0..k {
            let idx = by_row[i] as usize;
            let r = obstacles[idx].r as usize;
            if i > 0 {
                let prev_idx = by_row[i-1] as usize;
                let prev_r = obstacles[prev_idx].r as usize;
                if r != prev_r {
                    row_ranges[prev_r] = (start as u32, i as u32);
                    start = i;
                }
            }
        }
        let last_idx = by_row[k-1] as usize;
        row_ranges[obstacles[last_idx].r as usize] = (start as u32, k as u32);
    }

    let mut col_ranges = vec![(0u32, 0u32); m as usize];
    if k > 0 {
        let mut start = 0;
        for i in 0..k {
            let idx = by_col[i] as usize;
            let c = obstacles[idx].c as usize;
            if i > 0 {
                let prev_idx = by_col[i-1] as usize;
                let prev_c = obstacles[prev_idx].c as usize;
                if c != prev_c {
                    col_ranges[prev_c] = (start as u32, i as u32);
                    start = i;
                }
            }
        }
        let last_idx = by_col[k-1] as usize;
        col_ranges[obstacles[last_idx].c as usize] = (start as u32, k as u32);
    }

    let find_next = |r: u32, c: u32, dir: usize| -> Option<u32> {
        match dir {
            UP => {
                let (start, end) = col_ranges[c as usize];
                if start == end { return None; }
                let slice = &by_col[start as usize..end as usize];
                let idx = slice.partition_point(|&id| obstacles[id as usize].r < r);
                if idx > 0 {
                    Some(slice[idx - 1])
                } else {
                    Some(slice[slice.len() - 1])
                }
            },
            DOWN => {
                let (start, end) = col_ranges[c as usize];
                if start == end { return None; }
                let slice = &by_col[start as usize..end as usize];
                let idx = slice.partition_point(|&id| obstacles[id as usize].r <= r);
                if idx < slice.len() {
                    Some(slice[idx])
                } else {
                    Some(slice[0])
                }
            },
            LEFT => {
                let (start, end) = row_ranges[r as usize];
                if start == end { return None; }
                let slice = &by_row[start as usize..end as usize];
                let idx = slice.partition_point(|&id| obstacles[id as usize].c < c);
                if idx > 0 {
