        }
    };

    let num_nodes = 4 * k;
    let next_node: Vec<u32> = (0..num_nodes).into_par_iter().map(|u| {
        let oid = (u / 4) as u32;
        let dir = (u % 4) as usize;
        let o = &obstacles[oid as usize];

