            let next_o = &obstacles[next_oid as usize];
            let turn = if next_o.kind == 0 { 3 } else { 1 };
            let new_dir = (dir + turn) % 4;
            (next_oid * 4 + new_dir as u32)
        } else {
            u32::MAX
        }
    }).collect();

    let mut state = vec![0u8; num_nodes]; 
    let mut depth = vec![0u32; num_nodes];
    let mut root_cycle = vec![u32::MAX; num_nodes]; 
    let mut comp_id = vec![u32::MAX; num_nodes];
    let mut pos_cycle = vec![0u32; num_nodes];
    let mut cycle_lens = Vec::new();

    for i in 0..num_nodes {
