        let mut path = Vec::new();
        let mut curr = i as u32;
        while curr != u32::MAX && state[curr as usize] == 0 {
            state[curr as usize] = 1;
            path.push(curr);
            curr = next_node[curr as usize];
        }

        let mut cycle_start = usize::MAX;
        if curr != u32::MAX && state[curr as usize] == 1 {
            for (idx, &node) in path.iter().enumerate() {
                if node == curr {
                    cycle_start = idx;
                    break;
                }
            }
        }

        if cycle_start != usize::MAX {
            let cid = cycle_lens.len() as u32;
            let len = (path.len() - cycle_start) as u32;
            cycle_lens.push(len);

            for (k, &u) in path.iter().enumerate().skip(cycle_start) {
                let u = u as usize;
                state[u] = 2;
                comp_id[u] = cid;
                depth[u] = 0;
                root_cycle[u] = u as u32;
                pos_cycle[u] = (k - cycle_start) as u32;
            }

            for k in (0..cycle_start).rev() {
                let u = path[k] as usize;
                let v = next_node[u] as usize;
                state[u] = 2;
                comp_id[u] = cid;
                depth[u] = depth[v] + 1;
                root_cycle[u] = root_cycle[v];
            }
        } else {
            let (t_cid, t_root, t_depth) = if curr != u32::MAX {
                (comp_id[curr as usize], root_cycle[curr as usize], depth[curr as usize])
            } else {
                (u32::MAX, u32::MAX, 0)
            };

            for &u in path.iter().rev() {
                let u = u as usize;
                state[u] = 2;
                if t_cid != u32::MAX {
                    comp_id[u] = t_cid;
                    let v = next_node[u] as usize;
                    depth[u] = depth[v] + 1;
                    root_cycle[u] = root_cycle[v];
                } else {
                    comp_id[u] = u32::MAX;
                }
            }
        }
    }

    let mut up = vec![vec![u32::MAX; LOG_K]; num_nodes];
    up.par_iter_mut().enumerate().for_each(|(i, row)| {
        row[0] = next_node[i];
    });
    for j in 1..LOG_K {
        let prev_col: Vec<u32> = (0..num_nodes).into_par_iter().map(|i| up[i][j-1]).collect();
        up.par_iter_mut().enumerate().for_each(|(i, row)| {
            if prev_col[i] != u32::MAX {
                row[j] = prev_col[prev_col[i] as usize];
