                DOWN => if q.c1 == q.c2 { (if q.r2 >= q.r1 { q.r2 - q.r1 } else { n - q.r1 + q.r2 }, true) } else { (INF, false) },
                LEFT => if q.r1 == q.r2 { (if q.c2 <= q.c1 { q.c1 - q.c2 } else { q.c1 + m - q.c2 }, true) } else { (INF, false) },
                RIGHT => if q.r1 == q.r2 { (if q.c2 >= q.c1 { q.c2 - q.c1 } else { m - q.c1 + q.c2 }, true) } else { (INF, false) },
