                    let o = &obstacles[oid as usize];
                    let dist_o = match dir {
                        UP => if o.r < q.r1 { q.r1 - o.r } else { q.r1 + n - o.r },
                        DOWN => if o.r > q.r1 { o.r - q.r1 } else { n - q.r1 + o.r },
                        LEFT => if o.c < q.c1 { q.c1 - o.c } else { q.c1 + m - o.c },
                        RIGHT => if o.c > q.c1 { o.c - q.c1 } else { m - q.c1 + o.c },
                        _ => 0
                    };
                    if dist_g <= dist_o {
                        ans = 0;
                        break;
                    }
                } else {
                    ans = 0;
                    break;
                }
            }
        }

        if ans == 0 {
            *res = 0; return;
        }

        if k == 0 {
            *res = -1; return;
        }

        let mut starts = Vec::with_capacity(4);
        for dir in 0..4 {
            if let Some(oid) = find_next(q.r1, q.c1, dir) {
                let o = &obstacles[oid as usize];
                let turn = if o.kind == 0 { 3 } else { 1 };
                let new_dir = (dir + turn) % 4;
                starts.push(oid * 4 + new_dir as u32);
            }
        }

        let mut targets = Vec::with_capacity(4);
        let back_dirs = [DOWN, UP, RIGHT, LEFT];
        let fwd_dirs = [UP, DOWN, LEFT, RIGHT];

        for i in 0..4 {
            let look_dir = back_dirs[i];
            let arr_dir = fwd_dirs[i];
            if let Some(oid) = find_next(q.r2, q.c2, look_dir) {
                targets.push(oid * 4 + arr_dir as u32);
            }
        }

        for &s in &starts {
            for &t in &targets {
                let s = s as usize;
                let t = t as usize;
                if comp_id[s] == u32::MAX || comp_id[s] != comp_id[t] { continue; }

                let mut d = INF;
                if depth[t] == 0 {
                    let rs = root_cycle[s] as usize;
