                            }
                        }
                        if curr == t as u32 {
                            d = diff;
                        }
                    }
                }

                if d != INF {
                    if d + 1 < ans { ans = d + 1; }
                }
            }
        }

        *res = if ans >= INF { -1 } else { ans as i32 };
    });

    let mut out = io::BufWriter::new(io::stdout());
