                let end = cols.partition_point(|&i| obs[i as usize].c <= c);
                let slice = &cols[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obs[i as usize].r < r);
                if idx > 0 { Some(slice[idx - 1] as usize) } else { Some(slice[slice.len() - 1] as usize) }
            },
            DOWN => {
                let start = cols.partition_point(|&i| obs[i as usize].c < c);
                let end = cols.partition_point(|&i| obs[i as usize].c <= c);
                let slice = &cols[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obs[i as usize].r <= r);
                if idx < slice.len() { Some(slice[idx] as usize) } else { Some(slice[0] as usize) }
            },
            LEFT => {
                let start = rows.partition_point(|&i| obs[i as usize].r < r);
                let end = rows.partition_point(|&i| obs[i as usize].r <= r);
                let slice = &rows[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obs[i as usize].c < c);
                if idx > 0 { Some(slice[idx - 1] as usize) } else { Some(slice[slice.len() - 1] as usize) }
            },
