            let len = (path.len() - cycle_start_index) as u32;
            cycle_lens.push(len);

            // Process cycle nodes
            for (k, &u) in path.iter().enumerate().skip(cycle_start_index) {
                let u = u as usize;
                state[u] = 2;
                comp[u] = cid;
                depth[u] = 0;
                root_cycle[u] = u as u32;
                pos_cycle[u] = (k - cycle_start_index) as u32;
            }

