    let m: u32 = iter.next().unwrap().parse().unwrap();
    let k: usize = iter.next().unwrap().parse().unwrap();

    let mut blockers = Vec::with_capacity(k);
    let mut by_row: Vec<BInfo> = Vec::with_capacity(k);

