        let r: u32 = iter.next().unwrap().parse().unwrap();
        let c: u32 = iter.next().unwrap().parse().unwrap();
        let s_str = iter.next().unwrap();
        let s = s_str.chars().next().unwrap();
        let b = BInfo { r, c, id: i as u32, kind: s };
        by_row.push(b);
        blockers.push(Blocker { r, c, kind: s });
    }

    let mut by_col = Vec::with_capacity(k);
    for b in &by_row {
        by_col.push(BInfo { r: b.r, c: b.c, id: b.id, kind: b.kind });
    }

    by_row.par_sort_unstable_by(|a, b| a.r.cmp(&b.r).then(a.c.cmp(&b.c)));
    by_col.par_sort_unstable_by(|a, b| a.c.cmp(&b.c).then(a.r.cmp(&b.r)));

    let num_nodes = 4 * k;
    let next_node_vec: Vec<usize> = (0..num_nodes).into_par_iter().map(|u| {
        let b_id = u / 4;
