                let v = next_node_vec[u];
                depth[u] = depth[v] + 1;
                root_on_cycle[u] = root_on_cycle[v];
                cycle_id[u] = cycle_id[v];
                state[u] = 2;
            }
        } else {
            for k in (0..path.len()).rev() {
                let u = path[k];
                let v = next_node_vec[u];
                if v != usize::MAX {
                    depth[u] = depth[v] + 1;
                    root_on_cycle[u] = root_on_cycle[v];
                    cycle_id[u] = cycle_id[v];
                }
                state[u] = 2;
            }
        }
    }

