use std::io::{self, Read, Write};
use rayon::prelude::*;

const UP: usize = 0;
const RIGHT: usize = 1;
const DOWN: usize = 2;
const LEFT: usize = 3;
const INF: u32 = 1_000_000_000;

#[derive(Clone, Copy, Debug)]
struct Obstacle {
    r: u32,
    c: u32,
    kind: u8, // 0: L, 1: R
    id: u32,
}

#[derive(Clone, Copy)]
struct Query {
    r1: u32, c1: u32, r2: u32, c2: u32,
    id: u32,
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_ascii_whitespace();

    let n: u32 = iter.next().unwrap().parse().unwrap();
    let m: u32 = iter.next().unwrap().parse().unwrap();
    let k: usize = iter.next().unwrap().parse().unwrap();

    let mut obstacles = Vec::with_capacity(k);
    for i in 0..k {
        let r: u32 = iter.next().unwrap().parse().unwrap();
        let c: u32 = iter.next().unwrap().parse().unwrap();
        let s = iter.next().unwrap();
        let kind = if s == "L" { 0 } else { 1 };
        obstacles.push(Obstacle { r: r - 1, c: c - 1, kind, id: i as u32 });
    }

    let mut by_row = obstacles.clone();
    by_row.par_sort_unstable_by(|a, b| a.r.cmp(&b.r).then(a.c.cmp(&b.c)));

    let mut by_col = obstacles.clone();
    by_col.par_sort_unstable_by(|a, b| a.c.cmp(&b.c).then(a.r.cmp(&b.r)));

    // Precompute the functional graph where each node is (obstacle_id * 4 + outgoing_direction)
    let num_nodes = 4 * k;
    let next_node: Vec<usize> = (0..num_nodes).into_par_iter().map(|u| {
        let oid = (u / 4) as usize;
        let dir = u % 4;
        let r = obstacles[oid].r;
        let c = obstacles[oid].c;

        let next_o = match dir {
            UP => {
                let start = by_col.partition_point(|o| o.c < c);
                let end = by_col.partition_point(|o| o.c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|o| o.r < r);
                    if idx > 0 { Some(slice[idx - 1]) } else { Some(slice[slice.len() - 1]) }
                }
            },
            DOWN => {
                let start = by_col.partition_point(|o| o.c < c);
                let end = by_col.partition_point(|o| o.c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|o| o.r <= r);
                    if idx < slice.len() { Some(slice[idx]) } else { Some(slice[0]) }
                }
            },
            LEFT => {
                let start = by_row.partition_point(|o| o.r < r);
                let end = by_row.partition_point(|o| o.r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|o| o.c < c);
                    if idx > 0 { Some(slice[idx - 1]) } else { Some(slice[slice.len() - 1]) }
                }
            },
            RIGHT => {
                let start = by_row.partition_point(|o| o.r < r);
                let end = by_row.partition_point(|o| o.r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|o| o.c <= c);
                    if idx < slice.len() { Some(slice[idx]) } else { Some(slice[0]) }
                }
            },
            _ => None
        };

        if let Some(no) = next_o {
            let nd = if no.kind == 0 { (dir + 3) % 4 } else { (dir + 1) % 4 };
            (no.id as usize) * 4 + nd
        } else {
            usize::MAX
        }
    }).collect();

    // Functional Graph Analysis: Find components, cycles, and depths
    let mut state = vec![0u8; num_nodes];
    let mut depth = vec![0u32; num_nodes];
    let mut comp = vec![usize::MAX; num_nodes];
    let mut pos = vec![0u32; num_nodes];
    let mut root = vec![usize::MAX; num_nodes];
    let mut cycle_lens = Vec::new();

    for i in 0..num_nodes {
        if state[i] != 0 { continue; }

        let mut path = Vec::new();
        let mut curr = i;
        while curr != usize::MAX && state[curr] == 0 {
            state[curr] = 1;
            path.push(curr);
            curr = next_node[curr];
        }

        let mut on_cycle = false;
        let mut cycle_start_idx = 0;

        if curr != usize::MAX && state[curr] == 1 {
            on_cycle = true;
            while cycle_start_idx < path.len() && path[cycle_start_idx] != curr {
                cycle_start_idx += 1;
            }
        }

        if on_cycle {
            let cid = cycle_lens.len();
            let c_len = (path.len() - cycle_start_idx) as u32;
            cycle_lens.push(c_len);

            for (idx, &u) in path.iter().enumerate().skip(cycle_start_idx) {
                state[u] = 2;
                comp[u] = cid;
                depth[u] = 0;
                pos[u] = (idx - cycle_start_idx) as u32;
                root[u] = u;
