            for idx in (0..cycle_start_idx).rev() {
                let u = path[idx];
                let v = next_node[u];
                state[u] = 2;
                comp[u] = comp[v];
                depth[u] = depth[v] + 1;
                root[u] = root[v];
            }
        } else {
            let (target_comp, _, target_root) = if curr != usize::MAX {
                (comp[curr], depth[curr], root[curr])
            } else {
                (usize::MAX, 0, usize::MAX)
            };

            for &u in path.iter().rev() {
                state[u] = 2;
                comp[u] = target_comp;
                if target_comp != usize::MAX {
                    let v = next_node[u];
                    depth[u] = depth[v] + 1;
                    root[u] = root[v];
                }
            }
        }
    }

    // Binary Lifting for Tree Part
    let log_k = 19;
    let mut jump = vec![vec![usize::MAX; log_k]; num_nodes];

    jump.par_iter_mut().enumerate().for_each(|(i, row)| {
        row[0] = next_node[i];
    });

    for j in 1..log_k {
        let prev: Vec<usize> = (0..num_nodes).into_par_iter().map(|i| jump[i][j-1]).collect();
        jump.par_iter_mut().enumerate().for_each(|(i, row)| {
            if prev[i] != usize::MAX {
                row[j] = prev[prev[i]];
            }
        });
    }

    let q_count: usize = iter.next().unwrap().parse().unwrap();
    let mut queries = Vec::with_capacity(q_count);
    for i in 0..q_count {
        queries.push(Query {
            r1: iter.next().unwrap().parse().unwrap(),
            c1: iter.next().unwrap().parse().unwrap(),
            r2: iter.next().unwrap().parse().unwrap(),
            c2: iter.next().unwrap().parse().unwrap(),
            id: i as u32,
        });
    }

    let mut results = vec![0; q_count];
    results.par_iter_mut().zip(queries.par_iter()).for_each(|(res, q)| {
        let r1 = q.r1 - 1;
