const INF: u32 = 1_000_000_000;
const LOG_K: usize = 19; 

// Directions
const UP: usize = 0;
const RIGHT: usize = 1;
const DOWN: usize = 2;
const LEFT: usize = 3;

#[derive(Clone, Copy, Debug)]
struct Obstacle {
    r: u32,
    c: u32,
    kind: u8, // 0 for L, 1 for R
    id: u32,
}

#[derive(Clone, Copy)]
struct Query {
    r1: u32, c1: u32, r2: u32, c2: u32,
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_ascii_whitespace();

    let n: u32 = iter.next().unwrap().parse().unwrap();
    let m: u32 = iter.next().unwrap().parse().unwrap();
    let k: usize = iter.next().unwrap().parse().unwrap();

    let mut obstacles = Vec::with_capacity(k);
    for i in 0..k {
        let r: u32 = iter.next().unwrap().parse().unwrap();
        let c: u32 = iter.next().unwrap().parse().unwrap();
        let s_char = iter.next().unwrap().chars().next().unwrap();
        let kind = if s_char == 'L' { 0 } else { 1 };
        // Store 0-based coordinates
        obstacles.push(Obstacle { r: r - 1, c: c - 1, kind, id: i as u32 });
    }

    // Sorted indices for efficient searching
    let mut by_row: Vec<u32> = (0..k as u32).collect();
    by_row.par_sort_unstable_by(|&a, &b| {
        let oa = &obstacles[a as usize];
        let ob = &obstacles[b as usize];
        oa.r.cmp(&ob.r).then(oa.c.cmp(&ob.c))
    });

    let mut by_col: Vec<u32> = (0..k as u32).collect();
    by_col.par_sort_unstable_by(|&a, &b| {
        let oa = &obstacles[a as usize];
        let ob = &obstacles[b as usize];
        oa.c.cmp(&ob.c).then(oa.r.cmp(&ob.r))
    });

    // Helper to find next obstacle index in a given direction from (r, c)
    let get_next_obs_idx = |r: u32, c: u32, dir: usize| -> Option<usize> {
        match dir {
            UP => {
                let start = by_col.partition_point(|&i| obstacles[i as usize].c < c);
                let end = by_col.partition_point(|&i| obstacles[i as usize].c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i as usize].r < r);
                if idx > 0 { Some(slice[idx - 1] as usize) } else { Some(slice[slice.len() - 1] as usize) }
            },
            DOWN => {
                let start = by_col.partition_point(|&i| obstacles[i as usize].c < c);
                let end = by_col.partition_point(|&i| obstacles[i as usize].c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i as usize].r <= r);
                if idx < slice.len() { Some(slice[idx] as usize) } else { Some(slice[0] as usize) }
            },
            LEFT => {
                let start = by_row.partition_point(|&i| obstacles[i as usize].r < r);
                let end = by_row.partition_point(|&i| obstacles[i as usize].r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i as usize].c < c);
                if idx > 0 { Some(slice[idx - 1] as usize) } else { Some(slice[slice.len() - 1] as usize) }
            },
            RIGHT => {
                let start = by_row.partition_point(|&i| obstacles[i as usize].r < r);
                let end = by_row.partition_point(|&i| obstacles[i as usize].r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|&i| obstacles[i as usize].c <= c);
                if idx < slice.len() { Some(slice[idx] as usize) } else { Some(slice[0] as usize) }
            },
            _ => None
        }
    };

    // Build Functional Graph
    let num_nodes = 4 * k;
    let next_node: Vec<u32> = (0..num_nodes).into_par_iter().map(|u| {
        let oid = (u / 4) as usize;
        let dir = (u % 4) as usize;
        let o = &obstacles[oid];

        if let Some(n_idx) = get_next_obs_idx(o.r, o.c, dir) {
            let no = &obstacles[n_idx];
            let turn = if no.kind == 0 { 3 } else { 1 };
            let new_dir = (dir + turn) % 4;
            (n_idx * 4 + new_dir) as u32
        } else {
