            cycle_lens.push(len);

            for (k, &u) in path.iter().enumerate().skip(cycle_start_index) {
                let u = u as usize;
                state[u] = 2;
                comp[u] = cid;
                depth[u] = 0;
                root_cycle[u] = u as u32;
                pos_cycle[u] = (k - cycle_start_index) as u32;
            }

            for k in (0..cycle_start_index).rev() {
                let u = path[k] as usize;
                let v = next_node[u] as usize;
                state[u] = 2;
                comp[u] = cid;
                depth[u] = depth[v] + 1;
                root_cycle[u] = root_cycle[v];
            }
        } else {
            let (t_comp, t_root, t_depth) = if curr != u32::MAX {
                (comp[curr as usize], root_cycle[curr as usize], depth[curr as usize])
            } else {
                (u32::MAX, u32::MAX, 0)
            };

            for &u in path.iter().rev() {
                let u = u as usize;
                state[u] = 2;
                if t_comp != u32::MAX {
                    comp[u] = t_comp;
                    let v = next_node[u] as usize;
                    depth[u] = depth[v] + 1;
                    root_cycle[u] = t_root;
                } else {
