use std::io::{self, Read, Write};
use rayon::prelude::*;

const INF: u32 = u32::MAX / 2;
const UP: usize = 0;
const RIGHT: usize = 1;
const DOWN: usize = 2;
const LEFT: usize = 3;
const LOG_K: usize = 19;

#[derive(Clone, Copy, Debug)]
struct Obstacle {
    r: u32,
    c: u32,
    kind: u8, // 0: L, 1: R
    id: u32,
}

#[derive(Clone, Copy)]
struct Query {
    r1: u32, c1: u32, r2: u32, c2: u32,
    idx: usize,
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_ascii_whitespace();

    let n: u32 = iter.next().unwrap().parse().unwrap();
    let m: u32 = iter.next().unwrap().parse().unwrap();
    let k: usize = iter.next().unwrap().parse().unwrap();

    let mut obstacles = Vec::with_capacity(k);
    for i in 0..k {
        let r: u32 = iter.next().unwrap().parse().unwrap();
        let c: u32 = iter.next().unwrap().parse().unwrap();
        let s_str = iter.next().unwrap();
        let kind = if s_str.starts_with('L') { 0 } else { 1 };
        obstacles.push(Obstacle { r, c, kind, id: i as u32 });
    }

    // Sort by row then col
    let mut by_row = obstacles.clone();
    by_row.par_sort_unstable_by(|a, b| a.r.cmp(&b.r).then(a.c.cmp(&b.c)));

    // Sort by col then row
    let mut by_col = obstacles.clone();
    by_col.par_sort_unstable_by(|a, b| a.c.cmp(&b.c).then(a.r.cmp(&b.r)));

    // Original order lookup
    let mut obs_by_id = vec![Obstacle { r: 0, c: 0, kind: 0, id: 0 }; k];
    for o in &obstacles {
        obs_by_id[o.id as usize] = *o;
    }

    // Helper to find next obstacle
    let find_next_obs = |r: u32, c: u32, dir: usize| -> Option<Obstacle> {
        match dir {
            UP => {
                let start = by_col.partition_point(|o| o.c < c);
                let end = by_col.partition_point(|o| o.c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|o| o.r < r);
                if idx > 0 { Some(slice[idx - 1]) } else { Some(slice[slice.len() - 1]) }
            },
            DOWN => {
                let start = by_col.partition_point(|o| o.c < c);
                let end = by_col.partition_point(|o| o.c <= c);
                let slice = &by_col[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|o| o.r <= r);
                if idx < slice.len() { Some(slice[idx]) } else { Some(slice[0]) }
            },
            LEFT => {
                let start = by_row.partition_point(|o| o.r < r);
                let end = by_row.partition_point(|o| o.r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|o| o.c < c);
                if idx > 0 { Some(slice[idx - 1]) } else { Some(slice[slice.len() - 1]) }
            },
            RIGHT => {
                let start = by_row.partition_point(|o| o.r < r);
                let end = by_row.partition_point(|o| o.r <= r);
                let slice = &by_row[start..end];
                if slice.is_empty() { return None; }
                let idx = slice.partition_point(|o| o.c <= c);
                if idx < slice.len() { Some(slice[idx]) } else { Some(slice[0]) }
            },
            _ => None
        }
    };

    let num_nodes = 4 * k;
    let next_node: Vec<usize> = (0..num_nodes).into_par_iter().map(|u| {
        let oid = u / 4;
        let dir = u % 4;
        let o = &obs_by_id[oid];

        if let Some(next_o) = find_next_obs(o.r, o.c, dir) {
            let turn = if next_o.kind == 0 { 3 } else { 1 }; // L=+3, R=+1
            let new_dir = (dir + turn) % 4;
            (next_o.id as usize) * 4 + new_dir
        } else {
            usize::MAX
        }
    }).collect();

    // Functional Graph Processing
    let mut visited = vec![0u8; num_nodes]; // 0: new, 1: visiting, 2: visited
    let mut comp_id = vec![usize::MAX; num_nodes];
    let mut depth = vec![0u32; num_nodes];
    let mut root_on_cycle = vec![usize::MAX; num_nodes];
    let mut pos_in_cycle = vec![0u32; num_nodes];
    let mut cycle_lens = Vec::new();

    // Non-recursive DFS / traversal
    for i in 0..num_nodes {
        if visited[i] != 0 { continue; }

        let mut path = Vec::new();
        let mut curr = i;
        while curr != usize::MAX && visited[curr] == 0 {
            visited[curr] = 1;
            path.push(curr);
            curr = next_node[curr];
        }

        let mut cycle_start_idx = usize::MAX;
        if curr != usize::MAX && visited[curr] == 1 {
            // Found cycle in current path
            for (idx, &node) in path.iter().enumerate() {
                if node == curr {
                    cycle_start_idx = idx;
                    break;
                }
            }
        }

        if cycle_start_idx != usize::MAX {
            let cid = cycle_lens.len();
            let c_len = (path.len() - cycle_start_idx) as u32;
            cycle_lens.push(c_len);

            // Mark cycle nodes
            for (k, &u) in path.iter().enumerate().skip(cycle_start_idx) {
                visited[u] = 2;
                comp_id[u] = cid;
                depth[u] = 0;
                root_on_cycle[u] = u;
                pos_in_cycle[u] = (k - cycle_start_idx) as u32;
            }

            // Mark tree nodes leading to cycle
            for k in (0..cycle_start_idx).rev() {
                let u = path[k];
                let v = next_node[u];
                visited[u] = 2;
                comp_id[u] = cid;
                depth[u] = depth[v] + 1;
                root_on_cycle[u] = root_on_cycle[v];
            }
        } else {
            // Leads to an already processed component or sink
            let (target_comp, _, target_root) = if curr != usize::MAX {
                (comp_id[curr], depth[curr], root_on_cycle[curr])
            } else {
                (usize::MAX, 0, usize::MAX)
            };

            for &u in path.iter().rev() {
                visited[u] = 2;
                if target_comp != usize::MAX {
                    comp_id[u] = target_comp;
                    let v = next_node[u]; // Should be valid
                    depth[u] = depth[v] + 1;
                    root_on_cycle[u] = root_on_cycle[v];
                }
            }
        }
    }

    // Binary Lifting
    let mut up = vec![vec![usize::MAX; LOG_K]; num_nodes];
    up.par_iter_mut().enumerate().for_each(|(i, row)| {
        row[0] = next_node[i];
    });
    for j in 1..LOG_K {
        let prev_col: Vec<usize> = (0..num_nodes).map(|i| up[i][j-1]).collect();
        up.par_iter_mut().enumerate().for_each(|(i, row)| {
            if prev_col[i] != usize::MAX {
                row[j] = prev_col[prev_col[i]];
            }
        });
    }

    // Helper: is u in sorted vec
    let is_obstacle = |r: u32, c: u32, row_vec: &Vec<Obstacle>| -> Option<usize> {
        let start = row_vec.partition_point(|o| o.r < r);
        let end = row_vec.partition_point(|o| o.r <= r);
        let slice = &row_vec[start..end];
        if let Ok(idx) = slice.binary_search_by_key(&c, |o| o.c) {
             Some(slice[idx].id as usize)
        } else {
             None
        }
    };

    let q_count: usize = iter.next().unwrap().parse().unwrap();
    let mut queries = Vec::with_capacity(q_count);
    for i in 0..q_count {
        queries.push(Query {
            r1: iter.next().unwrap().parse().unwrap(),
            c1: iter.next().unwrap().parse().unwrap(),
            r2: iter.next().unwrap().parse().unwrap(),
            c2: iter.next().unwrap().parse().unwrap(),
            idx: i,
        });
    }

    let mut results = vec![0; q_count];
    results.par_iter_mut().zip(queries.par_iter()).for_each(|(res, q)| {
        if q.r1 == q.r2 && q.c1 == q.c2 {
            *res = 0; return;
        }

        let mut ans = INF;

        // 0-turn Check
        let check_0 = |dir: usize| -> bool {
            // Distance to goal
            let dist_g = match dir {
                UP => if q.c1 == q.c2 { if q.r2 <= q.r1 { q.r1 - q.r2 } else { q.r1 + n - q.r2 } } else { INF },
                DOWN => if q.c1 == q.c2 { if q.r2 >= q.r1 { q.r2 - q.r1 } else { n - q.r1 + q.r2 } } else { INF },
                LEFT => if q.r1 == q.r2 { if q.c2 <= q.c1 { q.c1 - q.c2 } else { q.c1 + m - q.c2 } } else { INF },
                RIGHT => if q.r1 == q.r2 { if q.c2 >= q.c1 { q.c2 - q.c1 } else { m - q.c1 + q.c2 } } else { INF },
                _ => INF
            };
            if dist_g == INF { return false; }

            // Distance to first obstacle
            if let Some(o) = find_next_obs(q.r1, q.c1, dir) {
                let dist_o = match dir {
                    UP => if o.r < q.r1 { q.r1 - o.r } else { q.r1 + n - o.r },
                    DOWN => if o.r > q.r1 { o.r - q.r1 } else { n - q.r1 + o.r },
                    LEFT => if o.c < q.c1 { q.c1 - o.c } else { q.c1 + m - o.c },
                    RIGHT => if o.c > q.c1 { o.c - q.c1 } else { m - q.c1 + o.c },
                    _ => INF
                };
                if dist_g <= dist_o { return true; }
            } else {
                return true;
            }
            false
        };

        if check_0(UP) || check_0(DOWN) || check_0(LEFT) || check_0(RIGHT) {
            *res = 0; return;
        }

        if k == 0 {
            *res = -1; return;
        }

        // Identify Start States
        let start_obs_id = is_obstacle(q.r1, q.c1, &by_row);
        let mut starts = Vec::with_capacity(4);

        if let Some(sid) = start_obs_id {
            // Start is an obstacle, cost 0
            for dir in 0..4 {
                starts.push((sid * 4 + dir, 0));
            }
        } else {
            // Start is empty, cost 1 to hit first obs
            for dir in 0..4 {
