        let mut targets = Vec::with_capacity(4);

        let mut add_target = |look_dir: usize, arr_dir: usize| {
             if let Some(o) = find_next_obs(q.r2, q.c2, look_dir) {
                 targets.push((o.id as usize) * 4 + arr_dir);
             }
