        add_target(UP, DOWN); 
        add_target(DOWN, UP); 
        add_target(LEFT, RIGHT); 
        add_target(RIGHT, LEFT); 

        for (s, cost_s) in starts {
            for &t in &targets {
                if comp_id[s] == usize::MAX || comp_id[s] != comp_id[t] { continue; }

                let mut d = INF;
