                    d = depth[s] + dist_cyc;
                } else {
                    if root_on_cycle[s] == root_on_cycle[t] && depth[s] >= depth[t] {
                        let diff = depth[s] - depth[t];
                        let mut curr = s;
                        for b in 0..LOG_K {
                            if (diff >> b) & 1 == 1 {
                                curr = up[curr][b];
                            }
                        }
                        if curr == t {
                            d = diff;
                        }
                    }
                }

                if d != INF {
                    if cost_s + d < ans { ans = cost_s + d; }
                }
            }
        }

