use rayon::prelude::*;

const INF: u32 = u32::MAX / 2;
const UP: usize = 0;
const RIGHT: usize = 1;
const DOWN: usize = 2;
const LEFT: usize = 3;

#[derive(Clone, Copy)]
struct Blocker {
    r: u32,
    c: u32,
    kind: char,
}

#[derive(Clone)]
struct Query {
    r1: u32, c1: u32, r2: u32, c2: u32,
}

struct BInfo {
    r: u32,
    c: u32,
    id: u32,
    kind: char,
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_ascii_whitespace();

    let n: u32 = iter.next().unwrap().parse().unwrap();
    let m: u32 = iter.next().unwrap().parse().unwrap();
    let k: usize = iter.next().unwrap().parse().unwrap();

    let mut blockers = Vec::with_capacity(k);
    let mut by_row: Vec<BInfo> = Vec::with_capacity(k);

    for i in 0..k {
        let r: u32 = iter.next().unwrap().parse().unwrap();
        let c: u32 = iter.next().unwrap().parse().unwrap();
        let s_str = iter.next().unwrap();
        let s = s_str.chars().next().unwrap();
        let b = BInfo { r, c, id: i as u32, kind: s };
        by_row.push(b);
        blockers.push(Blocker { r, c, kind: s });
    }

    let mut by_col = Vec::with_capacity(k);
    for b in &by_row {
        by_col.push(BInfo { r: b.r, c: b.c, id: b.id, kind: b.kind });
    }

    by_row.par_sort_unstable_by(|a, b| a.r.cmp(&b.r).then(a.c.cmp(&b.c)));
    by_col.par_sort_unstable_by(|a, b| a.c.cmp(&b.c).then(a.r.cmp(&b.r)));

    let num_nodes = 4 * k;
    let next_node_vec: Vec<usize> = (0..num_nodes).into_par_iter().map(|u| {
        let b_id = u / 4;
        let out_dir = u % 4;
        let b = &blockers[b_id];

        let next_b = match out_dir {
            UP => {
                let start = by_col.partition_point(|x| x.c < b.c);
                let end = by_col.partition_point(|x| x.c <= b.c);
                let slice = &by_col[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|x| x.r < b.r);
                    if idx > 0 { Some(&slice[idx - 1]) } else { Some(slice.last().unwrap()) }
                }
            },
            DOWN => {
                let start = by_col.partition_point(|x| x.c < b.c);
                let end = by_col.partition_point(|x| x.c <= b.c);
                let slice = &by_col[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|x| x.r <= b.r);
                    if idx < slice.len() { Some(&slice[idx]) } else { Some(&slice[0]) }
                }
            },
            LEFT => {
                let start = by_row.partition_point(|x| x.r < b.r);
                let end = by_row.partition_point(|x| x.r <= b.r);
                let slice = &by_row[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|x| x.c < b.c);
                    if idx > 0 { Some(&slice[idx - 1]) } else { Some(slice.last().unwrap()) }
                }
            },
            RIGHT => {
                let start = by_row.partition_point(|x| x.r < b.r);
                let end = by_row.partition_point(|x| x.r <= b.r);
                let slice = &by_row[start..end];
                if slice.is_empty() { None }
                else {
                    let idx = slice.partition_point(|x| x.c <= b.c);
                    if idx < slice.len() { Some(&slice[idx]) } else { Some(&slice[0]) }
                }
            },
            _ => None
        };

        if let Some(nb) = next_b {
            let new_dir = if nb.kind == 'L' { (out_dir + 3) % 4 } else { (out_dir + 1) % 4 };
            (nb.id as usize) * 4 + new_dir
        } else {
            usize::MAX
        }
    }).collect();

    let mut state = vec![0u8; num_nodes];
    let mut depth = vec![0u32; num_nodes];
    let mut root_on_cycle = vec![usize::MAX; num_nodes];
    let mut pos_in_cycle = vec![0u32; num_nodes];
    let mut cycle_id = vec![usize::MAX; num_nodes];
    let mut cycle_lens = Vec::new();

    for i in 0..num_nodes {
        if state[i] != 0 { continue; }

        let mut path = Vec::new();
        let mut curr = i;
        while curr != usize::MAX && state[curr] == 0 {
            state[curr] = 1;
            path.push(curr);
            curr = next_node_vec[curr];
        }

        let mut cycle_start_idx = usize::MAX;
        if curr != usize::MAX && state[curr] == 1 {
            for (idx, &node) in path.iter().enumerate() {
                if node == curr {
                    cycle_start_idx = idx;
                    break;
                }
            }
        }

        if cycle_start_idx != usize::MAX {
            let cid = cycle_lens.len();
            let c_len = (path.len() - cycle_start_idx) as u32;
            cycle_lens.push(c_len);

            for (k, &u) in path.iter().enumerate().skip(cycle_start_idx) {
                cycle_id[u] = cid;
                pos_in_cycle[u] = (k - cycle_start_idx) as u32;
                depth[u] = 0;
                root_on_cycle[u] = u;
                state[u] = 2;
            }

            for k in (0..cycle_start_idx).rev() {
                let u = path[k];
                let v = next_node_vec[u];
                depth[u] = depth[v] + 1;
                root_on_cycle[u] = root_on_cycle[v];
                cycle_id[u] = cycle_id[v];
                state[u] = 2;
            }
        } else {
            for k in (0..path.len()).rev() {
                let u = path[k];
                let v = next_node_vec[u];
                if v != usize::MAX {
                    depth[u] = depth[v] + 1;
                    root_on_cycle[u] = root_on_cycle[v];
                    cycle_id[u] = cycle_id[v];
                }
                state[u] = 2;
            }
        }
    }

    let log_k = 20;
    let mut up = vec![vec![usize::MAX; log_k]; num_nodes];
    up.par_iter_mut().enumerate().for_each(|(i, row)| {
        row[0] = next_node_vec[i];
    });
    for j in 1..log_k {
        let prev_col: Vec<usize> = (0..num_nodes).map(|i| up[i][j-1]).collect();
        up.par_iter_mut().enumerate().for_each(|(i, row)| {
             if prev_col[i] != usize::MAX {
                 row[j] = prev_col[prev_col[i]];
             }
        });
    }

    let q_count: usize = iter.next().unwrap().parse().unwrap();
    let mut queries = Vec::with_capacity(q_count);
    for _ in 0..q_count {
        queries.push(Query {
            r1: iter.next().unwrap().parse().unwrap(),
            c1: iter.next().unwrap().parse().unwrap(),
            r2: iter.next().unwrap().parse().unwrap(),
            c2: iter.next().unwrap().parse().unwrap(),
        });
    }

    let mut results = vec![0; q_count];
    results.par_iter_mut().zip(queries.par_iter()).for_each(|(res, query)| {
        if query.r1 == query.r2 && query.c1 == query.c2 {
            *res = 0; return;
        }

        let mut ans = INF;

        // 0-turn checks
        let col_slice = {
            let start = by_col.partition_point(|x| x.c < query.c1);
            let end = by_col.partition_point(|x| x.c <= query.c1);
            &by_col[start..end]
        };
        let row_slice = {
            let start = by_row.partition_point(|x| x.r < query.r1);
            let end = by_row.partition_point(|x| x.r <= query.r1);
            &by_row[start..end]
        };

        if query.c1 == query.c2 {
            // UP
            let fb = if col_slice.is_empty() { None } else {
                let idx = col_slice.partition_point(|x| x.r < query.r1);
                if idx > 0 { Some(&col_slice[idx - 1]) } else { Some(col_slice.last().unwrap()) }
            };
            if let Some(b) = fb {
                let d_g = if query.r2 <= query.r1 { query.r1 - query.r2 } else { query.r1 + n - query.r2 };
                let d_b = if b.r < query.r1 { query.r1 - b.r } else { query.r1 + n - b.r };
                if d_g <= d_b { ans = 0; }
            } else { ans = 0; }

            // DOWN
            if ans != 0 {
                let fb = if col_slice.is_empty() { None } else {
                    let idx = col_slice.partition_point(|x| x.r <= query.r1);
                    if idx < col_slice.len() { Some(&col_slice[idx]) } else { Some(&col_slice[0]) }
                };
                if let Some(b) = fb {
                    let d_g = if query.r2 >= query.r1 { query.r2 - query.r1 } else { n - query.r1 + query.r2 };
                    let d_b = if b.r > query.r1 { b.r - query.r1 } else { n - query.r1 + b.r };
                    if d_g <= d_b { ans = 0; }
                } else { ans = 0; }
            }
        } else if query.r1 == query.r2 {
            // LEFT
            let fb = if row_slice.is_empty() { None } else {
                let idx = row_slice.partition_point(|x| x.c < query.c1);
                if idx > 0 { Some(&row_slice[idx - 1]) } else { Some(row_slice.last().unwrap()) }
            };
            if let Some(b) = fb {
                let d_g = if query.c2 <= query.c1 { query.c1 - query.c2 } else { query.c1 + m - query.c2 };
                let d_b = if b.c < query.c1 { query.c1 - b.c } else { query.c1 + m - b.c };
                if d_g <= d_b { ans = 0; }
            } else { ans = 0; }

            // RIGHT
            if ans != 0 {
                let fb = if row_slice.is_empty() { None } else {
                    let idx = row_slice.partition_point(|x| x.c <= query.c1);
                    if idx < row_slice.len() { Some(&row_slice[idx]) } else { Some(&row_slice[0]) }
                };
                if let Some(b) = fb {
                    let d_g = if query.c2 >= query.c1 { query.c2 - query.c1 } else { m - query.c1 + query.c2 };
                    let d_b = if b.c > query.c1 { b.c - query.c1 } else { m - query.c1 + b.c };
                    if d_g <= d_b { ans = 0; }
                } else { ans = 0; }
            }
        }

        if ans == 0 { *res = 0; return; }

        let mut starts = Vec::with_capacity(4);
        // Start nodes
        // UP
        {
            let fb = if col_slice.is_empty() { None } else {
                let idx = col_slice.partition_point(|x| x.r < query.r1);
                if idx > 0 { Some(&col_slice[idx - 1]) } else { Some(col_slice.last().unwrap()) }
            };
            if let Some(b) = fb {
                let nd = if b.kind == 'L' { (UP + 3) % 4 } else { (UP + 1) % 4 };
                starts.push((b.id as usize) * 4 + nd);
            }
        }
        // DOWN
        {
            let fb = if col_slice.is_empty() { None } else {
                let idx = col_slice.partition_point(|x| x.r <= query.r1);
                if idx < col_slice.len() { Some(&col_slice[idx]) } else { Some(&col_slice[0]) }
            };
            if let Some(b) = fb {
                let nd = if b.kind == 'L' { (DOWN + 3) % 4 } else { (DOWN + 1) % 4 };
                starts.push((b.id as usize) * 4 + nd);
            }
        }
        // LEFT
        {
            let fb = if row_slice.is_empty() { None } else {
                let idx = row_slice.partition_point(|x| x.c < query.c1);
                if idx > 0 { Some(&row_slice[idx - 1]) } else { Some(row_slice.last().unwrap()) }
            };
            if let Some(b) = fb {
                let nd = if b.kind == 'L' { (LEFT + 3) % 4 } else { (LEFT + 1) % 4 };
                starts.push((b.id as usize) * 4 + nd);
            }
        }
        // RIGHT
        {
            let fb = if row_slice.is_empty() { None } else {
                let idx = row_slice.partition_point(|x| x.c <= query.c1);
                if idx < row_slice.len() { Some(&row_slice[idx]) } else { Some(&row_slice[0]) }
            };
            if let Some(b) = fb {
                let nd = if b.kind == 'L' { (RIGHT + 3) % 4 } else { (RIGHT + 1) % 4 };
                starts.push((b.id as usize) * 4 + nd);
            }
        }

        let mut targets = Vec::with_capacity(4);
        // Arrival DOWN
        {
            let s = {
                let start = by_col.partition_point(|x| x.c < query.c2);
                let end = by_col.partition_point(|x| x.c <= query.c2);
                &by_col[start..end]
            };
            if !s.is_empty() {
                let idx = s.partition_point(|x| x.r < query.r2);
                let b = if idx > 0 { &s[idx - 1] } else { s.last().unwrap() };
                targets.push((b.id as usize) * 4 + DOWN);
            }
        }
        // Arrival UP
        {
            let s = {
                let start = by_col.partition_point(|x| x.c < query.c2);
                let end = by_col.partition_point(|x| x.c <= query.c2);
                &by_col[start..end]
            };
            if !s.is_empty() {
                let idx = s.partition_point(|x| x.r <= query.r2);
                let b = if idx < s.len() { &s[idx] } else { &s[0] };
                targets.push((b.id as usize) * 4 + UP);
            }
        }
        // Arrival RIGHT
        {
            let s = {
                let start = by_row.partition_point(|x| x.r < query.r2);
                let end = by_row.partition_point(|x| x.r <= query.r2);
                &by_row[start..end]
            };
            if !s.is_empty() {
                let idx = s.partition_point(|x| x.c < query.c2);
                let b = if idx > 0 { &s[idx - 1] } else { s.last().unwrap() };
                targets.push((b.id as usize) * 4 + RIGHT);
            }
        }
        // Arrival LEFT
        {
            let s = {
                let start = by_row.partition_point(|x| x.r < query.r2);
                let end = by_row.partition_point(|x| x.r <= query.r2);
                &by_row[start..end]
            };
            if !s.is_empty() {
                let idx = s.partition_point(|x| x.c <= query.c2);
                let b = if idx < s.len() { &s[idx] } else { &s[0] };
                targets.push((b.id as usize) * 4 + LEFT);
            }
        }

        for &u in &starts {
            for &v in &targets {
                if cycle_id[u] == usize::MAX { continue; }
                if cycle_id[u] == cycle_id[v] {
                    let mut d = INF;
                    if depth[v] == 0 {
                        let root_u = root_on_cycle[u];
                        let c_len = cycle_lens[cycle_id[u]];
                        let p_u = pos_in_cycle[root_u];
                        let p_v = pos_in_cycle[v];
                        let dist = if p_v >= p_u { p_v - p_u } else { p_v + c_len - p_u };
                        d = depth[u] + dist;
                    } else {
                        if root_on_cycle[u] == root_on_cycle[v] && depth[u] >= depth[v] {
                             let diff = depth[u] - depth[v];
                             let mut curr = u;
                             for j in 0..log_k {
                                 if (diff >> j) & 1 == 1 {
                                     curr = up[curr][j];
                                 }
                             }
                             if curr == v {
                                 d = diff;
                             }
                        }
                    }
                    if d != INF {
                        if d + 1 < ans { ans = d + 1; }
                    }
                }
            }
        }

        if ans >= INF { *res = -1; } else { *res = ans as i32; }
    });

    let mut out = io::BufWriter::new(io::stdout());
    for res in results {
        writeln!(out, "{}", res).unwrap();
    }
}

