use std::io::{self, Read, Write};
use rayon::prelude::*;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Dir {
    Up = 0,
    Right = 1,
    Down = 2,
    Left = 3,
}

impl Dir {
    fn from_usize(u: usize) -> Self {
        match u {
            0 => Dir::Up,
            1 => Dir::Right,
            2 => Dir::Down,
            3 => Dir::Left,
            _ => panic!("Invalid dir"),
        }
    }

    fn to_usize(self) -> usize {
        self as usize
    }

    fn turn(self, t: char) -> Self {
        match t {
            'L' => match self {
                Dir::Up => Dir::Left,
                Dir::Right => Dir::Up,
                Dir::Down => Dir::Right,
                Dir::Left => Dir::Down,
            },
            'R' => match self {
                Dir::Up => Dir::Right,
                Dir::Right => Dir::Down,
                Dir::Down => Dir::Left,
                Dir::Left => Dir::Up,
            },
            _ => panic!("Invalid turn"),
        }
    }
}

struct Special {
    r: u32,
    c: u32,
    t: char,
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_whitespace();

    let n: u32 = iter.next().unwrap().parse().unwrap();
    let m: u32 = iter.next().unwrap().parse().unwrap();
    let k: usize = iter.next().unwrap().parse().unwrap();

    let mut specials = Vec::with_capacity(k);
    for _ in 0..k {
        let r = iter.next().unwrap().parse().unwrap();
        let c = iter.next().unwrap().parse().unwrap();
        let t = iter.next().unwrap().chars().next().unwrap();
        specials.push(Special { r, c, t });
    }

    let mut by_row: Vec<u32> = (0..k as u32).collect();
    by_row.sort_unstable_by(|&a, &b| {
        let sa = &specials[a as usize];
        let sb = &specials[b as usize];
        if sa.r != sb.r { sa.r.cmp(&sb.r) } else { sa.c.cmp(&sb.c) }
    });

    let mut by_col: Vec<u32> = (0..k as u32).collect();
    by_col.sort_unstable_by(|&a, &b| {
        let sa = &specials[a as usize];
        let sb = &specials[b as usize];
        if sa.c != sb.c { sa.c.cmp(&sb.c) } else { sa.r.cmp(&sb.r) }
    });

    let mut row_start = vec![u32::MAX; (n + 1) as usize];
    let mut row_end = vec![0; (n + 1) as usize];
    for (i, &idx) in by_row.iter().enumerate() {
        let r = specials[idx as usize].r as usize;
        if row_start[r] == u32::MAX { row_start[r] = i as u32; }
        row_end[r] = (i + 1) as u32;
    }

    let mut col_start = vec![u32::MAX; (m + 1) as usize];
    let mut col_end = vec![0; (m + 1) as usize];
    for (i, &idx) in by_col.iter().enumerate() {
        let c = specials[idx as usize].c as usize;
        if col_start[c] == u32::MAX { col_start[c] = i as u32; }
        col_end[c] = (i + 1) as u32;
    }

    let get_next = |r: u32, c: u32, dir: Dir| -> Option<(usize, u32)> {
        match dir {
            Dir::Right => {
                let start = row_start[r as usize];
                if start == u32::MAX { return None; }
                let end = row_end[r as usize];
                let slice = &by_row[start as usize .. end as usize];
                let pos = slice.partition_point(|&idx| specials[idx as usize].c <= c);
                if pos < slice.len() {
                    let idx = slice[pos] as usize;
                    Some((idx, specials[idx].c - c))
                } else {
                    let idx = slice[0] as usize;
                    Some((idx, (m - c) + specials[idx].c))
                }
            },
            Dir::Left => {
                let start = row_start[r as usize];
                if start == u32::MAX { return None; }
                let end = row_end[r as usize];
                let slice = &by_row[start as usize .. end as usize];
                let pos = slice.partition_point(|&idx| specials[idx as usize].c < c);
                if pos > 0 {
                    let idx = slice[pos - 1] as usize;
                    Some((idx, c - specials[idx].c))
                } else {
                    let idx = slice[slice.len() - 1] as usize;
                    Some((idx, c + (m - specials[idx].c)))
                }
            },
            Dir::Down => {
                let start = col_start[c as usize];
                if start == u32::MAX { return None; }
                let end = col_end[c as usize];
                let slice = &by_col[start as usize .. end as usize];
                let pos = slice.partition_point(|&idx| specials[idx as usize].r <= r);
                if pos < slice.len() {
                    let idx = slice[pos] as usize;
                    Some((idx, specials[idx].r - r))
                } else {
                    let idx = slice[0] as usize;
                    Some((idx, (n - r) + specials[idx].r))
                }
            },
            Dir::Up => {
                let start = col_start[c as usize];
                if start == u32::MAX { return None; }
                let end = col_end[c as usize];
                let slice = &by_col[start as usize .. end as usize];
                let pos = slice.partition_point(|&idx| specials[idx as usize].r < r);
                if pos > 0 {
                    let idx = slice[pos - 1] as usize;
                    Some((idx, r - specials[idx].r))
                } else {
                    let idx = slice[slice.len() - 1] as usize;
                    Some((idx, r + (n - specials[idx].r)))
                }
            }
        }
    };

    let num_nodes = 4 * k;
    let mut succ = vec![usize::MAX; num_nodes];
    for i in 0..k {
        for d_in in 0..4 {
            let dir_in = Dir::from_usize(d_in);
            let dir_out = dir_in.turn(specials[i].t);
            if let Some((next_idx, _)) = get_next(specials[i].r, specials[i].c, dir_out) {
                succ[i * 4 + d_in] = next_idx * 4 + dir_out.to_usize();
            }
        }
    }

    let mut comp = vec![usize::MAX; num_nodes];
    let mut depth = vec![0; num_nodes];
    let mut cycle_pos = vec![usize::MAX; num_nodes];
    let mut root = vec![usize::MAX; num_nodes];
    let mut cycle_sizes = Vec::new();
    let mut visited = vec![0u8; num_nodes];

    for i in 0..num_nodes {
        if visited[i] != 0 || succ[i] == usize::MAX { continue; }
        let mut path = Vec::new();
        let mut curr = i;
        while visited[curr] == 0 {
            visited[curr] = 1;
            path.push(curr);
            let next = succ[curr];
            if next == usize::MAX { break; }
            curr = next;
        }

        let hit = curr;
        let mut is_cycle = false;
        let mut start_idx = 0;

        if succ[hit] != usize::MAX && visited[hit] == 1 {
             if let Some(pos) = path.iter().position(|&x| x == hit) {
                 is_cycle = true;
                 start_idx = pos;
             }
        }

        if is_cycle {
            let comp_id = cycle_sizes.len();
            let mut c_len = 0;
            for j in start_idx..path.len() {
                let node = path[j];
                comp[node] = comp_id;
                root[node] = node;
                cycle_pos[node] = c_len;
                depth[node] = 0;
                visited[node] = 2;
                c_len += 1;
            }
            cycle_sizes.push(c_len);

            for j in (0..start_idx).rev() {
                let node = path[j];
                let nxt = succ[node];
                comp[node] = comp[nxt];
                root[node] = root[nxt];
                depth[node] = depth[nxt] + 1;
                visited[node] = 2;
            }
        } else {
             let target_comp = if succ[hit] == usize::MAX { usize::MAX } else { comp[hit] };
             if target_comp == usize::MAX {
                 for &node in &path {
                     visited[node] = 2;
                     comp[node] = usize::MAX;
                 }
             } else {
                 for j in (0..path.len()).rev() {
                     let node = path[j];
                     let nxt = succ[node];
                     comp[node] = comp[nxt];
                     root[node] = root[nxt];
                     depth[node] = depth[nxt] + 1;
                     visited[node] = 2;
                 }
             }
        }
    }

    let log_k = 20;
    let mut up = vec![vec![usize::MAX; log_k]; num_nodes];
    for i in 0..num_nodes {
        up[i][0] = succ[i];
    }
    for j in 1..log_k {
        for i in 0..num_nodes {
            if up[i][j-1] != usize::MAX {
                up[i][j] = up[up[i][j-1]][j-1];
            }
        }
    }

    let q: usize = iter.next().unwrap().parse().unwrap();
    let mut queries = Vec::with_capacity(q);
    for _ in 0..q {
        let a: u32 = iter.next().unwrap().parse().unwrap();
        let b: u32 = iter.next().unwrap().parse().unwrap();
        let c: u32 = iter.next().unwrap().parse().unwrap();
        let d: u32 = iter.next().unwrap().parse().unwrap();
        queries.push((a, b, c, d));
    }

    let results: Vec<i32> = queries.into_par_iter().map(|(r1, c1, r2, c2)| {
        if r1 == r2 && c1 == c2 { return 0; }

        let mut ans = u32::MAX;

        for dir_idx in 0..4 {
            let dir = Dir::from_usize(dir_idx);
            let dist_opt = match dir {
                Dir::Up => if c1==c2 { Some(if r1>=r2 {r1-r2} else {r1+n-r2}) } else {None},
                Dir::Down => if c1==c2 { Some(if r2>=r1 {r2-r1} else {r2+n-r1}) } else {None},
                Dir::Left => if r1==r2 { Some(if c1>=c2 {c1-c2} else {c1+m-c2}) } else {None},
                Dir::Right => if r1==r2 { Some(if c2>=c1 {c2-c1} else {c2+m-c1}) } else {None},
            };

            if let Some(d_target) = dist_opt {
                let next_spec = get_next(r1, c1, dir);
                if let Some((_, d_spec)) = next_spec {
                    if d_spec >= d_target { return 0; }
                } else {
                    return 0;
                }
            }
        }

        let mut start_nodes = Vec::new();
        for dir_idx in 0..4 {
            let dir = Dir::from_usize(dir_idx);
            if let Some((idx, _)) = get_next(r1, c1, dir) {
                start_nodes.push(idx * 4 + dir_idx);
            }
        }
        if start_nodes.is_empty() { return -1; }

        let mut targets = Vec::new();
        for final_dir_idx in 0..4 {
            let final_dir = Dir::from_usize(final_dir_idx);
            let back_dir = match final_dir {
                Dir::Up => Dir::Down, Dir::Down => Dir::Up,
                Dir::Left => Dir::Right, Dir::Right => Dir::Left,
            };

            if let Some((v_idx, _)) = get_next(r2, c2, back_dir) {
                let t_char = specials[v_idx].t;
                let in_dir = match t_char {
                    'L' => match final_dir { Dir::Up=>Dir::Right, Dir::Right=>Dir::Down, Dir::Down=>Dir::Left, Dir::Left=>Dir::Up },
                    'R' => match final_dir { Dir::Up=>Dir::Left, Dir::Left=>Dir::Down, Dir::Down=>Dir::Right, Dir::Right=>Dir::Up },
                    _ => unreachable!(),
                };
                targets.push(v_idx * 4 + in_dir.to_usize());
            }
        }

        for &u in &start_nodes {
            for &v in &targets {
                if comp[u] == usize::MAX || comp[v] == usize::MAX || comp[u] != comp[v] { continue; }

                let d;
                if cycle_pos[v] != usize::MAX { 
                     if cycle_pos[u] != usize::MAX { 
                         let c_len = cycle_sizes[comp[u]];
                         d = (cycle_pos[v] + c_len - cycle_pos[u]) % c_len;
                     } else { 
                         let c_len = cycle_sizes[comp[u]];
                         let d_on_cycle = (cycle_pos[v] + c_len - cycle_pos[root[u]]) % c_len;
                         d = depth[u] as usize + d_on_cycle;
                     }
                } else { 
                    if cycle_pos[u] != usize::MAX { 
                        d = usize::MAX;
                    } else { 
                        if root[u] != root[v] || depth[v] > depth[u] {
                            d = usize::MAX;
                        } else {
                            let diff = depth[u] - depth[v];
                            let mut curr = u;
                            let mut shift = diff;
                            for k in 0..log_k {
                                if (shift >> k) & 1 == 1 {
                                    curr = up[curr][k];
                                    if curr == usize::MAX { break; }
                                }
                            }
                            if curr == v {
                                d = diff as usize;
                            } else {
                                d = usize::MAX;
                            }
                        }
                    }
                }

                if d != usize::MAX {
                    if (d as u32) + 1 < ans {
                        ans = (d as u32) + 1;
                    }
                }
            }
        }

        if ans == u32::MAX { -1 } else { ans as i32 }
    }).collect();

    let stdout = io::stdout();
    let mut handle = stdout.lock();
    for r in results {
        writeln!(handle, "{}", r).ok();
    }
