        // Target states: leaving an obstacle to hit Goal
        let mut targets = Vec::with_capacity(4);
        if let Some(idx) = get_next_obs(q.r2, q.c2, DOWN) { targets.push(idx * 4 + UP); }
        if let Some(idx) = get_next_obs(q.r2, q.c2, UP) { targets.push(idx * 4 + DOWN); }
        if let Some(idx) = get_next_obs(q.r2, q.c2, RIGHT) { targets.push(idx * 4 + LEFT); }
        if let Some(idx) = get_next_obs(q.r2, q.c2, LEFT) { targets.push(idx * 4 + RIGHT); }

        for &s in &starts {
            for &t in &targets {
                if cycle_id[s] == usize::MAX || cycle_id[t] == usize::MAX { continue; }
                if cycle_id[s] != cycle_id[t] { continue; }

