fn dfs(u: u32, p: u32, d: u32, adj: &Vec<Vec<u32>>, 
       tin: &mut Vec<u32>, low: &mut Vec<u32>, tout: &mut Vec<u32>, 
       depth: &mut Vec<u32>, up: &mut Vec<[u32; LOG_N]>, timer: &mut u32) {
