#[inline(always)]
fn is_ancestor(u: u32, v: u32, tin: &[u32], tout: &[u32]) -> bool {
    tin[u as usize] <= tin[v as usize] && tout[u as usize] >= tout[v as usize]
}

fn check_edge(a: u32, b: u32, g1: u32, g2: u32, 
             tin: &[u32], tout: &[u32], low: &[u32], depth: &[u32]) -> &'static str {
    let (u, v) = if depth[g1 as usize] < depth[g2 as usize] { (g1, g2) } else { (g2, g1) };

    if low[v as usize] <= tin[u as usize] {
        return "yes";
    }

    if is_ancestor(v, a, tin, tout) == is_ancestor(v, b, tin, tout) { "yes" } else { "no" }
}

fn check_node(a: u32, b: u32, c: u32,
             tin: &[u32], tout: &[u32], low: &[u32], depth: &[u32], up: &[[u32; LOG_N]]) -> &'static str {
    let in_a = is_ancestor(c, a, tin, tout);
    let in_b = is_ancestor(c, b, tin, tout);

    if !in_a && !in_b {
        return "yes";
    }

    if in_a && in_b {
        let child_a = get_child_towards(c, a, depth, up);
        let child_b = get_child_towards(c, b, depth, up);

        if child_a == child_b {
            return "yes";
        }

        if low[child_a as usize] < tin[c as usize] && low[child_b as usize] < tin[c as usize] {
            return "yes";
        }
        return "no";
    }

    let inside = if in_a { a } else { b };
    let child = get_child_towards(c, inside, depth, up);

    if low[child as usize] < tin[c as usize] {
        "yes"
    } else {
        "no"
    }
}

fn get_child_towards(ancestor: u32, descendant: u32, depth: &[u32], up: &[[u32; LOG_N]]) -> u32 {
    let target = depth[ancestor as usize] + 1;
    let mut curr = descendant;

    for i in (0..LOG_N).rev() {
        let next = up[curr as usize][i];
        if next != 0 && depth[next as usize] >= target {
            curr = next;
        }
    }
    curr
}

