fn solve() {
    let mut input = Vec::new();
    io::stdin().read_to_end(&mut input).unwrap();

    // Fast cursor-based parser
    let mut cursor = 0;
    let mut next_u32 = || -> u32 {
        while cursor < input.len() && input[cursor] <= b' ' {
            cursor += 1;
        }
        if cursor == input.len() { return 0; }
        let mut res = 0;
        while cursor < input.len() && input[cursor] > b' ' {
            res = res * 10 + (input[cursor] - b'0') as u32;
            cursor += 1;
        }
        res
    };

    let n = next_u32() as usize;
    let e = next_u32() as usize;

    let mut adj = vec![vec![]; n + 1];
    for _ in 0..e {
        let u = next_u32();
        let v = next_u32();
        adj[u as usize].push(v);
        adj[v as usize].push(u);
    }

    let mut tin = vec![0u32; n + 1];
    let mut tout = vec![0u32; n + 1];
    let mut low = vec![0u32; n + 1];
    let mut depth = vec![0u32; n + 1];
    let mut up = vec![0u32; (n + 1) * LOG_N];

    // Iterative DFS
    let mut timer = 0;
    let mut stack = Vec::with_capacity(n);
    // (u, edge_index, parent)
    stack.push((1u32, 0u32, 0u32));

    while let Some((u, idx, p)) = stack.pop() {
        let u_usize = u as usize;

        if idx == 0 {
            timer += 1;
            tin[u_usize] = timer;
            low[u_usize] = timer;
            depth[u_usize] = if p == 0 { 0 } else { depth[p as usize] + 1 };

            up[u_usize * LOG_N] = p;
            for i in 1..LOG_N {
                let ancestor = up[u_usize * LOG_N + i - 1];
                if ancestor != 0 {
                    up[u_usize * LOG_N + i] = up[ancestor as usize * LOG_N + i - 1];
                }
            }
        }

        let adj_len = adj[u_usize].len() as u32;
        if idx < adj_len {
            stack.push((u, idx + 1, p));

            let v = adj[u_usize][idx as usize];
            if v == p {
                continue;
            }

            let v_usize = v as usize;
            if tin[v_usize] != 0 {
                low[u_usize] = low[u_usize].min(tin[v_usize]);
            } else {
                stack.push((v, 0, u));
            }
        } else {
            tout[u_usize] = timer;
            if p != 0 {
                low[p as usize] = low[p as usize].min(low[u_usize]);
            }
        }
    }

    let q = next_u32() as usize;
    // Store query data in a flat vector for better cache locality and chunking
    let mut query_data = Vec::with_capacity(q * 5);
    for _ in 0..q {
        let t = next_u32();
        query_data.push(t);
        query_data.push(next_u32());
        query_data.push(next_u32());
        query_data.push(next_u32());
        if t == 1 {
            query_data.push(next_u32());
        } else {
            query_data.push(0);
        }
    }

    let tin = &tin;
    let tout = &tout;
    let low = &low;
    let depth = &depth;
    let up = &up;

    let results: Vec<&'static str> = query_data.par_chunks(5).map(|chunk| {
        let t = chunk[0];
        let a = chunk[1] as usize;
        let b = chunk[2] as usize;

        let is_ancestor = |u: usize, v: usize| -> bool {
            tin[u] <= tin[v] && tout[u] >= tout[v]
        };

        if t == 1 {
            let g1 = chunk[3] as usize;
            let g2 = chunk[4] as usize;
            let (u, v) = if depth[g1] < depth[g2] { (g1, g2) } else { (g2, g1) };

            // If low[v] <= tin[u], then there's a back-edge covering the edge (u, v),
            // so removing (u, v) doesn't disconnect v from u.
            if low[v] <= tin[u] {
                "yes"
            } else {
                // Bridge: A and B disconnected if separated by (u, v)
                let in_a = is_ancestor(v, a);
                let in_b = is_ancestor(v, b);
                if in_a == in_b { "yes" } else { "no" }
            }
        } else {
            let c = chunk[3] as usize;

            // Determine the component ID relative to C
            // 0 -> Connected to "upper" part (ancestors of C)
            // v -> Disconnected subtree rooted at child v of C
            let get_comp = |node: usize| -> usize {
                if !is_ancestor(c, node) {
                    return 0;
                }

                let target_depth = depth[c] + 1;
                let mut curr = node;

                // Lift node to the child of C
                for i in (0..LOG_N).rev() {
                    let up_node = up[curr * LOG_N + i] as usize;
                    if up_node != 0 && depth[up_node] >= target_depth {
                        curr = up_node;
                    }
                }

                // Check if this subtree has a back-edge going above C
                if low[curr] < tin[c] { 0 } else { curr }
            };

            if get_comp(a) == get_comp(b) { "yes" } else { "no" }
        }
    }).collect();

    let stdout = io::stdout();
    let mut out = std::io::BufWriter::new(stdout.lock());
    for res in results {
        out.write_all(res.as_bytes()).unwrap();
        out.write_all(b"\n").unwrap();
    }
}

