fn solve() {
    let mut scanner = Scanner::new();
    let n = scanner.next_u32() as usize;
    let e = scanner.next_u32() as usize;

    let mut adj = vec![vec![]; n + 1];
    for _ in 0..e {
        let u = scanner.next_u32();
        let v = scanner.next_u32();
        adj[u as usize].push(v);
        adj[v as usize].push(u);
    }

    // --- Part 1: Bridges & Bridge Tree ---
    let mut tin = vec![0u32; n + 1];
    let mut low = vec![0u32; n + 1];
    let mut timer = 0;
    let mut bridges = Vec::new();

    bridge_dfs(1, 0, &mut timer, &mut tin, &mut low, &adj, &mut bridges);
    bridges.sort_unstable(); // Required for binary search

    // Identify Components for Bridge Tree
    let mut comp_id = vec![0u32; n + 1];
    let mut comp_count = 0;
    let mut q_bfs = Vec::new();

    for i in 1..=n {
        if comp_id[i] == 0 {
            comp_count += 1;
            comp_id[i] = comp_count;
            q_bfs.push(i as u32);
            while let Some(u) = q_bfs.pop() {
                for &v in &adj[u as usize] {
                    // If edge is a bridge, do not traverse
                    let edge = (min(u, v), max(u, v));
                    if bridges.binary_search(&edge).is_ok() {
                        continue;
                    }
                    if comp_id[v as usize] == 0 {
                        comp_id[v as usize] = comp_count;
                        q_bfs.push(v);
                    }
                }
            }
        }
    }

    let mut bt_adj = vec![vec![]; comp_count as usize + 1];
    for &(u, v) in &bridges {
        let cu = comp_id[u as usize];
        let cv = comp_id[v as usize];
        bt_adj[cu as usize].push(cv);
        bt_adj[cv as usize].push(cu);
    }

    let bt_lca = LCA::build(comp_count as usize, &bt_adj, 1);

    // --- Part 2: Block-Cut Tree ---
    tin.fill(0);
    low.fill(0);
    timer = 0;

    // Nodes 1..N are original vertices, N+1.. are block nodes.
    // Preallocate adjacency for BCT. Safe upper bound is N + E + 1.
    let mut bct_adj = vec![vec![]; n + e + 1]; 
    let mut num_blocks = 0;
    let mut stack_edges = Vec::with_capacity(e);
    let mut marker = vec![0; n + 1]; // Tracks which block a node was last added to

    bct_dfs(1, 0, &mut timer, &mut tin, &mut low, &adj, &mut bct_adj, &mut num_blocks, &mut stack_edges, &mut marker, n);

    // Truncate to actual size used
    let bct_size = n + num_blocks;
    bct_adj.truncate(bct_size + 1);

    let bct_lca = LCA::build(bct_size, &bct_adj, 1);

    // --- Queries ---
    let q = scanner.next_u32();
    let mut queries = Vec::with_capacity(q as usize);
    for _ in 0..q {
        let t = scanner.next_u32();
        if t == 1 {
            let a = scanner.next_u32();
            let b = scanner.next_u32();
            let g1 = scanner.next_u32();
            let g2 = scanner.next_u32();
            queries.push((1, a, b, g1, g2));
        } else {
            let a = scanner.next_u32();
            let b = scanner.next_u32();
            let c = scanner.next_u32();
            queries.push((2, a, b, c, 0));
        }
    }

    let results: Vec<&'static str> = queries.par_iter().map(|&(t, a, b, g1, g2)| {
        if t == 1 {
            let ca = comp_id[a as usize];
            let cb = comp_id[b as usize];
            let cg1 = comp_id[g1 as usize];
            let cg2 = comp_id[g2 as usize];

            // If the removed edge is within a component (not a bridge), connected.
            if cg1 == cg2 {
                "yes"
            } else {
                // In Bridge Tree, identify parent (u) and child (v) of the bridge edge.
                let (u, v) = if bt_lca.depth[cg1 as usize] < bt_lca.depth[cg2 as usize] {
                    (cg1, cg2)
                } else {
                    (cg2, cg1)
                };

                // If removing (u, v) disconnects ca and cb, then exactly one of them 
                // must be in the subtree of v.
                let a_in = bt_lca.is_ancestor(v, ca);
                let b_in = bt_lca.is_ancestor(v, cb);

                if a_in == b_in { "yes" } else { "no" }
            }
        } else {
            let c = g1; // 'c' is passed in g1 position
            // Check if C is on the simple path between A and B in Block-Cut Tree.
            // C is on path iff LCA(A, B) is ancestor of C AND (C is ancestor of A OR C is ancestor of B).
            let l = bct_lca.get_lca(a, b);

            let l_anc_c = bct_lca.is_ancestor(l, c);
            let c_anc_a = bct_lca.is_ancestor(c, a);
            let c_anc_b = bct_lca.is_ancestor(c, b);

            if l_anc_c && (c_anc_a || c_anc_b) {
                "no"
            } else {
                "yes"
            }
        }
    }).collect();

    let stdout = io::stdout();
    let mut out = std::io::BufWriter::new(stdout.lock());
    for res in results {
        out.write_all(res.as_bytes()).unwrap();
        out.write_all(b"\n").unwrap();
    }
}

fn bridge_dfs(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>, 
              adj: &Vec<Vec<u32>>, bridges: &mut Vec<(u32, u32)>) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v in &adj[u] {
        let v_usize = v as usize;
        if v_usize == p { continue; }
        if tin[v_usize] != 0 {
            low[u] = min(low[u], tin[v_usize]);
        } else {
            bridge_dfs(v_usize, u, timer, tin, low, adj, bridges);
            low[u] = min(low[u], low[v_usize]);
            if low[v_usize] > tin[u] {
                bridges.push((min(u as u32, v), max(u as u32, v)));
            }
        }
    }
}

fn bct_dfs(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>,
           adj: &Vec<Vec<u32>>, bct_adj: &mut Vec<Vec<u32>>, num_blocks: &mut usize,
           stack_edges: &mut Vec<(u32, u32)>, marker: &mut Vec<usize>, n: usize) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v in &adj[u] {
        let v_usize = v as usize;
        if v_usize == p { continue; }
        if tin[v_usize] != 0 {
            low[u] = min(low[u], tin[v_usize]);
            if tin[v_usize] < tin[u] {
                stack_edges.push((u as u32, v));
            }
        } else {
            stack_edges.push((u as u32, v));
            bct_dfs(v_usize, u, timer, tin, low, adj, bct_adj, num_blocks, stack_edges, marker, n);
            low[u] = min(low[u], low[v_usize]);
            if low[v_usize] >= tin[u] {
                *num_blocks += 1;
                let blk_idx = n + *num_blocks;

                // Ensure space (though preallocated, safety check)
                if bct_adj.len() <= blk_idx {
                    bct_adj.resize(blk_idx + 1, vec![]);
                }

                // Add u to block if not already added for this block
                if marker[u] != *num_blocks {
                    marker[u] = *num_blocks;
                    bct_adj[u].push(blk_idx as u32);
                    bct_adj[blk_idx].push(u as u32);
                }

                // Add other nodes in the biconnected component from stack
                loop {
                    let (x, y) = stack_edges.pop().unwrap();
                    let x_idx = x as usize;
                    let y_idx = y as usize;

                    if marker[x_idx] != *num_blocks {
                        marker[x_idx] = *num_blocks;
                        bct_adj[x_idx].push(blk_idx as u32);
                        bct_adj[blk_idx].push(x);
                    }
                    if marker[y_idx] != *num_blocks {
                        marker[y_idx] = *num_blocks;
                        bct_adj[y_idx].push(blk_idx as u32);
                        bct_adj[blk_idx].push(y);
                    }

                    if x == u as u32 && y == v { break; }
                }
            }
        }
    }
}

