        for i in (0..MAX_LOG).rev() {
            let next = self.up[curr][i] as usize;
            if next != 0 && !self.is_ancestor(next, v) {
                curr = next;
            }
        }
        self.up[curr][0] as usize
    }
}

fn solve() {
    let mut scanner = Scanner::new();
    let n = scanner.next_usize();
    let e = scanner.next_usize();

    let mut adj = vec![vec![]; n + 1];
    for _ in 0..e {
        let u = scanner.next_usize();
        let v = scanner.next_usize();
        adj[u].push(v as u32);
        adj[v].push(u as u32);
    }

    // --- Phase 1: Bridge Tree Construction ---
    let mut tin = vec![0u32; n + 1];
    let mut low = vec![0u32; n + 1];
    let mut timer = 0;
    let mut bridges = Vec::new();

    find_bridges(1, 0, &mut timer, &mut tin, &mut low, &adj, &mut bridges);
    bridges.sort_unstable();

    let mut comp_id = vec![0; n + 1];
    let mut comp_count = 0;
    let mut q_bfs = Vec::new();

    for i in 1..=n {
        if comp_id[i] == 0 {
            comp_count += 1;
            comp_id[i] = comp_count;
            q_bfs.push(i);

            while let Some(u) = q_bfs.pop() {
                for &v_u32 in &adj[u] {
                    let v = v_u32 as usize;
                    let edge = (min(u as u32, v_u32), max(u as u32, v_u32));
                    if bridges.binary_search(&edge).is_ok() {
                        continue;
                    }
                    if comp_id[v] == 0 {
                        comp_id[v] = comp_count;
                        q_bfs.push(v);
                    }
                }
            }
        }
    }

    let mut bt_adj = vec![vec![]; comp_count + 1];
    for &(u, v) in &bridges {
        let cu = comp_id[u as usize];
        let cv = comp_id[v as usize];
        bt_adj[cu].push(cv as u32);
        bt_adj[cv].push(cu as u32);
    }

    let bt_info = TreeInfo::new(comp_count, &bt_adj, 1);

    // --- Phase 2: Block-Cut Tree Construction ---
    tin.fill(0);
    low.fill(0);
    timer = 0;

    let mut bct_adj = vec![vec![]; n + 1];
    let mut num_blocks = 0;
    let mut edge_stack = Vec::new();
    let mut marker = vec![0; n + 1];

    build_bct(1, 0, &mut timer, &mut tin, &mut low, &adj, &mut bct_adj, &mut num_blocks, &mut edge_stack, &mut marker, n);

    let bct_info = TreeInfo::new(n + num_blocks, &bct_adj, 1);

    // --- Phase 3: Queries ---
    let q = scanner.next_usize();
    let mut queries = Vec::with_capacity(q);

    for _ in 0..q {
        let t = scanner.next_usize();
        let a = scanner.next_usize();
        let b = scanner.next_usize();
        let c = scanner.next_usize();
        let d = if t == 1 { scanner.next_usize() } else { 0 };
        queries.push((t, a, b, c, d));
    }

    let results: Vec<&'static str> = queries.par_iter().map(|&(t, a, b, c, d)| {
        if t == 1 {
            let g1 = c;
            let g2 = d;
            let ca = comp_id[a];
            let cb = comp_id[b];
            let cg1 = comp_id[g1];
            let cg2 = comp_id[g2];

            if cg1 == cg2 {
                "yes"
            } else {
                let v = if bt_info.depth[cg1] < bt_info.depth[cg2] { cg2 } else { cg1 };
                let a_in = bt_info.is_ancestor(v, ca);
                let b_in = bt_info.is_ancestor(v, cb);
                if a_in == b_in { "yes" } else { "no" }
            }
        } else {
            let l = bct_info.lca(a, b);
            let l_anc_c = bct_info.is_ancestor(l, c);
            let c_anc_a = bct_info.is_ancestor(c, a);
            let c_anc_b = bct_info.is_ancestor(c, b);

            if l_anc_c && (c_anc_a || c_anc_b) {
                "no"
            } else {
                "yes"
            }
        }
    }).collect();

    let stdout = io::stdout();
    let mut out = std::io::BufWriter::new(stdout.lock());
    for res in results {
        out.write_all(res.as_bytes()).unwrap();
        out.write_all(b"\n").unwrap();
    }
}

fn find_bridges(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>, 
                adj: &Vec<Vec<u32>>, bridges: &mut Vec<(u32, u32)>) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v_u32 in &adj[u] {
        let v = v_u32 as usize;
        if v == p { continue; }
        if tin[v] != 0 {
            low[u] = min(low[u], tin[v]);
        } else {
            find_bridges(v, u, timer, tin, low, adj, bridges);
            low[u] = min(low[u], low[v]);
            if low[v] > tin[u] {
                bridges.push((min(u as u32, v_u32), max(u as u32, v_u32)));
            }
        }
    }
}

fn build_bct(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>,
             adj: &Vec<Vec<u32>>, bct_adj: &mut Vec<Vec<u32>>, num_blocks: &mut usize,
             edge_stack: &mut Vec<(usize, usize)>, marker: &mut Vec<usize>, n: usize) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v_u32 in &adj[u] {
        let v = v_u32 as usize;
        if v == p { continue; }

        if tin[v] != 0 {
            low[u] = min(low[u], tin[v]);
            if tin[v] < tin[u] {
                edge_stack.push((u, v));
            }
        } else {
            edge_stack.push((u, v));
            build_bct(v, u, timer, tin, low, adj, bct_adj, num_blocks, edge_stack, marker, n);
            low[u] = min(low[u], low[v]);

            if low[v] >= tin[u] {
                *num_blocks += 1;
                let blk_idx = n + *num_blocks;

                if bct_adj.len() <= blk_idx {
                    bct_adj.resize(blk_idx + 1, Vec::new());
                }

                let mut add_bct_edge = |node: usize, blk: usize| {
                    if marker[node] != blk {
                        marker[node] = blk;
                        bct_adj[node].push(blk as u32);
                        bct_adj[blk].push(node as u32);
                    }
                };

                loop {
                    let (x, y) = edge_stack.pop().unwrap();
                    add_bct_edge(x, blk_idx);
                    add_bct_edge(y, blk_idx);
                    if x == u && y == v { break; }
                }
            }
        }
    }
}

