fn solve() {
    let mut input = Vec::new();
    io::stdin().read_to_end(&mut input).unwrap();

    let mut cursor = 0;
    let mut next_u32 = || -> u32 {
        while cursor < input.len() && input[cursor] <= b' ' {
            cursor += 1;
        }
        if cursor == input.len() { return 0; }
        let mut res = 0;
        while cursor < input.len() && input[cursor] > b' ' {
            res = res * 10 + (input[cursor] - b'0') as u32;
            cursor += 1;
        }
        res
    };

    let n = next_u32() as usize;
    let e = next_u32() as usize;

    let mut degree = vec![0u32; n + 1];
    let mut edges = Vec::with_capacity(e);
    for _ in 0..e {
        let u = next_u32();
        let v = next_u32();
        edges.push((u, v));
        degree[u as usize] += 1;
        degree[v as usize] += 1;
    }

    let mut head = vec![0usize; n + 2];
    for i in 1..=n {
        head[i+1] = head[i] + degree[i] as usize;
    }

    let mut adj = vec![0u32; head[n+1]];
    let mut current_head = head.clone();

    for (u, v) in edges {
        let u_idx = u as usize;
        let v_idx = v as usize;
        adj[current_head[u_idx]] = v;
        current_head[u_idx] += 1;
        adj[current_head[v_idx]] = u;
        current_head[v_idx] += 1;
    }

    let mut tin = vec![0u32; n + 1];
    let mut tout = vec![0u32; n + 1];
    let mut low = vec![0u32; n + 1];
    let mut depth = vec![0u32; n + 1];
    let mut up = vec![0u32; (n + 1) * LOG_N];
    let mut timer = 0;

    let mut stack = Vec::with_capacity(n);
    stack.push((1u32, head[1], 0u32));

    while let Some((u, idx, p)) = stack.pop() {
        let u_usize = u as usize;

        if idx == head[u_usize] {
            timer += 1;
            tin[u_usize] = timer;
            low[u_usize] = timer;
            depth[u_usize] = if p == 0 { 0 } else { depth[p as usize] + 1 };

            let base = u_usize * LOG_N;
            up[base] = p;
            for i in 1..LOG_N {
                let ancestor = up[base + i - 1] as usize;
                if ancestor != 0 {
                    up[base + i] = up[ancestor * LOG_N + i - 1];
                }
            }
        } else {
            let v = adj[idx - 1] as usize;
            low[u_usize] = std::cmp::min(low[u_usize], low[v]);
        }

        let end = head[u_usize + 1];
        let mut next_idx = idx;
        let mut pushed_child = false;

        while next_idx < end {
            let v = adj[next_idx];
            let v_usize = v as usize;
            next_idx += 1;

            if v == p {
                continue;
            }

            if tin[v_usize] != 0 {
                low[u_usize] = std::cmp::min(low[u_usize], tin[v_usize]);
            } else {
                stack.push((u, next_idx, p));
                stack.push((v, head[v_usize], u));
                pushed_child = true;
                break;
            }
        }

        if !pushed_child {
            tout[u_usize] = timer;
        }
    }

    let q = next_u32() as usize;
    let mut queries = Vec::with_capacity(q * 5);
    for _ in 0..q {
        let t = next_u32();
        queries.push(t);
        queries.push(next_u32());
        queries.push(next_u32());
        queries.push(next_u32());
        if t == 1 {
            queries.push(next_u32());
        } else {
            queries.push(0);
        }
    }

    let tin = &tin;
    let tout = &tout;
    let low = &low;
    let depth = &depth;
    let up = &up;

    let results: Vec<&'static str> = queries.par_chunks_exact(5).map(|chunk| {
        let t = chunk[0];
        let a = chunk[1] as usize;
        let b = chunk[2] as usize;

        let is_ancestor = |u: usize, v: usize| -> bool {
            tin[u] <= tin[v] && tout[u] >= tout[v]
        };

        if t == 1 {
            let g1 = chunk[3] as usize;
            let g2 = chunk[4] as usize;
            let (u, v) = if depth[g1] < depth[g2] { (g1, g2) } else { (g2, g1) };

            if low[v] <= tin[u] {
                "yes"
            } else {
                let a_in = is_ancestor(v, a);
                let b_in = is_ancestor(v, b);
                if a_in == b_in { "yes" } else { "no" }
            }
        } else {
            let c = chunk[3] as usize;

            let get_comp = |node: usize| -> usize {
                if !is_ancestor(c, node) {
                    return 0;
                }

                let mut curr = node;
                let mut k = (depth[curr] as isize - depth[c] as isize - 1) as usize;

                while k > 0 {
                    let tz = k.trailing_zeros();
                    curr = up[curr * LOG_N + tz as usize] as usize;
                    k &= !(1 << tz);
                }

                if low[curr] < tin[c] {
                    0
                } else {
                    curr
                }
            };

            if get_comp(a) == get_comp(b) { "yes" } else { "no" }
        }
    }).collect();

    let stdout = io::stdout();
    let mut out = std::io::BufWriter::new(stdout.lock());
    for res in results {
        out.write_all(res.as_bytes()).unwrap();
        out.write_all(b"\n").unwrap();
    }
}

