use std::io::{self, Read, Write};
use rayon::prelude::*;
use std::cmp::{min, max};

const STACK_SIZE: usize = 256 * 1024 * 1024;
const MAX_LOG: usize = 19; // Sufficient for 2N nodes where N=100,000

fn main() {
    // Spawn a thread with a large stack to prevent overflow during deep DFS
    let builder = std::thread::Builder::new().stack_size(STACK_SIZE);
    builder.spawn(run).unwrap().join().unwrap();
}

fn run() {
    // Fast Input Reading
    let mut input = Vec::new();
    io::stdin().read_to_end(&mut input).unwrap();
    let mut scanner = Scanner::new(&input);
    let out = io::stdout();
    let mut writer = std::io::BufWriter::new(out.lock());

    let n = scanner.next_u32() as usize;
    let e = scanner.next_u32() as usize;

    let mut adj = vec![vec![]; n + 1];
    for _ in 0..e {
        let u = scanner.next_u32();
        let v = scanner.next_u32();
        adj[u as usize].push(v);
        adj[v as usize].push(u);
    }

    // --- Phase 1: DFS for Bridges and Block-Cut Tree (BCT) construction ---
    // We compute Bridges and build the BCT in a single DFS pass to be efficient.

    let mut tin = vec![0u32; n + 1];
    let mut low = vec![0u32; n + 1];
    let mut timer = 0;
    let mut bridges = Vec::new();
    let mut edge_stack = Vec::new();

    // BCT Adjacency: Nodes 1..N are original vertices. Nodes N+1.. are Block nodes.
    let mut bct_adj = vec![vec![]; n + 1]; 
    let mut bct_node_count = n;

    dfs_process(1, 0, &adj, &mut tin, &mut low, &mut timer, &mut edge_stack, 
                &mut bridges, &mut bct_adj, &mut bct_node_count);

    // --- Phase 2: Build Bridge Tree ---
    // Compress 2-edge-connected components into single nodes.

    bridges.sort_unstable(); // Sort bridges to allow binary search

    let mut dsu = Dsu::new(n);
    for u in 1..=n {
        for &v_u32 in &adj[u] {
            let v = v_u32 as usize;
            if u < v {
                // If edge (u, v) is NOT a bridge, union the sets
                if bridges.binary_search(&(u as u32, v_u32)).is_err() {
                    dsu.union(u, v);
                }
            }
        }
    }

    // Map each original node to its component ID in the Bridge Tree
    let mut comp = vec![0u32; n + 1];
    let mut comp_count = 0;
    let mut root_map = vec![0u32; n + 1];

    for i in 1..=n {
        let root = dsu.find(i);
        if root_map[root] == 0 {
            comp_count += 1;
            root_map[root] = comp_count;
        }
        comp[i] = root_map[root];
    }

    // Build adjacency list for Bridge Tree
    let mut bt_adj = vec![vec![]; comp_count as usize + 1];
    for &(u, v) in &bridges {
        let cu = comp[u as usize];
        let cv = comp[v as usize];
        bt_adj[cu as usize].push(cv);
        bt_adj[cv as usize].push(cu);
    }

    // --- Phase 3: Preprocess LCA for both trees ---
    // Bridge Tree LCA
    let bt_lca = Lca::new(&bt_adj, 1, comp_count as usize);
    // Block-Cut Tree LCA
    let bct_lca = Lca::new(&bct_adj, 1, bct_node_count);

    // --- Phase 4: Process Queries ---
    let q = scanner.next_u32() as usize;
    let mut queries = Vec::with_capacity(q);
    for _ in 0..q {
        let t = scanner.next_u32();
        if t == 1 {
            queries.push((1, scanner.next_u32(), scanner.next_u32(), scanner.next_u32(), scanner.next_u32()));
        } else {
            queries.push((2, scanner.next_u32(), scanner.next_u32(), scanner.next_u32(), 0));
        }
    }

    // Process queries in parallel
    let results: Vec<&str> = queries.par_iter().map(|&(t, a, b, c, d)| {
        if t == 1 {
            // Type 1: Can we go A -> B if edge (G1, G2) is blocked?
            let g1 = c;
            let g2 = d;
            let ca = comp[a as usize];
            let cb = comp[b as usize];
            let cg1 = comp[g1 as usize];
            let cg2 = comp[g2 as usize];

            // If the edge (G1, G2) is not a bridge, removing it doesn't disconnect components
            if cg1 == cg2 {
                "yes"
            } else {
                // In the Bridge Tree, check if removing edge (cg1, cg2) separates ca and cb.
                // Identify parent/child relationship in rooted tree
                let (u, v) = if bt_lca.depth[cg1 as usize] < bt_lca.depth[cg2 as usize] {
                    (cg1, cg2)
                } else {
                    (cg2, cg1)
                };

                // If separated, exactly one of ca, cb is in v's subtree
                let a_in = bt_lca.is_ancestor(v, ca);
                let b_in = bt_lca.is_ancestor(v, cb);

                if a_in == b_in { "yes" } else { "no" }
            }
        } else {
            // Type 2: Can we go A -> B if vertex C is blocked?
            let blocked = c;

            // In Block-Cut Tree, removing 'blocked' disconnects A and B if 'blocked' lies on the simple path between them.
            // Condition: LCA(A, B) is ancestor of Blocked AND (Blocked is ancestor of A OR Blocked is ancestor of B)
            let l = bct_lca.lca(a, b);

            let l_anc_c = bct_lca.is_ancestor(l, blocked);
            let c_anc_a = bct_lca.is_ancestor(blocked, a);
            let c_anc_b = bct_lca.is_ancestor(blocked, b);

            if l_anc_c && (c_anc_a || c_anc_b) { "no" } else { "yes" }
        }
    }).collect();

    for res in results {
        writeln!(writer, "{}", res).unwrap();
    }
}

// --- Helper Functions and Structs ---

// DFS to find Bridges and build BCT structure
fn dfs_process(u: usize, p: usize, adj: &Vec<Vec<u32>>, 
               tin: &mut Vec<u32>, low: &mut Vec<u32>, timer: &mut u32,
               edge_stack: &mut Vec<(u32, u32)>,
               bridges: &mut Vec<(u32, u32)>,
               bct_adj: &mut Vec<Vec<u32>>, bct_node_count: &mut usize) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v_u32 in &adj[u] {
        let v = v_u32 as usize;
        if v == p { continue; }

        if tin[v] != 0 {
            low[u] = min(low[u], tin[v]);
            if tin[v] < tin[u] {
                edge_stack.push((u as u32, v_u32));
            }
        } else {
            edge_stack.push((u as u32, v_u32));
            dfs_process(v, u, adj, tin, low, timer, edge_stack, bridges, bct_adj, bct_node_count);
            low[u] = min(low[u], low[v]);

            // Bridge Condition
            if low[v] > tin[u] {
                bridges.push((min(u as u32, v_u32), max(u as u32, v_u32)));
            }

            // Block (Biconnected Component) Condition
            if low[v] >= tin[u] {
                *bct_node_count += 1;
                let blk = *bct_node_count as u32;
                if bct_adj.len() <= *bct_node_count {
                    bct_adj.resize(*bct_node_count + 1, Vec::new());
                }

                // Collect unique nodes in this block
                let mut block_nodes = Vec::new();
                block_nodes.push(u as u32);

                loop {
                    let (x, y) = edge_stack.pop().unwrap();
                    block_nodes.push(x);
                    block_nodes.push(y);
                    if x == u as u32 && y == v_u32 { break; }
                }

                // Deduplicate nodes to avoid multi-edges in BCT
                block_nodes.sort_unstable();
                block_nodes.dedup();

                for &node in &block_nodes {
                    bct_adj[node as usize].push(blk);
                    bct_adj[blk as usize].push(node);
                }
            }
        }
    }
}

// Disjoint Set Union (DSU) for component tracking
struct Dsu {
    parent: Vec<usize>,
}
impl Dsu {
    fn new(n: usize) -> Self {
        Self { parent: (0..=n).collect() }
    }
    fn find(&mut self, i: usize) -> usize {
        if self.parent[i] != i {
            self.parent[i] = self.find(self.parent[i]);
        }
        self.parent[i]
    }
    fn union(&mut self, i: usize, j: usize) {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i] = root_j;
        }
    }
}

// Lowest Common Ancestor (LCA) Preprocessing
struct Lca {
    tin: Vec<u32>,
    tout: Vec<u32>,
    depth: Vec<u32>,
    up: Vec<[u32; MAX_LOG]>,
}

impl Lca {
    fn new(adj: &Vec<Vec<u32>>, root: usize, n: usize) -> Self {
        let mut tin = vec![0; n + 1];
        let mut tout = vec![0; n + 1];
        let mut depth = vec![0; n + 1];
        let mut up = vec![[0; MAX_LOG]; n + 1];
        let mut timer = 0;

        // Iterative DFS could be used, but recursive is fine with large stack
        Self::dfs(root, 0, 0, &mut timer, adj, &mut tin, &mut tout, &mut depth, &mut up);

        Self { tin, tout, depth, up }
    }

    fn dfs(u: usize, p: usize, d: u32, timer: &mut u32, adj: &Vec<Vec<u32>>, 
           tin: &mut Vec<u32>, tout: &mut Vec<u32>, depth: &mut Vec<u32>, up: &mut Vec<[u32; MAX_LOG]>) {
        *timer += 1;
        tin[u] = *timer;
        depth[u] = d;
        up[u][0] = p as u32;
        for i in 1..MAX_LOG {
            let anc = up[u][i-1] as usize;
            if anc != 0 {
                up[u][i] = up[anc][i-1];
            }
        }

        for &v_u32 in &adj[u] {
            let v = v_u32 as usize;
            if v != p {
                Self::dfs(v, u, d + 1, timer, adj, tin, tout, depth, up);
            }
        }
        tout[u] = *timer;
    }

    #[inline]
    fn is_ancestor(&self, u: u32, v: u32) -> bool {
        if u == 0 { return true; } // 0 is root's parent
        let u = u as usize;
        let v = v as usize;
        self.tin[u] <= self.tin[v] && self.tout[u] >= self.tout[v]
    }

    fn lca(&self, u: u32, v: u32) -> u32 {
        if self.is_ancestor(u, v) { return u; }
        if self.is_ancestor(v, u) { return v; }
        let mut curr = u as usize;
        for i in (0..MAX_LOG).rev() {
            let next = self.up[curr][i];
            if next != 0 && !self.is_ancestor(next, v) {
                curr = next as usize;
            }
        }
        self.up[curr][0]
    }
}

// Fast Scanner
struct Scanner<'a> {
    input: &'a [u8],
    pos: usize,
}

