    // Preallocate adjacency for BCT. Safe upper bound is N + E + 1.
    let mut bct_adj = vec![vec![]; n + e + 1]; 
    let mut num_blocks = 0;
    let mut stack_edges = Vec::with_capacity(e);
    let mut marker = vec![0; n + 1]; // Tracks which block a node was last added to

