            let b = scanner.next_u32();
            let c = scanner.next_u32();
            queries.push((2, a, b, c, 0));
        }
    }

    let results: Vec<&'static str> = queries.par_iter().map(|&(t, a, b, g1, g2)| {
        if t == 1 {
            let ca = comp_id[a as usize];
            let cb = comp_id[b as usize];
            let cg1 = comp_id[g1 as usize];
            let cg2 = comp_id[g2 as usize];

