    let mut out = std::io::BufWriter::new(stdout.lock());
    for res in results {
        out.write_all(res.as_bytes()).unwrap();
        out.write_all(b"\n").unwrap();
    }
}

fn bridge_dfs(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>, 
              adj: &Vec<Vec<u32>>, bridges: &mut Vec<(u32, u32)>) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v in &adj[u] {
        let v_usize = v as usize;
        if v_usize == p { continue; }
        if tin[v_usize] != 0 {
            low[u] = min(low[u], tin[v_usize]);
        } else {
            bridge_dfs(v_usize, u, timer, tin, low, adj, bridges);
            low[u] = min(low[u], low[v_usize]);
            if low[v_usize] > tin[u] {
                bridges.push((min(u as u32, v), max(u as u32, v)));
            }
        }
    }
}

fn bct_dfs(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>,
           adj: &Vec<Vec<u32>>, bct_adj: &mut Vec<Vec<u32>>, num_blocks: &mut usize,
           stack_edges: &mut Vec<(u32, u32)>, marker: &mut Vec<usize>, n: usize) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v in &adj[u] {
        let v_usize = v as usize;
        if v_usize == p { continue; }
        if tin[v_usize] != 0 {
            low[u] = min(low[u], tin[v_usize]);
            if tin[v_usize] < tin[u] {
                stack_edges.push((u as u32, v));
            }
        } else {
            stack_edges.push((u as u32, v));
            bct_dfs(v_usize, u, timer, tin, low, adj, bct_adj, num_blocks, stack_edges, marker, n);
            low[u] = min(low[u], low[v_usize]);
            if low[v_usize] >= tin[u] {
                *num_blocks += 1;
                let blk_idx = n + *num_blocks;

                // Ensure space (though preallocated, safety check)
                if bct_adj.len() <= blk_idx {
                    bct_adj.resize(blk_idx + 1, vec![]);
                }

                // Add u to block if not already added for this block
                if marker[u] != *num_blocks {
                    marker[u] = *num_blocks;
                    bct_adj[u].push(blk_idx as u32);
                    bct_adj[blk_idx].push(u as u32);
