                // Add other nodes in the biconnected component from stack
                loop {
                    let (x, y) = stack_edges.pop().unwrap();
                    let x_idx = x as usize;
                    let y_idx = y as usize;

                    if marker[x_idx] != *num_blocks {
                        marker[x_idx] = *num_blocks;
                        bct_adj[x_idx].push(blk_idx as u32);
                        bct_adj[blk_idx].push(x);
                    }
                    if marker[y_idx] != *num_blocks {
                        marker[y_idx] = *num_blocks;
                        bct_adj[y_idx].push(blk_idx as u32);
                        bct_adj[blk_idx].push(y);
                    }

                    if x == u as u32 && y == v { break; }
                }
            }
        }
    }
