fn find_bridges(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>, 
                adj: &Vec<Vec<u32>>, bridges: &mut Vec<(u32, u32)>) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v_u32 in &adj[u] {
        let v = v_u32 as usize;
        if v == p { continue; }
        if tin[v] != 0 {
            low[u] = min(low[u], tin[v]);
        } else {
            find_bridges(v, u, timer, tin, low, adj, bridges);
            low[u] = min(low[u], low[v]);
            if low[v] > tin[u] {
                bridges.push((min(u as u32, v_u32), max(u as u32, v_u32)));
            }
        }
    }
}

fn build_bct(u: usize, p: usize, timer: &mut u32, tin: &mut Vec<u32>, low: &mut Vec<u32>,
             adj: &Vec<Vec<u32>>, bct_adj: &mut Vec<Vec<u32>>, num_blocks: &mut usize,
             edge_stack: &mut Vec<(usize, usize)>, marker: &mut Vec<usize>, n: usize) {
    *timer += 1;
    tin[u] = *timer;
    low[u] = *timer;

    for &v_u32 in &adj[u] {
        let v = v_u32 as usize;
        if v == p { continue; }

        if tin[v] != 0 {
            low[u] = min(low[u], tin[v]);
            if tin[v] < tin[u] {
                edge_stack.push((u, v));
            }
        } else {
            edge_stack.push((u, v));
            build_bct(v, u, timer, tin, low, adj, bct_adj, num_blocks, edge_stack, marker, n);
            low[u] = min(low[u], low[v]);

            if low[v] >= tin[u] {
                *num_blocks += 1;
                let blk_idx = n + *num_blocks;

                if bct_adj.len() <= blk_idx {
                    bct_adj.resize(blk_idx + 1, Vec::new());
                }

                let mut add_bct_edge = |node: usize, blk: usize| {
                    if marker[node] != blk {
                        marker[node] = blk;
                        bct_adj[node].push(blk as u32);
                        bct_adj[blk].push(node as u32);
                    }
                };

                loop {
                    let (x, y) = edge_stack.pop().unwrap();
                    add_bct_edge(x, blk_idx);
                    add_bct_edge(y, blk_idx);
                    if x == u && y == v { break; }
                }
            }
