use std::io::{self, Read};
use rayon::prelude::*;

#[derive(Clone, Debug, PartialEq, Eq, Hash)]
struct Partition {
    mapping: Vec<u8>,
}

#[derive(Clone, Copy, Debug)]
struct Group {
    count: u64,
    sum_complexity: u64,
}

struct Grid {
    rows: Vec<u64>,
    n: usize,
    m: usize,
}

struct Dsu {
    parent: Vec<u8>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n as u8).collect(),
        }
    }

    #[inline(always)]
    fn find(&mut self, i: u8) -> u8 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize(ids: &[u8]) -> Partition {
    let mut mapping = vec![0u8; ids.len()];
    let mut map = [0u8; 256];
    let mut next = 1;
    for (i, &id) in ids.iter().enumerate() {
        if id != 0 {
            if map[id as usize] == 0 {
                map[id as usize] = next;
                next += 1;
            }
            mapping[i] = map[id as usize];
        }
    }
    Partition { mapping }
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> Vec<(Partition, Group)> {
    let m = grid.m;
    let mut results = Vec::new();

    let rows: Vec<usize> = if is_up {
        (end_row..=start_row).rev().collect()
    } else {
        (start_row..=end_row).collect()
    };

    if rows.is_empty() {
        return results;
    }

    let first_row_idx = rows[0];
    let row_val = grid.rows[first_row_idx];

    let mut interface_ids = vec![0u8; m];
    let mut active_ids = vec![0u8; m];
    let mut current_complexity;

    let mut dsu = Dsu::new(m + 1);

    for c in 0..m {
        if (row_val >> c) & 1 == 1 {
            interface_ids[c] = (c + 1) as u8;
            active_ids[c] = (c + 1) as u8;
            if c > 0 && (row_val >> (c - 1)) & 1 == 1 {
                dsu.union(interface_ids[c - 1], interface_ids[c]);
            }
        }
    }

    let mut max_id = 0;
    for c in 0..m {
        if interface_ids[c] != 0 {
            let root = dsu.find(interface_ids[c]);
            interface_ids[c] = root;
            active_ids[c] = root;
            if root > max_id { max_id = root; }
        }
    }

    let mut unique_roots = 0;
    let mut seen = [false; 256];
    for &id in &interface_ids {
        if id != 0 && !seen[id as usize] {
            seen[id as usize] = true;
            unique_roots += 1;
        }
    }
    current_complexity = unique_roots;

    let p = canonicalize(&interface_ids);
    results.push((p, Group { count: 1, sum_complexity: current_complexity }));

    for &r in rows.iter().skip(1) {
        let row_val = grid.rows[r];
        let mut new_active_ids = vec![0u8; m];
        let mut new_grass = 0;

        let mut max_current_id = 0;
        for &id in &active_ids { if id > max_current_id { max_current_id = id; } }
        for &id in &interface_ids { if id > max_current_id { max_current_id = id; } }

        let mut next_id = max_current_id + 1;

        for c in 0..m {
            if (row_val >> c) & 1 == 1 {
                new_active_ids[c] = next_id;
                next_id += 1;
                new_grass += 1;
            }
        }

        let mut step_dsu = Dsu::new(next_id as usize + 1);

        let mut merges = 0;
        for c in 0..m {
            if new_active_ids[c] != 0 {
                if c > 0 && new_active_ids[c - 1] != 0 {
                    if step_dsu.union(new_active_ids[c - 1], new_active_ids[c]) {
                        merges += 1;
                    }
                }
            }
        }

        for c in 0..m {
            if new_active_ids[c] != 0 && active_ids[c] != 0 {
                if step_dsu.union(new_active_ids[c], active_ids[c]) {
                    merges += 1;
                }
            }
        }

        current_complexity = current_complexity + new_grass - merges;

        let mut mapping = [0u8; 256];
        let mut next_small_id = 1;

        for c in 0..m {
            if interface_ids[c] != 0 {
                let root = step_dsu.find(interface_ids[c]);
                if mapping[root as usize] == 0 {
                    mapping[root as usize] = next_small_id;
                    next_small_id += 1;
                }
                interface_ids[c] = mapping[root as usize];
            }
        }

        for c in 0..m {
            if new_active_ids[c] != 0 {
                let root = step_dsu.find(new_active_ids[c]);
                if mapping[root as usize] == 0 {
                    mapping[root as usize] = next_small_id;
                    next_small_id += 1;
                }
                new_active_ids[c] = mapping[root as usize];
            }
        }

        active_ids = new_active_ids;

        let p = canonicalize(&interface_ids);

        if let Some(last) = results.last_mut() {
            if last.0 == p {
                last.1.count += 1;
                last.1.sum_complexity += current_complexity;
            } else {
                results.push((p, Group { count: 1, sum_complexity: current_complexity }));
            }
        } else {
            results.push((p, Group { count: 1, sum_complexity: current_complexity }));
        }
    }

    results
}

fn count_merges(p1: &Partition, p2: &Partition) -> u64 {
    let mut max_1 = 0;
    for &x in &p1.mapping { if x > max_1 { max_1 = x; } }
    let mut max_2 = 0;
    for &x in &p2.mapping { if x > max_2 { max_2 = x; } }

    if max_1 == 0 || max_2 == 0 { return 0; }

    let offset = max_1;
    let mut dsu = Dsu::new((offset + max_2 + 1) as usize);
    let mut merges = 0;

    for c in 0..p1.mapping.len() {
        let u = p1.mapping[c];
        let v = p2.mapping[c];
        if u != 0 && v != 0 {
            if dsu.union(u, v + offset) {
                merges += 1;
            }
        }
    }
    merges
}

fn solve(r1: usize, r2: usize, grid: &Grid) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let row_val = grid.rows[r1];
        let mut comps = 0;
        let mut in_comp = false;
        for c in 0..grid.m {
            if (row_val >> c) & 1 == 1 {
                if !in_comp {
                    comps += 1;
                    in_comp = true;
                }
            } else {
                in_comp = false;
            }
        }
        return comps;
    }

    let mid = (r1 + r2) / 2;

    let (left_res, right_res) = rayon::join(
        || solve(r1, mid, grid),
        || solve(mid + 1, r2, grid)
    );

    let mut total = left_res + right_res;

    let left_groups = scan(grid, mid, r1, true);
    let right_groups = scan(grid, mid + 1, r2, false);

    let mut sum_count_r = 0;
    let mut sum_comp_r = 0;
    for (_, g) in &right_groups {
        sum_count_r += g.count;
        sum_comp_r += g.sum_complexity;
    }

    let mut sum_count_l = 0;
    let mut sum_comp_l = 0;
    for (_, g) in &left_groups {
        sum_count_l += g.count;
        sum_comp_l += g.sum_complexity;
    }

    total += sum_comp_l * sum_count_r;
    total += sum_comp_r * sum_count_l;

    for (p_l, g_l) in &left_groups {
        for (p_r, g_r) in &right_groups {
            let merges = count_merges(p_l, p_r);
            total -= merges * g_l.count * g_r.count;
        }
    }

    total
}

