struct Dsu {
    parent: Vec<u8>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n as u8).collect(),
        }
    }

    #[inline(always)]
    fn find(&mut self, i: u8) -> u8 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize(ids: &[u8]) -> Partition {
    let mut mapping = vec![0u8; ids.len()];
    let mut map = [0u8; 256];
    let mut next = 1;
    for (i, &id) in ids.iter().enumerate() {
        if id != 0 {
            if map[id as usize] == 0 {
                map[id as usize] = next;
                next += 1;
            }
            mapping[i] = map[id as usize];
        }
    }
    Partition { mapping }
}

