        for c in 0..m {
            if new_ids[c] != 0 {
                let root = dsu.find(new_ids[c]);
                if map_buf[root as usize] == 0 {
                    map_buf[root as usize] = next_k;
                    next_k += 1;
                }
                new_ids[c] = map_buf[root as usize];
            }
        }

        current_ids.copy_from_slice(&new_ids);
        max_active_id = next_k - 1;

        if let Some(last) = groups_map.last_mut() {
            if last.partition.mapping == boundary_ids {
                last.count += 1;
                last.sum_complexity += current_complexity;
            } else {
                groups_map.push(Group {
                    partition: Partition { mapping: boundary_ids.clone() },
                    count: 1,
                    sum_complexity: current_complexity,
                });
            }
        } else {
            groups_map.push(Group {
                partition: Partition { mapping: boundary_ids.clone() },
                count: 1,
                sum_complexity: current_complexity,
            });
        }
    }

    groups_map.sort_unstable_by(|a, b| a.partition.cmp(&b.partition));

    let mut merged_groups = Vec::with_capacity(groups_map.len());
    if !groups_map.is_empty() {
        let mut cur = groups_map[0].clone();
        for next in groups_map.into_iter().skip(1) {
            if cur.partition == next.partition {
                cur.count += next.count;
                cur.sum_complexity += next.sum_complexity;
            } else {
                merged_groups.push(cur);
                cur = next;
            }
        }
        merged_groups.push(cur);
    }

    merged_groups
}

fn count_merges(p_l: &Partition, p_r: &Partition, m: usize) -> u64 {
    let mut max_l = 0;
    for &x in &p_l.mapping { if x > max_l { max_l = x; } }

    let mut max_r = 0;
    for &x in &p_r.mapping { if x > max_r { max_r = x; } }

    if max_l == 0 || max_r == 0 { return 0; }

    let offset = max_l;
    let size = (offset + max_r + 1) as usize;

    let mut parent = [0u8; 128];
    for i in 0..size {
        parent[i] = i as u8;
    }

    let mut merges = 0;

    for c in 0..m {
        let u = p_l.mapping[c];
        let v = p_r.mapping[c];

        if u != 0 && v != 0 {
            let v_shifted = v + offset;

            let mut root_u = u;
            while root_u != parent[root_u as usize] {
                root_u = parent[root_u as usize];
            }
            let mut curr = u;
            while curr != root_u {
                let next = parent[curr as usize];
                parent[curr as usize] = root_u;
                curr = next;
            }

            let mut root_v = v_shifted;
            while root_v != parent[root_v as usize] {
                root_v = parent[root_v as usize];
            }
            let mut curr = v_shifted;
            while curr != root_v {
                let next = parent[curr as usize];
                parent[curr as usize] = root_v;
                curr = next;
            }

            if root_u != root_v {
                parent[root_u as usize] = root_v;
                merges += 1;
            }
        }
    }
    merges
}

fn solve(grid: &Grid, r1: usize, r2: usize) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let offset = r1 * grid.m;
        let row_data = &grid.data[offset..offset + grid.m];
        let mut comps = 0;
        let mut in_comp = false;
        for &cell in row_data {
            if cell == 1 {
                if !in_comp {
                    comps += 1;
                    in_comp = true;
                }
            } else {
                in_comp = false;
            }
        }
        return comps;
    }

    let mid = (r1 + r2) / 2;

    let (left_res, right_res) = rayon::join(
        || solve(grid, r1, mid),
        || solve(grid, mid + 1, r2)
    );

    let mut total = left_res + right_res;

    let left_groups = scan(grid, mid, r1, true);
    let right_groups = scan(grid, mid + 1, r2, false);

    let mut sum_count_l = 0;
    let mut sum_comp_l = 0;
    for g in &left_groups {
        sum_count_l += g.count;
        sum_comp_l += g.sum_complexity;
    }

    let mut sum_count_r = 0;
    let mut sum_comp_r = 0;
    for g in &right_groups {
        sum_count_r += g.count;
        sum_comp_r += g.sum_complexity;
    }

    total += sum_comp_l * sum_count_r;
    total += sum_comp_r * sum_count_l;

    let merge_deduction: u64 = left_groups.par_iter().map(|g_l| {
        let mut sub = 0;
        for g_r in &right_groups {
            let merges = count_merges(&g_l.partition, &g_r.partition, grid.m);
            if merges > 0 {
                sub += merges * g_l.count * g_r.count;
            }
        }
        sub
    }).sum();

    total -= merge_deduction;

    total
}

