use std::cmp::Ordering;

const MAX_M: usize = 50;

#[derive(Clone, Copy, Debug)]
struct Partition {
    mapping: [u8; MAX_M],
    max_id: u8,
}

impl PartialEq for Partition {
    #[inline]
    fn eq(&self, other: &Self) -> bool {
        self.mapping[..] == other.mapping[..]
    }
}
impl Eq for Partition {}

impl PartialOrd for Partition {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        self.mapping[..].partial_cmp(&other.mapping[..])
    }
}
impl Ord for Partition {
    fn cmp(&self, other: &Self) -> Ordering {
        self.mapping[..].cmp(&other.mapping[..])
    }
}

#[derive(Clone, Debug)]
struct Group {
    partition: Partition,
    count: u64,
    sum_complexity: u64,
}

struct Grid {
    rows: Vec<u64>,
    n: usize,
    m: usize,
}

struct TinyDsu {
    parent: [u8; 128],
}

impl TinyDsu {
    #[inline(always)]
    fn new() -> Self {
        let mut p = [0u8; 128];
        for i in 0..128 { p[i] = i as u8; }
        TinyDsu { parent: p }
    }

    #[inline(always)]
    fn init(&mut self, n: u8) {
        for i in 0..n as usize {
            self.parent[i] = i as u8;
        }
    }

    #[inline(always)]
    fn find(&mut self, i: u8) -> u8 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize(ids: &[u8], m: usize, buf: &mut [u8; MAX_M]) -> u8 {
    let mut map = [0u8; 128];
    let mut next = 1;
    let mut max_id = 0;

    for i in 0..m {
        let id = ids[i];
        if id != 0 {
            let idx = id as usize;
            if map[idx] == 0 {
                map[idx] = next;
                next += 1;
            }
            let new_val = map[idx];
            buf[i] = new_val;
            if new_val > max_id { max_id = new_val; }
        } else {
            buf[i] = 0;
        }
    }
    for i in m..MAX_M {
        buf[i] = 0;
    }
    max_id
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> Vec<Group> {
