use std::io::{self, Read};
use std::collections::HashMap;
use rayon::prelude::*;

#[derive(Clone, Debug, PartialEq, Eq, Hash)]
struct Partition {
    mapping: Vec<i8>, // -1 for no grass, 0..k for sets
}

// DSU with path compression
struct Dsu {
    parent: Vec<usize>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n).collect(),
        }
    }

    fn find(&mut self, i: usize) -> usize {
        if self.parent[i] != i {
            self.parent[i] = self.find(self.parent[i]);
        }
        self.parent[i]
    }

    fn union(&mut self, i: usize, j: usize) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i] = root_j;
            true
        } else {
            false
        }
    }
}

fn solve(r1: usize, r2: usize, m: usize, grid: &[u8]) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let mut comps = 0;
        let start = r1 * m;
        for c in 0..m {
            if grid[start + c] == 1 {
                if c == 0 || grid[start + c - 1] == 0 {
                    comps += 1;
                }
            }
        }
        return comps;
    }

    let mid = (r1 + r2) / 2;

    let (left_res, right_res) = rayon::join(
        || solve(r1, mid, m, grid),
        || solve(mid + 1, r2, m, grid)
    );

    let mut total = left_res + right_res;

    // Scan Up
    let (left_sum_comp, left_counts) = scan(mid, r1, m, grid, true);
    // Scan Down
    let (right_sum_comp, right_counts) = scan(mid + 1, r2, m, grid, false);

    let count_l: u64 = left_counts.iter().map(|(_, c)| c).sum();
    let count_r: u64 = right_counts.iter().map(|(_, c)| c).sum();

    total += left_sum_comp * count_r;
    total += right_sum_comp * count_l;

    // Subtract merges
    for (p_l, c_l) in &left_counts {
        for (p_r, c_r) in &right_counts {
            let merges = count_merges(p_l, p_r, m, grid, mid);
            if merges > 0 {
                total -= (merges as u64) * c_l * c_r;
            }
        }
    }

    total
}

fn scan(start_row: usize, end_row: usize, m: usize, grid: &[u8], is_up: bool) -> (u64, Vec<(Partition, u64)>) {
    let mut groups: HashMap<Partition, u64> = HashMap::new();
    let mut total_comp_sum = 0;

    let rows: Vec<usize> = if is_up {
        (end_row..=start_row).rev().collect()
    } else {
        (start_row..=end_row).collect()
    };

    // DSU state on 2*m elements: 0..m (Current Row), m..2m (Fixed Boundary Row)
    // Initially Current == Fixed
    let mut dsu = Dsu::new(2 * m);
    let mut current_comp = 0;

    // Initialize for start_row
    let row_off = start_row * m;
    let mut grass_count = 0;
    let mut merges = 0;

    // For the first row, we treat it as being both Current and Fixed.
    for c in 0..m {
        if grid[row_off + c] == 1 {
            grass_count += 1;
            dsu.union(c, m + c);
            if c > 0 && grid[row_off + c - 1] == 1 {
                if dsu.union(c - 1, c) { merges += 1; }
                dsu.union(m + c - 1, m + c); // Redundant but keeps consistency
            }
        }
    }
    current_comp = grass_count - merges;

    // Canonicalize partition of Fixed Boundary (indices m..2m)
    let mut part = Partition { mapping: vec![-1; m] };
    let mut root_map = vec![-1i8; 2 * m];
    let mut next_id = 0;

    for c in 0..m {
        if grid[row_off + c] == 1 {
            let r = dsu.find(m + c);
            if root_map[r] == -1 {
                root_map[r] = next_id;
                next_id += 1;
            }
            part.mapping[c] = root_map[r];
        }
    }

    *groups.entry(part).or_insert(0) += 1;
    total_comp_sum += current_comp;

    let mut prev_row = start_row;

    // Iterate subsequent rows
    for &r in rows.iter().skip(1) {
        let r_off = r * m;
        let prev_off = prev_row * m;

        let mut next_dsu = Dsu::new(2 * m);
        let mut temp_dsu = Dsu::new(3 * m);

        // Copy current connections to temp_dsu
        for i in 0..2*m {
            let p = dsu.find(i);
            temp_dsu.union(i, p);
        }

        let mut r_grass = 0;
        let mut r_h_merges = 0;
        let mut v_merges = 0;

        for c in 0..m {
            if grid[r_off + c] == 1 {
                r_grass += 1;
                // Horizontal in new row (indices 2m..3m in temp_dsu)
                if c > 0 && grid[r_off + c - 1] == 1 {
                    if temp_dsu.union(2*m + c - 1, 2*m + c) {
                        r_h_merges += 1;
                    }
                }
                // Vertical to previous row (indices 0..m in temp_dsu)
                if grid[prev_off + c] == 1 {
                    if temp_dsu.union(2*m + c, c) {
                        v_merges += 1;
                    }
                }
            }
        }

        current_comp = current_comp + r_grass - r_h_merges - v_merges;
        total_comp_sum += current_comp;

        // Map temp_dsu (2m..3m -> 0..m, m..2m -> m..2m) to next_dsu
        let mut root_mapping = HashMap::new();

        for c in 0..m {
            // New Current (r) -> 0..m
            if grid[r_off + c] == 1 {
                let root = temp_dsu.find(2*m + c);
                if !root_mapping.contains_key(&root) {
                    root_mapping.insert(root, c); 
                }
                let rep = root_mapping[&root];
                next_dsu.union(c, rep);
            }

            // Fixed (start_row) -> m..2m
            if grid[row_off + c] == 1 {
                let root = temp_dsu.find(m + c);
                if !root_mapping.contains_key(&root) {
                    root_mapping.insert(root, m + c);
                }
                let rep = root_mapping[&root];
                next_dsu.union(m + c, rep);
            }
        }

        dsu = next_dsu;
        prev_row = r;

        // Extract partition of Fixed (m..2m)
        let mut part = Partition { mapping: vec![-1; m] };
        let mut root_map = vec![-1i8; 2 * m];
        let mut next_id = 0;

        for c in 0..m {
            if grid[row_off + c] == 1 {
                let r_node = dsu.find(m + c);
                if root_map[r_node] == -1 {
                    root_map[r_node] = next_id;
                    next_id += 1;
                }
                part.mapping[c] = root_map[r_node];
            }
        }

        *groups.entry(part).or_insert(0) += 1;
    }

    (total_comp_sum, groups.into_iter().collect())
}

fn count_merges(p1: &Partition, p2: &Partition, m: usize, grid: &[u8], mid: usize) -> u32 {
    let mut dsu = Dsu::new(2 * m + 200); 
    let offset = m + 50;
    let mut merges = 0;

    let r1_off = mid * m;
    let r2_off = (mid + 1) * m;

