use std::io::{self, Read};
use rayon::prelude::*;
use std::cmp::Ordering;

// Fixed constants
const MAX_M: usize = 50;
const DSU_SIZE: usize = 128; // Sufficient for 2 rows of width 50 (50+50+padding)

#[derive(Clone, Copy, Debug, Eq, Hash)]
struct Partition {
    mapping: [u8; MAX_M],
    max_id: u8,
}

impl PartialEq for Partition {
    #[inline]
    fn eq(&self, other: &Self) -> bool {
        self.mapping[..] == other.mapping[..]
    }
}

impl PartialOrd for Partition {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Partition {
    fn cmp(&self, other: &Self) -> Ordering {
        self.mapping.cmp(&other.mapping)
    }
}

#[derive(Clone, Copy)]
struct Group {
    count: u64,
    sum_complexity: u64,
}

struct Grid {
    rows: Vec<u64>, // Each row is a bitmask. m <= 50 fits in u64.
    n: usize,
    m: usize,
}

struct TinyDsu {
    parent: [u8; DSU_SIZE],
}

impl TinyDsu {
    #[inline(always)]
    fn new() -> Self {
        let mut p = [0u8; DSU_SIZE];
        for i in 0..DSU_SIZE {
            p[i] = i as u8;
        }
        TinyDsu { parent: p }
    }

    #[inline(always)]
    fn init(&mut self, n: u8) {
        let limit = n as usize;
        if limit <= DSU_SIZE {
            for i in 0..limit {
                self.parent[i] = i as u8;
            }
        } else {
             for i in 0..DSU_SIZE { self.parent[i] = i as u8; }
        }
    }

    #[inline(always)]
    fn find(&mut self, i: u8) -> u8 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize_into(ids: &[u8], m: usize, out: &mut Partition) {
    let mut map = [0u8; DSU_SIZE];
    let mut next = 1;
    let mut max_id = 0;

    for i in 0..m {
        let id = ids[i];
        if id == 0 {
            out.mapping[i] = 0;
        } else {
            let idx = id as usize;
            if map[idx] == 0 {
                map[idx] = next;
                next += 1;
            }
            let new_val = map[idx];
            out.mapping[i] = new_val;
            if new_val > max_id { max_id = new_val; }
        }
    }
    for i in m..MAX_M {
        out.mapping[i] = 0;
    }
    out.max_id = max_id;
}

fn count_merges(p1: &Partition, p2: &Partition, m: usize) -> u64 {
    let max_1 = p1.max_id;
    let max_2 = p2.max_id;

    if max_1 == 0 || max_2 == 0 { return 0; }

    let offset = max_1;
    let size = (offset + max_2 + 1) as usize;

    let mut parent = [0u8; DSU_SIZE];
    for i in 0..size {
        parent[i] = i as u8;
    }

    let mut merges = 0;
    for c in 0..m {
        let u = p1.mapping[c];
        let v = p2.mapping[c];

        if u != 0 && v != 0 {
            let v_shifted = v + offset;

            let mut root_u = u;
            while root_u != parent[root_u as usize] {
                root_u = parent[root_u as usize];
            }
            let mut curr = u;
            while curr != root_u {
                let next = parent[curr as usize];
                parent[curr as usize] = root_u;
                curr = next;
            }

            let mut root_v = v_shifted;
            while root_v != parent[root_v as usize] {
                root_v = parent[root_v as usize];
            }
            let mut curr = v_shifted;
            while curr != root_v {
                let next = parent[curr as usize];
                parent[curr as usize] = root_v;
                curr = next;
            }

            if root_u != root_v {
                parent[root_u as usize] = root_v;
                merges += 1;
            }
        }
    }
    merges
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> Vec<(Partition, Group)> {
    let m = grid.m;
    let len = if is_up { start_row + 1 - end_row } else { end_row + 1 - start_row };
    let mut results = Vec::with_capacity(len);

    let mut dsu = TinyDsu::new();
    let mut interface_ids = [0u8; MAX_M];
    let mut active_ids = [0u8; MAX_M];
    let mut temp_part = Partition { mapping: [0; MAX_M], max_id: 0 };

    let row_val = grid.rows[start_row];
    dsu.init((m + 1) as u8);
    let mut grass_count = 0;
    let mut merges = 0;

    for c in 0..m {
        if (row_val >> c) & 1 == 1 {
            interface_ids[c] = (c + 1) as u8;
            active_ids[c] = (c + 1) as u8;
            grass_count += 1;
            if c > 0 && (row_val >> (c - 1)) & 1 == 1 {
                if dsu.union(interface_ids[c-1], interface_ids[c]) {
                    merges += 1;
                }
            }
        } else {
            interface_ids[c] = 0;
            active_ids[c] = 0;
        }
    }

    for c in 0..m {
        if interface_ids[c] != 0 {
            interface_ids[c] = dsu.find(interface_ids[c]);
        }
    }

    canonicalize_into(&interface_ids[0..m], m, &mut temp_part);
    for c in 0..m {
        interface_ids[c] = temp_part.mapping[c];
        active_ids[c] = temp_part.mapping[c];
    }
    let mut max_id = temp_part.max_id;
    let mut current_complexity = grass_count - merges;

    results.push((temp_part, Group { count: 1, sum_complexity: current_complexity }));

    let mut curr_r = start_row;
    let count = len - 1;

    for _ in 0..count {
        if is_up { curr_r -= 1; } else { curr_r += 1; }
        let row_val = grid.rows[curr_r];

        let mut new_ids = [0u8; MAX_M];
        let mut next_assign = max_id;
        let mut row_grass = 0;

        for c in 0..m {
            if (row_val >> c) & 1 == 1 {
                next_assign += 1;
                new_ids[c] = next_assign;
                row_grass += 1;
            }
        }

        dsu.init(next_assign + 1);
        let mut step_merges = 0;

        for c in 0..m {
            if new_ids[c] != 0 {
                if c > 0 && new_ids[c-1] != 0 {
                    if dsu.union(new_ids[c-1], new_ids[c]) {
                        step_merges += 1;
                    }
                }
            }
        }

        for c in 0..m {
            if new_ids[c] != 0 && active_ids[c] != 0 {
                if dsu.union(new_ids[c], active_ids[c]) {
                    step_merges += 1;
                }
            }
        }

        current_complexity = current_complexity + row_grass - step_merges;

        let mut map = [0u8; DSU_SIZE];
        let mut next_k = 1;

        for c in 0..m {
            if interface_ids[c] != 0 {
                let root = dsu.find(interface_ids[c]);
                if map[root as usize] == 0 {
                    map[root as usize] = next_k;
                    next_k += 1;
                }
                interface_ids[c] = map[root as usize];
            }
        }

        for c in 0..m {
            if new_ids[c] != 0 {
                let root = dsu.find(new_ids[c]);
                if map[root as usize] == 0 {
                    map[root as usize] = next_k;
                    next_k += 1;
                }
                new_ids[c] = map[root as usize];
            }
        }

        active_ids = new_ids;
        max_id = next_k - 1;

        canonicalize_into(&interface_ids[0..m], m, &mut temp_part);

        if let Some(last) = results.last_mut() {
            if last.0 == temp_part {
                last.1.count += 1;
                last.1.sum_complexity += current_complexity;
            } else {
                results.push((temp_part, Group { count: 1, sum_complexity: current_complexity }));
            }
        } else {
            results.push((temp_part, Group { count: 1, sum_complexity: current_complexity }));
        }
    }

    results.sort_unstable_by(|a, b| a.0.cmp(&b.0));

    let mut compacted = Vec::with_capacity(results.len());
    if !results.is_empty() {
        let mut cur = results[0];
        for next in results.into_iter().skip(1) {
            if cur.0 == next.0 {
                cur.1.count += next.1.count;
                cur.1.sum_complexity += next.1.sum_complexity;
            } else {
                compacted.push(cur);
                cur = next;
            }
        }
        compacted.push(cur);
    }

    compacted
}

fn solve(r1: usize, r2: usize, grid: &Grid) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let row_val = grid.rows[r1];
        let mut comps = 0;
        let mut in_comp = false;
        for c in 0..grid.m {
            if (row_val >> c) & 1 == 1 {
                if !in_comp {
                    comps += 1;
                    in_comp = true;
                }
            } else {
                in_comp = false;
            }
        }
        return comps;
    }

    let mid = (r1 + r2) / 2;

    let (left_res, right_res) = rayon::join(
        || solve(r1, mid, grid),
        || solve(mid + 1, r2, grid)
    );

    let mut total = left_res + right_res;

    let left_groups = scan(grid, mid, r1, true);
    let right_groups = scan(grid, mid + 1, r2, false);

    let mut sum_count_r = 0;
    let mut sum_comp_r = 0;
    for g in &right_groups {
        sum_count_r += g.1.count;
        sum_comp_r += g.1.sum_complexity;
    }

    let mut sum_count_l = 0;
    let mut sum_comp_l = 0;
    for g in &left_groups {
        sum_count_l += g.1.count;
        sum_comp_l += g.1.sum_complexity;
    }

    total += sum_comp_l * sum_count_r;
    total += sum_comp_r * sum_count_l;

    let merge_deduction: u64 = left_groups.par_iter().map(|(p_l, g_l)| {
        let mut local_sub = 0;
        for (p_r, g_r) in &right_groups {
            let merges = count_merges(p_l, p_r, grid.m);
            if merges > 0 {
                local_sub += merges * g_l.count * g_r.count;
            }
        }
        local_sub
    }).sum();

    total -= merge_deduction;

    total
}

fn main() {
    let builder = std::thread::Builder::new()
        .name("main".into())
        .stack_size(64 * 1024 * 1024);

    let handler = builder.spawn(|| {
        let mut input = String::new();
        io::stdin().read_to_string(&mut input).unwrap();
        let mut words = input.split_whitespace();

        let n_str = words.next();
        if n_str.is_none() { return; }
        let n: usize = n_str.unwrap().parse().unwrap();
        let m: usize = words.next().unwrap().parse().unwrap();

        let mut rows = Vec::with_capacity(n);
        for _ in 0..n {
            let s = words.next().unwrap();
            let mut row_val = 0u64;
            for (i, c) in s.chars().enumerate() {
                if c == '1' {
                    row_val |= 1 << i;
                }
            }
            rows.push(row_val);
        }

        let grid = Grid { rows, n, m };

        let result = solve(0, n - 1, &grid);
        println!("{}", result);
    }).unwrap();

    handler.join().unwrap();
}

