impl TinyDsu {
    fn new() -> Self {
        let mut p = [0u8; 128];
        for i in 0..128 {
            p[i] = i as u8;
        }
        TinyDsu { parent: p }
    }

    #[inline(always)]
    fn init(&mut self, n: usize) {
        for i in 0..n {
            self.parent[i] = i as u8;
        }
    }

    #[inline(always)]
    fn find(&mut self, i: u8) -> u8 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> Vec<Group> {
    let m = grid.m;
    let estimated_rows = if is_up { start_row - end_row + 1 } else { end_row - start_row + 1 };
    let mut groups_map: Vec<Group> = Vec::with_capacity(estimated_rows);

    let row_indices: Vec<usize> = if is_up {
        (end_row..=start_row).rev().collect()
    } else {
        (start_row..=end_row).collect()
    };

    if row_indices.is_empty() {
        return groups_map;
    }

    let mut dsu = TinyDsu::new();
    let mut boundary_ids = vec![0u8; m];
    let mut current_ids = vec![0u8; m];
    let mut new_ids = vec![0u8; m];
    let mut map_buf = [0u8; 128];

    let first_row = row_indices[0];
    let offset = first_row * m;
    let row_data = &grid.data[offset..offset + m];

    dsu.init(m + 1);
    let mut grass = 0;
    let mut merges = 0;

    for c in 0..m {
        if row_data[c] == 1 {
            current_ids[c] = (c + 1) as u8;
            grass += 1;
            if c > 0 && row_data[c-1] == 1 {
                if dsu.union(current_ids[c-1], current_ids[c]) {
                    merges += 1;
                }
            }
        } else {
            current_ids[c] = 0;
        }
    }

    for c in 0..m {
        if current_ids[c] != 0 {
            current_ids[c] = dsu.find(current_ids[c]);
        }
    }

    // Canonicalize initial row
    map_buf.fill(0);
    let mut next_id = 1;
    for c in 0..m {
        let id = current_ids[c];
        if id != 0 {
            if map_buf[id as usize] == 0 {
                map_buf[id as usize] = next_id;
                next_id += 1;
            }
            current_ids[c] = map_buf[id as usize];
        }
    }
    boundary_ids.copy_from_slice(&current_ids);
    let mut max_active_id = next_id - 1;

    let mut current_complexity = grass - merges;

    groups_map.push(Group {
        partition: Partition { mapping: boundary_ids.clone() },
        count: 1,
        sum_complexity: current_complexity,
    });

    for &r in row_indices.iter().skip(1) {
        let offset = r * m;
        let row_data = &grid.data[offset..offset + m];

        let mut next_assign = max_active_id;
        let mut row_grass = 0;

        for c in 0..m {
            if row_data[c] == 1 {
                next_assign += 1;
                new_ids[c] = next_assign;
                row_grass += 1;
            } else {
                new_ids[c] = 0;
            }
        }

        dsu.init(next_assign as usize + 1);

        let mut step_merges = 0;

        for c in 0..m {
            if new_ids[c] != 0 {
                if c > 0 && new_ids[c-1] != 0 {
                    if dsu.union(new_ids[c-1], new_ids[c]) {
                        step_merges += 1;
                    }
                }
            }
        }

        for c in 0..m {
            if new_ids[c] != 0 && current_ids[c] != 0 {
                if dsu.union(new_ids[c], current_ids[c]) {
                    step_merges += 1;
                }
            }
        }

        current_complexity = current_complexity + row_grass - step_merges;

        map_buf.fill(0);
        let mut next_k = 1;

        for c in 0..m {
            if boundary_ids[c] != 0 {
                let root = dsu.find(boundary_ids[c]);
                if map_buf[root as usize] == 0 {
                    map_buf[root as usize] = next_k;
                    next_k += 1;
                }
                boundary_ids[c] = map_buf[root as usize];
            }
        }

        for c in 0..m {
            if new_ids[c] != 0 {
                let root = dsu.find(new_ids[c]);
                if map_buf[root as usize] == 0 {
                    map_buf[root as usize] = next_k;
                    next_k += 1;
                }
                new_ids[c] = map_buf[root as usize];
            }
        }

        current_ids.copy_from_slice(&new_ids);
        max_active_id = next_k - 1;

        if let Some(last) = groups_map.last_mut() {
            if last.partition.mapping == boundary_ids {
                last.count += 1;
                last.sum_complexity += current_complexity;
            } else {
                groups_map.push(Group {
                    partition: Partition { mapping: boundary_ids.clone() },
                    count: 1,
                    sum_complexity: current_complexity,
                });
            }
        } else {
            groups_map.push(Group {
                partition: Partition { mapping: boundary_ids.clone() },
                count: 1,
                sum_complexity: current_complexity,
            });
        }
    }

    groups_map.sort_unstable_by(|a, b| a.partition.cmp(&b.partition));

    let mut merged_groups = Vec::with_capacity(groups_map.len());
    if !groups_map.is_empty() {
        let mut cur = groups_map[0].clone();
        for next in groups_map.into_iter().skip(1) {
            if cur.partition == next.partition {
                cur.count += next.count;
                cur.sum_complexity += next.sum_complexity;
            } else {
                merged_groups.push(cur);
                cur = next;
            }
        }
        merged_groups.push(cur);
    }

    merged_groups
}

fn count_merges(p_l: &Partition, p_r: &Partition, m: usize) -> u64 {
    let mut max_l = 0;
    for &x in &p_l.mapping { if x > max_l { max_l = x; } }

    let mut max_r = 0;
    for &x in &p_r.mapping { if x > max_r { max_r = x; } }

    if max_l == 0 || max_r == 0 { return 0; }

    let offset = max_l;
    let size = (offset + max_r + 1) as usize;

    let mut parent = [0u8; 128];
    for i in 0..size {
        parent[i] = i as u8;
    }

    let mut merges = 0;

    for c in 0..m {
        let u = p_l.mapping[c];
        let v = p_r.mapping[c];

        if u != 0 && v != 0 {
            let v_shifted = v + offset;

            let mut root_u = u;
            while root_u != parent[root_u as usize] {
                root_u = parent[root_u as usize];
            }
            let mut curr = u;
            while curr != root_u {
                let next = parent[curr as usize];
                parent[curr as usize] = root_u;
                curr = next;
            }

            let mut root_v = v_shifted;
            while root_v != parent[root_v as usize] {
                root_v = parent[root_v as usize];
            }
            let mut curr = v_shifted;
            while curr != root_v {
                let next = parent[curr as usize];
                parent[curr as usize] = root_v;
                curr = next;
            }

            if root_u != root_v {
                parent[root_u as usize] = root_v;
                merges += 1;
            }
        }
    }
    merges
}

fn solve(grid: &Grid, r1: usize, r2: usize) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let offset = r1 * grid.m;
        let row_data = &grid.data[offset..offset + grid.m];
        let mut comps = 0;
        let mut in_comp = false;
        for &cell in row_data {
