use std::io::{self, Read};
use rayon::prelude::*;

#[derive(Clone)]
struct Grid {
    rows: Vec<Vec<bool>>,
    n: usize,
    m: usize,
}

#[derive(Clone, PartialEq, Eq, Debug)]
struct Partition {
    mapping: Vec<u16>,
}

struct Dsu {
    parent: Vec<u16>,
}

impl Dsu {
    fn new(size: usize) -> Self {
        Dsu {
            parent: (0..size as u16).collect(),
        }
    }

    fn find(&mut self, i: u16) -> u16 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    fn union(&mut self, i: u16, j: u16) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

struct ScanResult {
    total_comps: u64,
    groups: Vec<(Partition, usize)>,
}

fn canonicalize(ids: &[u16]) -> Partition {
    let max_val = ids.iter().cloned().max().unwrap_or(0);
    let mut mapping = vec![0u16; (max_val + 1) as usize];
    let mut canon = Vec::with_capacity(ids.len());
    let mut next = 1;

    for &id in ids {
        if id == 0 {
            canon.push(0);
        } else {
            if mapping[id as usize] == 0 {
                mapping[id as usize] = next;
                next += 1;
            }
            canon.push(mapping[id as usize]);
        }
    }
    Partition { mapping: canon }
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> ScanResult {
    let m = grid.m;
    let mut total_comps = 0;
    let mut groups: Vec<(Partition, usize)> = Vec::new();

    let mut current_comps = 0;

    // Initialize for start_row
    // We use a DSU to correctly identify components in the single start_row
    let mut dsu = Dsu::new(m + 1);
    let mut row_ids = vec![0u16; m];

    let row_data = &grid.rows[start_row];
    for c in 0..m {
        if row_data[c] {
            row_ids[c] = (c + 1) as u16;
            if c > 0 && row_data[c-1] {
                dsu.union(row_ids[c-1], row_ids[c]);
            }
        }
    }

    // Normalize IDs to 1..k
    let mut mapping = vec![0u16; m + 2];
    let mut next_canon = 1;
    let mut final_row_ids = vec![0u16; m];

    for c in 0..m {
        if row_ids[c] != 0 {
            let root = dsu.find(row_ids[c]);
            if mapping[root as usize] == 0 {
                mapping[root as usize] = next_canon;
                next_canon += 1;
            }
            final_row_ids[c] = mapping[root as usize];
        }
    }

    current_comps = (next_canon - 1) as u64;
    let mut boundary_ids = final_row_ids.clone();
    let mut current_row_ids = final_row_ids;

    // Save first group
    total_comps += current_comps;
    groups.push((canonicalize(&boundary_ids), 1));

    let rows: Vec<usize> = if is_up {
        if start_row == end_row { return ScanResult { total_comps, groups }; }
        (end_row..start_row).rev().collect()
    } else {
        if start_row == end_row { return ScanResult { total_comps, groups }; }
        (start_row + 1..=end_row).collect()
    };

    let mut max_id = (next_canon - 1) as u16;

    for r in rows {
        let row_data = &grid.rows[r];

        // DSU size: current max_id + m new cells + 1 safety
        let dsu_size = (max_id as usize) + m + 1;
        let mut dsu = Dsu::new(dsu_size);

        let mut new_row_ids = vec![0u16; m];
        let mut new_grass_count = 0;

        // 1. Assign new IDs
        for c in 0..m {
            if row_data[c] {
                max_id += 1;
                new_row_ids[c] = max_id;
                new_grass_count += 1;
            }
        }

        let mut merges = 0;

        // 2. Horizontal merges in new row
        for c in 0..m {
            if new_row_ids[c] != 0 {
                if c > 0 && new_row_ids[c-1] != 0 {
                    if dsu.union(new_row_ids[c-1], new_row_ids[c]) {
                        merges += 1;
                    }
                }
            }
        }

        // 3. Vertical merges with previous row
        for c in 0..m {
            if new_row_ids[c] != 0 && current_row_ids[c] != 0 {
                if dsu.union(new_row_ids[c], current_row_ids[c]) {
                    merges += 1;
                }
            }
        }

        current_comps = current_comps + new_grass_count - merges;
        total_comps += current_comps;

        // Compress state
        let mut id_map = vec![0u16; dsu_size];
        let mut next_k = 1;

        for c in 0..m {
            if boundary_ids[c] != 0 {
                let root = dsu.find(boundary_ids[c]);
                if id_map[root as usize] == 0 {
                    id_map[root as usize] = next_k;
                    next_k += 1;
                }
                boundary_ids[c] = id_map[root as usize];
            }
        }

        for c in 0..m {
            if new_row_ids[c] != 0 {
                let root = dsu.find(new_row_ids[c]);
                if id_map[root as usize] == 0 {
                    id_map[root as usize] = next_k;
                    next_k += 1;
                }
                new_row_ids[c] = id_map[root as usize];
            }
        }

        current_row_ids = new_row_ids;
        max_id = next_k - 1;

        let canon_partition = canonicalize(&boundary_ids);

        if let Some(last) = groups.last_mut() {
            if last.0 == canon_partition {
                last.1 += 1;
            } else {
                groups.push((canon_partition, 1));
            }
        } else {
            groups.push((canon_partition, 1));
        }
    }

    ScanResult {
        total_comps,
        groups,
    }
}

fn count_merges(p_l: &[u16], p_r: &[u16], m: usize) -> u32 {
    let max_l = p_l.iter().cloned().max().unwrap_or(0);
    let offset = max_l;

    let max_r = p_r.iter().cloned().max().unwrap_or(0);
    let size = (offset + max_r + 1) as usize;
    let mut dsu = Dsu::new(size);

    let mut merges = 0;

    for c in 0..m {
        let u = p_l[c];
        let v = p_r[c];
        if u != 0 && v != 0 {
            if dsu.union(u, v + offset) {
                merges += 1;
            }
        }
    }
    merges
}

fn solve(grid: &Grid, r_start: usize, r_end: usize) -> u64 {
    if r_start > r_end {
        return 0;
    }
    if r_start == r_end {
        let row = &grid.rows[r_start];
        let mut comps = 0;
        let mut in_comp = false;
        for &cell in row {
            if cell {
                if !in_comp {
                    comps += 1;
                    in_comp = true;
                }
            } else {
                in_comp = false;
            }
        }
        return comps;
    }

    let mid = (r_start + r_end) / 2;

    let (left_res, right_res) = rayon::join(
        || solve(grid, r_start, mid),
        || solve(grid, mid + 1, r_end)
    );

    let mut total_complexity = left_res + right_res;

    let left_data = scan(grid, mid, r_start, true);
    let right_data = scan(grid, mid + 1, r_end, false);

    let len_l = (mid - r_start + 1) as u64;
    let len_r = (r_end - (mid + 1) + 1) as u64;

    total_complexity += left_data.total_comps * len_r;
    total_complexity += right_data.total_comps * len_l;

    for (p_l, count_l) in &left_data.groups {
        for (p_r, count_r) in &right_data.groups {
            let merges = count_merges(&p_l.mapping, &p_r.mapping, grid.m);
            total_complexity -= (merges as u64) * (*count_l as u64) * (*count_r as u64);
        }
    }

    total_complexity
}

fn main() {
