use std::io::{self, Read};
use rayon::prelude::*;

const MAX_M: usize = 50;

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
struct Partition {
    mapping: [u8; MAX_M],
}

impl PartialOrd for Partition {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Partition {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.mapping.cmp(&other.mapping)
    }
}

#[derive(Clone, Copy, Debug)]
struct Group {
    count: u64,
    sum_complexity: u64,
}

struct Grid {
    rows: Vec<u64>,
    n: usize,
    m: usize,
}

struct TinyDsu {
    parent: [u8; 128],
}

impl TinyDsu {
    #[inline(always)]
    fn new() -> Self {
        let mut parent = [0u8; 128];
        for i in 0..128 { parent[i] = i as u8; }
        TinyDsu { parent }
    }

    #[inline(always)]
    fn init(&mut self, n: u8) {
        for i in 0..n as usize {
            self.parent[i] = i as u8;
        }
    }

    #[inline(always)]
    fn find(&mut self, i: u8) -> u8 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize(ids: &[u8], m: usize, out: &mut [u8; MAX_M]) {
    let mut map = [0u8; 128];
    let mut next = 1;
    for i in 0..m {
        let id = ids[i];
        if id != 0 {
            if map[id as usize] == 0 {
                map[id as usize] = next;
                next += 1;
            }
            out[i] = map[id as usize];
        } else {
            out[i] = 0;
        }
    }
    for i in m..MAX_M {
        out[i] = 0;
    }
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> Vec<(Partition, Group)> {
    let m = grid.m;
    let len = if is_up { start_row - end_row + 1 } else { end_row - start_row + 1 };
    let mut results = Vec::with_capacity(len);

    let rows_iter: Box<dyn Iterator<Item = usize>> = if is_up {
        Box::new((end_row..=start_row).rev())
    } else {
        Box::new(start_row..=end_row)
    };

    let mut rows = rows_iter;
    let first_row = match rows.next() {
        Some(r) => r,
        None => return results,
    };

    let mut dsu = TinyDsu::new();
    let mut boundary_ids = [0u8; MAX_M];
    let mut current_ids = [0u8; MAX_M];

    let row_val = grid.rows[first_row];
    dsu.init((m + 1) as u8);
    let mut grass = 0;
    let mut merges = 0;

    for c in 0..m {
        if (row_val >> c) & 1 == 1 {
            current_ids[c] = (c + 1) as u8;
            grass += 1;
            if c > 0 && (row_val >> (c - 1)) & 1 == 1 {
                if dsu.union(current_ids[c - 1], current_ids[c]) {
                    merges += 1;
                }
            }
        } else {
            current_ids[c] = 0;
        }
    }

    for c in 0..m {
        if current_ids[c] != 0 {
            current_ids[c] = dsu.find(current_ids[c]);
        }
    }

    let mut part_buf = [0u8; MAX_M];
    canonicalize(&current_ids[0..m], m, &mut part_buf);

    for c in 0..m {
        boundary_ids[c] = part_buf[c];
        current_ids[c] = part_buf[c];
    }

    let mut current_complexity = grass - merges;

    let mut max_id = 0;
    for c in 0..m {
        if part_buf[c] > max_id { max_id = part_buf[c]; }
    }

    results.push((Partition { mapping: part_buf }, Group { count: 1, sum_complexity: current_complexity }));

    let mut new_ids = [0u8; MAX_M];
    let mut map = [0u8; 128];

    for r in rows {
        let row_val = grid.rows[r];
        let mut next_assign = max_id;
        let mut row_grass = 0;

        for c in 0..m {
            if (row_val >> c) & 1 == 1 {
                next_assign += 1;
                new_ids[c] = next_assign;
                row_grass += 1;
            } else {
                new_ids[c] = 0;
            }
        }

        dsu.init(next_assign + 1);

        let mut step_merges = 0;

        for c in 0..m {
            if new_ids[c] != 0 {
                if c > 0 && new_ids[c - 1] != 0 {
                    if dsu.union(new_ids[c - 1], new_ids[c]) {
                        step_merges += 1;
                    }
                }
            }
        }

        for c in 0..m {
            if new_ids[c] != 0 && current_ids[c] != 0 {
                if dsu.union(new_ids[c], current_ids[c]) {
                    step_merges += 1;
                }
            }
        }

        current_complexity = current_complexity + row_grass - step_merges;

        map.fill(0);
        let mut next_k = 1;

        for c in 0..m {
            if boundary_ids[c] != 0 {
                let root = dsu.find(boundary_ids[c]);
                if map[root as usize] == 0 {
                    map[root as usize] = next_k;
                    next_k += 1;
                }
                boundary_ids[c] = map[root as usize];
            }
        }

        for c in 0..m {
            if new_ids[c] != 0 {
                let root = dsu.find(new_ids[c]);
                if map[root as usize] == 0 {
                    map[root as usize] = next_k;
                    next_k += 1;
                }
                new_ids[c] = map[root as usize];
            }
        }

        current_ids = new_ids;
        max_id = next_k - 1;

        for i in 0..m { part_buf[i] = boundary_ids[i]; }
        for i in m..MAX_M { part_buf[i] = 0; }

        if let Some(last) = results.last_mut() {
            if last.0.mapping == part_buf {
                last.1.count += 1;
                last.1.sum_complexity += current_complexity;
            } else {
                 results.push((Partition { mapping: part_buf }, Group { count: 1, sum_complexity: current_complexity }));
            }
        } else {
             results.push((Partition { mapping: part_buf }, Group { count: 1, sum_complexity: current_complexity }));
        }
    }

    results.sort_unstable_by(|a, b| a.0.cmp(&b.0));

    let mut compacted = Vec::with_capacity(results.len());
    if !results.is_empty() {
        let mut cur = results[0];
        for next in results.into_iter().skip(1) {
            if cur.0 == next.0 {
                cur.1.count += next.1.count;
                cur.1.sum_complexity += next.1.sum_complexity;
            } else {
                compacted.push(cur);
                cur = next;
            }
        }
        compacted.push(cur);
    }

    compacted
}

fn count_merges(p1: &Partition, p2: &Partition, m: usize) -> u64 {
    let mut max_1 = 0;
    for i in 0..m {
        if p1.mapping[i] > max_1 { max_1 = p1.mapping[i]; }
    }
    if max_1 == 0 { return 0; }

    let mut max_2 = 0;
    for i in 0..m {
        if p2.mapping[i] > max_2 { max_2 = p2.mapping[i]; }
    }
    if max_2 == 0 { return 0; }

    let offset = max_1;
    let size = (offset + max_2 + 1) as usize;

    let mut parent = [0u8; 128];
    for i in 0..size { parent[i] = i as u8; }

    let mut merges = 0;

    for c in 0..m {
        let u = p1.mapping[c];
        let v = p2.mapping[c];

        if u != 0 && v != 0 {
            let v_shifted = v + offset;

            let mut root_u = u;
            while root_u != parent[root_u as usize] {
                root_u = parent[root_u as usize];
            }
            let mut curr = u;
            while curr != root_u {
                let next = parent[curr as usize];
                parent[curr as usize] = root_u;
                curr = next;
            }

            let mut root_v = v_shifted;
            while root_v != parent[root_v as usize] {
                root_v = parent[root_v as usize];
            }
            let mut curr = v_shifted;
            while curr != root_v {
                let next = parent[curr as usize];
                parent[curr as usize] = root_v;
                curr = next;
            }

            if root_u != root_v {
                parent[root_u as usize] = root_v;
                merges += 1;
            }
        }
    }
    merges
}

fn solve(r1: usize, r2: usize, grid: &Grid) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let row_val = grid.rows[r1];
        let mut comps = 0;
        let mut in_comp = false;
        for c in 0..grid.m {
            if (row_val >> c) & 1 == 1 {
                if !in_comp {
                    comps += 1;
                    in_comp = true;
                }
            } else {
                in_comp = false;
            }
        }
        return comps;
    }

    let mid = (r1 + r2) / 2;

    let (left_res, right_res) = rayon::join(
        || solve(r1, mid, grid),
        || solve(mid + 1, r2, grid)
    );

    let mut total = left_res + right_res;

    let left_groups = scan(grid, mid, r1, true);
    let right_groups = scan(grid, mid + 1, r2, false);

    let mut sum_count_r = 0;
    let mut sum_comp_r = 0;
    for g in &right_groups {
        sum_count_r += g.1.count;
        sum_comp_r += g.1.sum_complexity;
    }

    let mut sum_count_l = 0;
    let mut sum_comp_l = 0;
    for g in &left_groups {
        sum_count_l += g.1.count;
        sum_comp_l += g.1.sum_complexity;
    }

    total += sum_comp_l * sum_count_r;
    total += sum_comp_r * sum_count_l;

    let m = grid.m;
    for (p_l, g_l) in &left_groups {
        for (p_r, g_r) in &right_groups {
            let merges = count_merges(p_l, p_r, m);
            if merges > 0 {
                total -= merges * g_l.count * g_r.count;
            }
        }
    }

    total
}

