            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize(ids: &[u8], m: usize) -> Partition {
    let mut map = [0u8; 128];
    let mut new_mapping = [0u8; MAX_M];
    let mut next = 1;
    let mut max_id = 0;

    for i in 0..m {
        let id = ids[i];
        if id != 0 {
            if map[id as usize] == 0 {
                map[id as usize] = next;
                next += 1;
            }
            let new_val = map[id as usize];
            new_mapping[i] = new_val;
            if new_val > max_id {
                max_id = new_val;
