            groups.push(Group {
                partition: p_boundary,
                count: 1,
                sum_complexity: current_complexity,
            });
        }
    }

    groups
}

fn count_merges(p1: &Partition, p2: &Partition, m: usize) -> u64 {
    let max_1 = p1.max_id;
    let max_2 = p2.max_id;

    if max_1 == 0 || max_2 == 0 { return 0; }

    let offset = max_1;
    let size = offset + max_2 + 1;

    let mut parent = [0u8; 128];
    for i in 0..size as usize { parent[i] = i as u8; }

    let mut merges = 0;

    for c in 0..m {
        let u = p1.mapping[c];
        let v = p2.mapping[c];

        if u != 0 && v != 0 {
            let v_shifted = v + offset;

            let mut root_u = u;
            while root_u != parent[root_u as usize] {
                root_u = parent[root_u as usize];
            }
            let mut curr = u;
            while curr != root_u {
                let next = parent[curr as usize];
                parent[curr as usize] = root_u;
                curr = next;
            }

            let mut root_v = v_shifted;
            while root_v != parent[root_v as usize] {
                root_v = parent[root_v as usize];
            }
            let mut curr = v_shifted;
            while curr != root_v {
                let next = parent[curr as usize];
                parent[curr as usize] = root_v;
                curr = next;
            }

            if root_u != root_v {
                parent[root_u as usize] = root_v;
                merges += 1;
            }
        }
    }
    merges
}

fn solve(grid: &Grid, r1: usize, r2: usize) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
