    buf.clear();
    let mut map = [0u8; 128];
    let mut next = 1;

    for &id in ids.iter().take(m) {
        if id == 0 {
            buf.push(0);
        } else {
            let idx = id as usize;
            if map[idx] == 0 {
                map[idx] = next;
                next += 1;
            }
            buf.push(map[idx]);
