    let mut groups: Vec<(Partition, u64)> = Vec::with_capacity(std::cmp::min(range_len, m + 2));

    let mut dsu = TinyDsu::new();
    let mut row_ids = vec![0u8; m];

    let start_off = start_row * m;
    let row_slice = &grid.data[start_off..start_off + m];

