    let mut next_canon = 1;
    let mut current_ids = vec![0u8; m];

    for c in 0..m {
        if row_ids[c] != 0 {
            let root = dsu.find(row_ids[c]);
            if mapping[root as usize] == 0 {
                mapping[root as usize] = next_canon;
                next_canon += 1;
            }
            current_ids[c] = mapping[root as usize];
        }
    }

    let mut current_comps = (next_canon - 1) as u64;
    sum_comps += current_comps;

    let mut temp_buf = Vec::with_capacity(m);
    canonicalize(&current_ids, m, &mut temp_buf);

    groups.push((Partition { mapping: temp_buf.clone() }, 1));

    let mut boundary_ids = current_ids.clone();
    let mut active_row_ids = current_ids;
    let mut max_id = (next_canon - 1) as u8;

    let rows_iter: Box<dyn Iterator<Item = usize>> = if is_up {
        if start_row == end_row { return ScanResult { sum_comps, groups }; }
        Box::new((end_row..start_row).rev())
    } else {
        if start_row == end_row { return ScanResult { sum_comps, groups }; }
        Box::new(start_row + 1..=end_row)
    };

    let mut new_row_ids = vec![0u8; m];

    for r in rows_iter {
