            if boundary_ids[c] != 0 {
                let root = dsu.find(boundary_ids[c]);
                if mapping[root as usize] == 0 {
                    mapping[root as usize] = next_k;
                    next_k += 1;
                }
                boundary_ids[c] = mapping[root as usize];
            }
