struct TinyDsu {
    parent: [u8; 128],
}

impl TinyDsu {
    #[inline(always)]
    fn new() -> Self {
        let mut p = [0u8; 128];
        for i in 0..128 { p[i] = i as u8; }
        TinyDsu { parent: p }
    }

    #[inline(always)]
    fn init(&mut self, n: u8) {
        for i in 0..n as usize {
            self.parent[i] = i as u8;
        }
    }

    #[inline(always)]
    fn find(&mut self, i: u8) -> u8 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline(always)]
    fn union(&mut self, i: u8, j: u8) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize(ids: &[u8], m: usize, buf: &mut [u8; MAX_M]) -> u8 {
    let mut map = [0u8; 128];
    let mut next = 1;
    let mut max_id = 0;

    for i in 0..m {
        let id = ids[i];
        if id != 0 {
            let idx = id as usize;
            if map[idx] == 0 {
                map[idx] = next;
                next += 1;
            }
            let new_val = map[idx];
            buf[i] = new_val;
            if new_val > max_id { max_id = new_val; }
        } else {
            buf[i] = 0;
        }
    }
    for i in m..MAX_M {
        buf[i] = 0;
    }
    max_id
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> Vec<Group> {
    let m = grid.m;
    let mut groups: Vec<Group> = Vec::with_capacity(64);

    let mut curr_r = start_row;
    let step = if is_up { -1isize } else { 1isize };
    let stop_after = end_row;

    let mut dsu = TinyDsu::new();
    let mut boundary_ids = [0u8; MAX_M]; 
    let mut current_ids = [0u8; MAX_M]; 
    let mut temp_partition = Partition { mapping: [0; MAX_M], max_id: 0 };

    let row_val = grid.rows[curr_r];
    dsu.init((m + 1) as u8);
    let mut grass = 0;
    let mut merges = 0;

    for c in 0..m {
        if (row_val >> c) & 1 == 1 {
            current_ids[c] = (c + 1) as u8;
            grass += 1;
            if c > 0 && (row_val >> (c-1)) & 1 == 1 {
                if dsu.union(current_ids[c-1], current_ids[c]) {
                    merges += 1;
                }
            }
        } else {
            current_ids[c] = 0;
        }
    }

    for c in 0..m {
        if current_ids[c] != 0 {
            current_ids[c] = dsu.find(current_ids[c]);
        }
    }

    let max_id = canonicalize(&current_ids, m, &mut temp_partition.mapping);
    temp_partition.max_id = max_id;

    for i in 0..m {
        boundary_ids[i] = temp_partition.mapping[i];
        current_ids[i] = temp_partition.mapping[i];
    }

    let mut current_complexity = grass - merges;
    let mut max_active_id = max_id;

    groups.push(Group {
        partition: temp_partition,
        count: 1,
        sum_complexity: current_complexity,
    });

    let mut new_ids = [0u8; MAX_M];
    let mut mapping = [0u8; 128];

    loop {
        if curr_r == stop_after { break; }
        curr_r = (curr_r as isize + step) as usize;

        let row_val = grid.rows[curr_r];
        let mut next_assign = max_active_id;
        let mut row_grass = 0;

        for c in 0..m {
            if (row_val >> c) & 1 == 1 {
                next_assign += 1;
                new_ids[c] = next_assign;
                row_grass += 1;
            } else {
                new_ids[c] = 0;
            }
        }

        dsu.init(next_assign + 1);
        let mut step_merges = 0;

        if row_grass > 0 {
             for c in 0..m {
                if new_ids[c] != 0 {
                    if c > 0 && new_ids[c-1] != 0 {
                        if dsu.union(new_ids[c-1], new_ids[c]) {
                            step_merges += 1;
                        }
                    }
                }
            }

            for c in 0..m {
                if new_ids[c] != 0 && current_ids[c] != 0 {
                    if dsu.union(new_ids[c], current_ids[c]) {
                        step_merges += 1;
                    }
                }
            }
        }

        current_complexity = current_complexity + row_grass - step_merges;

        mapping.fill(0);
        let mut next_k = 1;

        for c in 0..m {
            if boundary_ids[c] != 0 {
                let root = dsu.find(boundary_ids[c]);
                if mapping[root as usize] == 0 {
                    mapping[root as usize] = next_k;
                    next_k += 1;
                }
                boundary_ids[c] = mapping[root as usize];
            }
        }

        for c in 0..m {
            if new_ids[c] != 0 {
                let root = dsu.find(new_ids[c]);
                if mapping[root as usize] == 0 {
                    mapping[root as usize] = next_k;
                    next_k += 1;
                }
                new_ids[c] = mapping[root as usize];
            }
        }

        for i in 0..m { current_ids[i] = new_ids[i]; }
        max_active_id = next_k - 1;

        let p_max = canonicalize(&boundary_ids, m, &mut temp_partition.mapping);
        temp_partition.max_id = p_max;

        if let Some(last) = groups.last_mut() {
            if last.partition == temp_partition {
                last.count += 1;
                last.sum_complexity += current_complexity;
            } else {
                groups.push(Group {
                    partition: temp_partition,
                    count: 1,
                    sum_complexity: current_complexity,
                });
            }
        } else {
            groups.push(Group {
                partition: temp_partition,
                count: 1,
                sum_complexity: current_complexity,
            });
        }
    }

    if groups.len() > 1 {
        groups.sort_unstable_by(|a, b| a.partition.cmp(&b.partition));
        let mut compacted = Vec::with_capacity(groups.len());
        let mut cur = groups[0].clone();
        for next in groups.into_iter().skip(1) {
            if cur.partition == next.partition {
                cur.count += next.count;
                cur.sum_complexity += next.sum_complexity;
            } else {
                compacted.push(cur);
                cur = next;
            }
        }
        compacted.push(cur);
        groups = compacted;
    }

    groups
}

fn count_merges(p1: &Partition, p2: &Partition, m: usize) -> u64 {
    if p1.max_id == 0 || p2.max_id == 0 { return 0; }

    let offset = p1.max_id;
    let size = offset + p2.max_id + 1;

    let mut parent = [0u8; 128];
    for i in 1..size as usize { parent[i] = i as u8; }

    let mut merges = 0;

    for c in 0..m {
        let u = p1.mapping[c];
        let v = p2.mapping[c];

        if u != 0 && v != 0 {
            let v_shifted = v + offset;

            let mut root_u = u;
            while root_u != parent[root_u as usize] {
                root_u = parent[root_u as usize];
            }
            let mut curr = u;
            while curr != root_u {
                let next = parent[curr as usize];
                parent[curr as usize] = root_u;
                curr = next;
            }

            let mut root_v = v_shifted;
            while root_v != parent[root_v as usize] {
                root_v = parent[root_v as usize];
            }
            let mut curr = v_shifted;
            while curr != root_v {
                let next = parent[curr as usize];
                parent[curr as usize] = root_v;
                curr = next;
            }

            if root_u != root_v {
                parent[root_u as usize] = root_v;
                merges += 1;
            }
        }
    }
    merges
}

fn solve(r1: usize, r2: usize, grid: &Grid) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let row_val = grid.rows[r1];
        let mut comps = 0;
        let mut in_comp = false;
        for c in 0..grid.m {
            if (row_val >> c) & 1 == 1 {
                if !in_comp {
                    comps += 1;
                    in_comp = true;
                }
            } else {
                in_comp = false;
            }
        }
        return comps;
    }

    let mid = (r1 + r2) / 2;

    let (left_res, right_res) = if r2 - r1 > 200 {
        rayon::join(
            || solve(r1, mid, grid),
            || solve(mid + 1, r2, grid)
        )
    } else {
        (solve(r1, mid, grid), solve(mid + 1, r2, grid))
    };

    let mut total = left_res + right_res;

    let left_groups = scan(grid, mid, r1, true);
    let right_groups = scan(grid, mid + 1, r2, false);

    let mut sum_count_l = 0;
    let mut sum_comp_l = 0;
    for g in &left_groups {
        sum_count_l += g.count;
        sum_comp_l += g.sum_complexity;
    }

    let mut sum_count_r = 0;
    let mut sum_comp_r = 0;
    for g in &right_groups {
        sum_count_r += g.count;
        sum_comp_r += g.sum_complexity;
    }

    total += sum_comp_l * sum_count_r;
    total += sum_comp_r * sum_count_l;

    if left_groups.len() * right_groups.len() > 1000 {
        let merge_deduction: u64 = left_groups.par_iter().map(|g_l| {
            let mut local_sub = 0;
            for g_r in &right_groups {
                let merges = count_merges(&g_l.partition, &g_r.partition, grid.m);
                if merges > 0 {
                    local_sub += merges * g_l.count * g_r.count;
                }
            }
            local_sub
        }).sum();
        total -= merge_deduction;
    } else {
        for g_l in &left_groups {
            for g_r in &right_groups {
                let merges = count_merges(&g_l.partition, &g_r.partition, grid.m);
                if merges > 0 {
                    total -= merges * g_l.count * g_r.count;
                }
            }
        }
    }

    total
}

fn main() {
    let builder = std::thread::Builder::new()
        .name("main".into())
        .stack_size(64 * 1024 * 1024);

    let handler = builder.spawn(|| {
