use std::io::{self, Read};
use std::collections::HashMap;
use rayon::prelude::*;

#[derive(Clone, Debug, PartialEq, Eq, Hash)]
struct Partition {
    mapping: Vec<u8>,
}

#[derive(Clone)]
struct Grid {
    rows: Vec<u64>,
    n: usize,
    m: usize,
}

struct Dsu {
    parent: Vec<u16>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n as u16).collect(),
        }
    }

    fn init(&mut self, n: usize) {
        if self.parent.len() < n {
            self.parent.resize(n, 0);
        }
        for i in 0..n {
            self.parent[i] = i as u16;
        }
    }

    #[inline]
    fn find(&mut self, i: u16) -> u16 {
        let mut root = i;
        while root != self.parent[root as usize] {
            root = self.parent[root as usize];
        }
        let mut curr = i;
        while curr != root {
            let next = self.parent[curr as usize];
            self.parent[curr as usize] = root;
            curr = next;
        }
        root
    }

    #[inline]
    fn union(&mut self, i: u16, j: u16) -> bool {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i as usize] = root_j;
            true
        } else {
            false
        }
    }
}

fn canonicalize(ids: &[u16], m: usize, buffer: &mut Vec<u8>) -> Partition {
    buffer.clear();
    buffer.reserve(m);
    let mut map = [0u8; 256]; 
    let mut next = 1;

    for &id in ids.iter().take(m) {
        if id == 0 {
            buffer.push(0);
        } else {
            let idx = id as usize;
            if idx < 256 {
                if map[idx] == 0 {
                    map[idx] = next;
                    next += 1;
                }
                buffer.push(map[idx]);
            } else {
                // Fallback for safety, though IDs should be < 150
                buffer.push(0); 
            }
        }
    }
    Partition { mapping: buffer.clone() }
}

fn count_merges(p1: &Partition, p2: &Partition, m: usize) -> u64 {
    let mut max_1 = 0;
    for &x in &p1.mapping { if x > max_1 { max_1 = x; } }

    let mut max_2 = 0;
    for &x in &p2.mapping { if x > max_2 { max_2 = x; } }

    if max_1 == 0 || max_2 == 0 { return 0; }

    let offset = max_1;
    let size = (offset + max_2 + 1) as usize;

    let mut parent = [0u8; 128];
    for i in 0..size {
        if i < 128 { parent[i] = i as u8; }
    }

    let mut merges = 0;

    for c in 0..m {
        let u = p1.mapping[c];
        let v = p2.mapping[c];
        if u != 0 && v != 0 {
            let u_idx = u;
            let v_idx = v + offset;

            if (v_idx as usize) >= 128 { continue; } // Should not happen given constraints

            let mut root_u = u_idx;
            while root_u != parent[root_u as usize] {
                root_u = parent[root_u as usize];
            }
            let mut curr = u_idx;
            while curr != root_u {
                let next = parent[curr as usize];
                parent[curr as usize] = root_u;
                curr = next;
            }

            let mut root_v = v_idx;
            while root_v != parent[root_v as usize] {
                root_v = parent[root_v as usize];
            }
            let mut curr = v_idx;
            while curr != root_v {
                let next = parent[curr as usize];
                parent[curr as usize] = root_v;
                curr = next;
            }

            if root_u != root_v {
                parent[root_u as usize] = root_v;
                merges += 1;
            }
        }
    }
    merges
}

fn solve(r1: usize, r2: usize, grid: &Grid) -> u64 {
    if r1 > r2 { return 0; }
    if r1 == r2 {
        let row_val = grid.rows[r1];
        let mut comps = 0;
        let mut in_comp = false;
        for c in 0..grid.m {
            if (row_val >> c) & 1 == 1 {
                if !in_comp {
                    comps += 1;
                    in_comp = true;
                }
            } else {
                in_comp = false;
            }
        }
        return comps;
    }

    let mid = (r1 + r2) / 2;

    let (left_res, right_res) = rayon::join(
        || solve(r1, mid, grid),
        || solve(mid + 1, r2, grid)
    );

    let mut total = left_res + right_res;

    let left_groups = scan(grid, mid, r1, true);
    let right_groups = scan(grid, mid + 1, r2, false);

    let mut sum_count_r = 0;
    let mut sum_comp_r = 0;
    for (count, sum_comp) in right_groups.values() {
        sum_count_r += count;
        sum_comp_r += sum_comp;
    }

    let mut sum_count_l = 0;
    let mut sum_comp_l = 0;
    for (count, sum_comp) in left_groups.values() {
        sum_count_l += count;
        sum_comp_l += sum_comp;
    }

    total += sum_comp_l * sum_count_r;
    total += sum_comp_r * sum_count_l;

    for (p_l, (c_l, _)) in &left_groups {
        for (p_r, (c_r, _)) in &right_groups {
            let merges = count_merges(p_l, p_r, grid.m);
            total -= merges * c_l * c_r;
        }
    }

    total
}

fn scan(grid: &Grid, start_row: usize, end_row: usize, is_up: bool) -> HashMap<Partition, (u64, u64)> {
    let m = grid.m;
    let mut groups: HashMap<Partition, (u64, u64)> = HashMap::new();

    let rows: Vec<usize> = if is_up {
        (end_row..=start_row).rev().collect()
    } else {
        (start_row..=end_row).collect()
    };

    if rows.is_empty() { return groups; }

    let first_row = rows[0];
    let row_val = grid.rows[first_row];

    let mut dsu = Dsu::new(2 * m);
    let mut grass_count = 0;
    let mut merges = 0;

    for c in 0..m {
        if (row_val >> c) & 1 == 1 {
            grass_count += 1;
            dsu.union(c as u16, (m + c) as u16);
            if c > 0 && (row_val >> (c - 1)) & 1 == 1 {
                if dsu.union((c - 1) as u16, c as u16) {
                    merges += 1;
                }
                dsu.union((m + c - 1) as u16, (m + c) as u16);
            }
        }
    }

    let mut current_complexity = grass_count - merges;

    let mut bound_ids = vec![0u16; m];
    for c in 0..m {
        if (row_val >> c) & 1 == 1 {
            bound_ids[c] = dsu.find((m + c) as u16);
        }
    }

    let mut temp_buf = Vec::new();
    let p = canonicalize(&bound_ids, m, &mut temp_buf);

    groups.insert(p, (1, current_complexity));

    let mut prev_row_val = row_val;

    let mut t_dsu = Dsu::new(3 * m);
    let mut map_old_root_to_t_root = [u16::MAX; 256];
    let mut map_t_root_to_next_root = [u16::MAX; 256];

    for &r in rows.iter().skip(1) {
        let curr_row_val = grid.rows[r];

        t_dsu.init(3 * m);
        map_old_root_to_t_root.fill(u16::MAX);

        for i in 0..2*m {
            let root = dsu.find(i as u16);
            let root_idx = root as usize;
             if root_idx < 256 {
                if map_old_root_to_t_root[root_idx] == u16::MAX {
                    map_old_root_to_t_root[root_idx] = (i + m) as u16;
                } else {
                    t_dsu.union(map_old_root_to_t_root[root_idx], (i + m) as u16);
                }
             }
        }

        let mut new_grass = 0;
        let mut step_merges = 0;

        for c in 0..m {
            if (curr_row_val >> c) & 1 == 1 {
                new_grass += 1;
                if c > 0 && (curr_row_val >> (c - 1)) & 1 == 1 {
                    if t_dsu.union((c - 1) as u16, c as u16) {
                        step_merges += 1;
                    }
                }
                if (prev_row_val >> c) & 1 == 1 {
                    if t_dsu.union(c as u16, (m + c) as u16) {
                        step_merges += 1;
                    }
                }
            }
        }

        current_complexity = current_complexity + new_grass - step_merges;

        dsu.init(2 * m);
        map_t_root_to_next_root.fill(u16::MAX);

        for c in 0..m {
            if (curr_row_val >> c) & 1 == 1 {
                let root = t_dsu.find(c as u16);
                let root_idx = root as usize;
                if root_idx < 256 {
                    if map_t_root_to_next_root[root_idx] == u16::MAX {
                        map_t_root_to_next_root[root_idx] = c as u16;
                    } else {
                        dsu.union(map_t_root_to_next_root[root_idx], c as u16);
                    }
                }
            }
        }

        for c in 0..m {
            if (row_val >> c) & 1 == 1 {
                let root = t_dsu.find((2 * m + c) as u16);
                let root_idx = root as usize;
                if root_idx < 256 {
                    if map_t_root_to_next_root[root_idx] == u16::MAX {
                        map_t_root_to_next_root[root_idx] = (m + c) as u16;
                    } else {
                        dsu.union(map_t_root_to_next_root[root_idx], (m + c) as u16);
                    }
                }
            }
        }

        prev_row_val = curr_row_val;

        for c in 0..m {
            if (row_val >> c) & 1 == 1 {
                bound_ids[c] = dsu.find((m + c) as u16);
            } else {
                bound_ids[c] = 0;
            }
        }

        let p = canonicalize(&bound_ids, m, &mut temp_buf);
        let entry = groups.entry(p).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += current_complexity;
    }

    groups
}

