use std::io::{self, Read};
use std::collections::VecDeque;
use rayon::prelude::*;

// Fast input scanner to handle large input efficiently
struct Scanner {
    buffer: Vec<u8>,
    pos: usize,
}

impl Scanner {
    fn new() -> Self {
        let mut buffer = Vec::new();
        let stdin = io::stdin();
        let mut handle = stdin.lock();
        handle.read_to_end(&mut buffer).unwrap();
        Self { buffer, pos: 0 }
    }

    #[inline(always)]
    fn next_u64(&mut self) -> u64 {
        while self.pos < self.buffer.len() && self.buffer[self.pos] <= b' ' {
            self.pos += 1;
        }
        if self.pos >= self.buffer.len() {
            return 0;
        }
        let mut n = 0;
        while self.pos < self.buffer.len() && self.buffer[self.pos] >= b'0' && self.buffer[self.pos] <= b'9' {
            n = n * 10 + (self.buffer[self.pos] - b'0') as u64;
            self.pos += 1;
        }
        n
    }

    #[inline(always)]
    fn next_i64(&mut self) -> i64 {
        self.next_u64() as i64
    }
}

// Data structure to store cycle info for parallel processing
struct Cycle {
    nodes: Vec<u32>,
    weights: Vec<i64>,
}

fn main() {
    let mut scanner = Scanner::new();
    if scanner.buffer.is_empty() { return; }

    let n = scanner.next_u64() as usize;
    if n == 0 {
        println!("0");
        return;
    }

    // Graph representation using arrays since each node has exactly 1 outgoing edge
    // dest[i]: destination of the bridge from i
    // weight[i]: length of the bridge from i
    // in_degree[i]: number of bridges pointing TO i
    let mut dest = vec![0u32; n + 1];
    let mut weight = vec![0i64; n + 1];
    let mut in_degree = vec![0u32; n + 1];

    for i in 1..=n {
        let v = scanner.next_u64() as u32;
        let w = scanner.next_i64();
        dest[i] = v;
        weight[i] = w;
        in_degree[v as usize] += 1;
    }

    // diam[u]: max path entirely within the tree branch attached at u (flowing into u)
    // max_depth[u]: max path starting at u and going down into the tree attached at u
    let mut diam = vec![0i64; n + 1];
    let mut max_depth = vec![0i64; n + 1];

    // Topological Sort / Peeling (Kahn's Algorithm)
    // Initialize with leaves (nodes with in-degree 0)
    let mut q = Vec::with_capacity(n);
    for i in 1..=n {
        if in_degree[i] == 0 {
            q.push(i as u32);
        }
    }

    // Process tree nodes
    let mut head = 0;
    while head < q.len() {
        let u = q[head];
        head += 1;

        let u_idx = u as usize;
        let v = dest[u_idx];
        let v_idx = v as usize;
        let w = weight[u_idx];

        // Update diam[v]: potential max path passing through v connecting u's branch
        // and the best previously processed branch of v
        let path_through_v = max_depth[v_idx] + max_depth[u_idx] + w;
        if path_through_v > diam[v_idx] {
            diam[v_idx] = path_through_v;
        }

        // Also inherit the max diameter found entirely within u's subtree
        if diam[u_idx] > diam[v_idx] {
            diam[v_idx] = diam[u_idx];
        }

        // Update max_depth[v]: longest path from v down to a leaf
        let depth_via_u = max_depth[u_idx] + w;
        if depth_via_u > max_depth[v_idx] {
            max_depth[v_idx] = depth_via_u;
        }

        in_degree[v_idx] -= 1;
        if in_degree[v_idx] == 0 {
            q.push(v);
        }
    }

    // Identify cycles
    // Nodes with in_degree > 0 after peeling are part of cycles
    let mut cycles = Vec::new();
    for i in 1..=n {
        if in_degree[i] > 0 {
            let mut curr = i as u32;
            let mut cycle_nodes = Vec::new();
            let mut cycle_weights = Vec::new();

            // Traverse the cycle
            while in_degree[curr as usize] > 0 {
                in_degree[curr as usize] = 0; // Mark as visited
                cycle_nodes.push(curr);
                cycle_weights.push(weight[curr as usize]);
                curr = dest[curr as usize];
            }
            cycles.push(Cycle { nodes: cycle_nodes, weights: cycle_weights });
        }
    }

    // Free memory of graph structures that are no longer needed
    drop(dest);
