fn main() {
    let mut scanner = Scanner::new();
    if scanner.buffer.is_empty() { return; }

    let n = scanner.next_usize();

    // next_node[i] = target of the bridge from island i
    // edge_weight[i] = length of the bridge from island i
    let mut next_node = vec![0usize; n];
    let mut edge_weight = vec![0i64; n];
    let mut in_degree = vec![0u32; n];

