    // d_val[u] stores the diameter of the tree attached at u
    let mut l_val = vec![0i64; n];
    let mut d_val = vec![0i64; n];

    // Topology sort / peeling to process the trees attached to the cycles
    let mut queue = Vec::with_capacity(n);
    for i in 0..n {
        if in_degree[i] == 0 {
            queue.push(i);
        }
    }

    let mut head = 0;
    while head < queue.len() {
        let u = queue[head];
        head += 1;

        let v = next_node[u];
        let w = edge_weight[u];

        // Calculate the longest path passing through v that comes from u
        let path_via_v = l_val[u] + w + l_val[v];

        // Update diameter of v's tree component
        d_val[v] = d_val[v].max(d_val[u]).max(path_via_v);

        // Update longest path starting at v going down into its tree
        l_val[v] = l_val[v].max(l_val[u] + w);

        in_degree[v] -= 1;
        if in_degree[v] == 0 {
            queue.push(v);
        }
