fn main() {
    let mut scanner = Scanner::new();
    let n = scanner.next_usize();

    // CSR Graph Representation
    // head[u] points to the first edge of u
    // next[e] points to the next edge index
    // to[e] is the destination of edge e
    // weight[e] is the weight of edge e
    let mut head = vec![-1i32; n + 1];
    let mut next = vec![-1i32; 2 * n];
    let mut to = vec![0u32; 2 * n];
    let mut weight = vec![0i32; 2 * n];
    let mut degree = vec![0i32; n + 1];
    let mut edge_count = 0;

    for i in 1..=n {
        let u = i;
        let v = scanner.next_usize();
        let w = scanner.next_i64() as i32;

        // u -> v
        to[edge_count] = v as u32;
        weight[edge_count] = w;
        next[edge_count] = head[u];
        head[u] = edge_count as i32;
        edge_count += 1;

        // v -> u
        to[edge_count] = u as u32;
        weight[edge_count] = w;
        next[edge_count] = head[v];
        head[v] = edge_count as i32;
        edge_count += 1;

        degree[u] += 1;
        degree[v] += 1;
    }

    // Topological Sort / Peeling to handle trees attached to cycles
    let mut q = VecDeque::new();
    for i in 1..=n {
        if degree[i] == 1 {
            q.push_back(i);
        }
    }

    let mut removed = vec![false; n + 1];
    let mut depth = vec![0i64; n + 1];
    let mut tree_diam = vec![0i64; n + 1];

    while let Some(u) = q.pop_front() {
        removed[u] = true;

        let mut parent = 0;
        let mut w_to_parent = 0;

        let mut e = head[u];
        while e != -1 {
            let v = to[e as usize] as usize;
            if !removed[v] {
                parent = v;
                w_to_parent = weight[e as usize] as i64;
                break;
            }
            e = next[e as usize];
        }

        if parent != 0 {
            let v = parent;
            let path_len = depth[u] + w_to_parent;

            // Update diameter of v's tree component
            // Possible max path is either existing max in v, max in u, 
            // or a path passing through v connecting u's branch and v's longest existing branch
            let new_diam = tree_diam[v].max(tree_diam[u]).max(depth[v] + path_len);
            tree_diam[v] = new_diam;

            // Update depth of v (longest path from v down to any leaf in processed subtree)
            depth[v] = depth[v].max(path_len);

            degree[v] -= 1;
            if degree[v] == 1 {
                q.push_back(v);
            }
        }
