            let mut cycle_weights = Vec::new();

            let mut curr = i;
            let mut last_edge_idx = -1;

            loop {
                visited_cycle[curr] = true;
                cycle_nodes.push(curr);

                let mut next_node = 0;
                let mut w = 0;
                let mut edge_idx = -1;

                let mut e = head[curr];
                while e != -1 {
                    let v = to[e as usize] as usize;
                    if !removed[v] {
                        // Avoid traversing back on the same edge we came from
                        // Edges are stored in pairs: (0,1), (2,3), etc.
                        // So edge e and e^1 are inverses.
                        if last_edge_idx == -1 || (e as usize) != (last_edge_idx as usize ^ 1) {
                            next_node = v;
                            w = weight[e as usize];
                            edge_idx = e;
                            break; 
                        }
                    }
                    e = next[e as usize];
                }

                if next_node == i {
                     cycle_weights.push(w as i64);
                     break;
                }

                cycle_weights.push(w as i64);
                last_edge_idx = edge_idx;
                curr = next_node;
            }
            cycles.push((cycle_nodes, cycle_weights));
        }
    }

    // Process each component (cycle + attached trees) in parallel
    let total_max_dist: i64 = cycles.into_par_iter().map(|(nodes, weights)| {
        let k = nodes.len();
        if k == 2 {
            // Special case for cycle of length 2 (2 nodes, 2 bridges)
            let u = nodes[0];
            let v = nodes[1];
            let max_w = weights[0].max(weights[1]);
            let path_through_cycle = depth[u] + depth[v] + max_w;
            return tree_diam[u].max(tree_diam[v]).max(path_through_cycle);
        }

        let mut max_diam = 0;
        for &u in &nodes {
            max_diam = max_diam.max(tree_diam[u]);
        }

        // Linearize cycle by duplicating it to handle circularity
        let mut a = Vec::with_capacity(2 * k);
        let mut p = Vec::with_capacity(2 * k + 1);
        p.push(0);

        for j in 0..2 * k {
            let idx = j % k;
            a.push(depth[nodes[idx]]);
            if j < 2 * k {
                p.push(p.last().unwrap() + weights[idx]);
            }
        }

        // Sliding window maximum to find max path on cycle
        // Maximize (A[i] - P[i]) + (A[j] + P[j]) such that j - i < k
        let mut dq: VecDeque<usize> = VecDeque::new();
        let mut max_cycle_path = 0;

        for j in 0..2 * k {
            // Remove indices that are out of window
            if let Some(&front) = dq.front() {
                if j >= k && (j - front >= k) {
                    dq.pop_front();
                }
            }

            // Calculate max path ending at j
            if let Some(&i) = dq.front() {
                 let val = (a[i] - p[i]) + (a[j] + p[j]);
                 max_cycle_path = max_cycle_path.max(val);
            }

            // Maintain deque monotonicity
            let curr_val = a[j] - p[j];
            while let Some(&back) = dq.back() {
                if a[back] - p[back] <= curr_val {
                    dq.pop_back();
                } else {
                    break;
                }
            }
            dq.push_back(j);
        }

        max_diam.max(max_cycle_path)
    }).sum();

    println!("{}", total_max_dist);
}

