        to[edge_count] = v as u32;
        weight[edge_count] = w;
        next[edge_count] = head[u];
        head[u] = edge_count as i32;
        edge_count += 1;

        to[edge_count] = u as u32;
        weight[edge_count] = w;
        next[edge_count] = head[v];
        head[v] = edge_count as i32;
        edge_count += 1;

        degree[u] += 1;
        degree[v] += 1;
    }

    // Peeling process (Topological Sort logic) to handle trees attached to cycles
    let mut stack = Vec::with_capacity(n);
    for i in 1..=n {
        if degree[i] == 1 {
            stack.push(i);
        }
    }

