            while let Some(&back) = dq.back() {
                if a[back] - p[back] <= curr_val {
                    dq.pop_back();
                } else {
                    break;
                }
            }
            dq.push_back(j);
        }

        max_diam.max(max_cycle_path)
    }).sum();

