            // Traverse the cycle to mark all nodes as visited
            while in_degree[curr] > 0 {
                in_degree[curr] = 0;
                curr = next_node[curr];
            }
            cycle_starts.push(i);
        }
    }

    // Process each component (cycle + attached trees) in parallel
    let total_max_dist: i64 = cycle_starts.par_iter().map(|&start_node| {
        // Reconstruct the cycle
        let mut cycle_nodes = Vec::new();
        let mut curr = start_node;
        loop {
            cycle_nodes.push(curr);
            curr = next_node[curr];
            if curr == start_node { break; }
        }

        let k = cycle_nodes.len();

        // Find max diameter entirely within any of the attached trees
        let mut max_tree_diam = 0;
        for &u in &cycle_nodes {
            max_tree_diam = max_tree_diam.max(d_val[u]);
        }

        // Compute prefix sums of cycle edge weights
        // We double the cycle to handle the circularity linearly
        let mut p = Vec::with_capacity(2 * k + 1);
        p.push(0);
        for i in 0..2*k {
            let u = cycle_nodes[i % k];
            let w = edge_weight[u];
            p.push(p.last().unwrap() + w);
        }

        // Use sliding window maximum to find the longest path that uses cycle edges
        // We want to maximize (l_val[u] + p[j]) + (l_val[v] - p[i])
        // where j is the end of the path and i is the start, i < j, and path length < k
        let mut max_cycle_path = 0;
        let mut deque: VecDeque<usize> = VecDeque::new();

        for j in 0..2*k {
            let u = cycle_nodes[j % k];
            let val_j = l_val[u] + p[j];

            // Remove indices that are out of the window (path length must be < k)
            while let Some(&front) = deque.front() {
                if j >= k && front < j - k + 1 {
                    deque.pop_front();
                } else {
                    break;
                }
            }

            // The front of the deque has the best i for the current j
            if let Some(&best_i) = deque.front() {
                let v_best = cycle_nodes[best_i % k];
                let val_i = l_val[v_best] - p[best_i];
                max_cycle_path = max_cycle_path.max(val_j + val_i);
            }

            // Insert current index j into the deque
            let val_insert = l_val[u] - p[j];
            while let Some(&back) = deque.back() {
                let v_back = cycle_nodes[back % k];
                let val_back = l_val[v_back] - p[back];
                // Maintain decreasing order of values
                if val_back <= val_insert {
                    deque.pop_back();
                } else {
                    break;
                }
            }
            deque.push_back(j);
        }

        max_tree_diam.max(max_cycle_path)
    }).sum();

    println!("{}", total_max_dist);
}

