        let mut buffer = Vec::new();
        io::stdin().read_to_end(&mut buffer).unwrap();
        Self { buffer, pos: 0 }
    }

    #[inline(always)]
    fn next_u32(&mut self) -> u32 {
        let mut res = 0;
        // Skip whitespace
        while self.pos < self.buffer.len() && self.buffer[self.pos] <= 32 {
            self.pos += 1;
        }
        // Read digits
        while self.pos < self.buffer.len() && self.buffer[self.pos] > 32 {
            res = res * 10 + (self.buffer[self.pos] - b'0') as u32;
            self.pos += 1;
        }
        res
    }

    #[inline(always)]
    fn next_usize(&mut self) -> usize {
        self.next_u32() as usize
    }
}

// LCT Implementation with u32 indices for better cache performance
struct LCT {
    p: Vec<u32>,
    ch: Vec<[u32; 2]>,
}

impl LCT {
    fn new(n: usize) -> Self {
        LCT {
            p: vec![0; n + 1],
            ch: vec![[0, 0]; n + 1],
        }
    }

    #[inline(always)]
    fn is_root(&self, x: u32) -> bool {
        let p = self.p[x as usize];
        p == 0 || (self.ch[p as usize][0] != x && self.ch[p as usize][1] != x)
    }

    #[inline(always)]
    fn rotate(&mut self, x: u32) {
        let y = self.p[x as usize];
        let z = self.p[y as usize];
        let k = if self.ch[y as usize][1] == x { 1 } else { 0 };

        if !self.is_root(y) {
            if self.ch[z as usize][1] == y { 
                self.ch[z as usize][1] = x; 
            } else { 
                self.ch[z as usize][0] = x; 
            }
        }
        self.p[x as usize] = z;

        let c = self.ch[x as usize][1 - k];
        self.ch[y as usize][k] = c;
        if c != 0 { self.p[c as usize] = y; }

        self.ch[x as usize][1 - k] = y;
        self.p[y as usize] = x;
    }

    fn splay(&mut self, x: u32) {
        while !self.is_root(x) {
            let y = self.p[x as usize];
            let z = self.p[y as usize];
            if !self.is_root(y) {
                if (self.ch[y as usize][1] == x) ^ (self.ch[z as usize][1] == y) {
                    self.rotate(x);
                } else {
                    self.rotate(y);
                }
            }
            self.rotate(x);
        }
    }

    fn access(&mut self, x: u32) {
        let mut t = 0;
        let mut curr = x;
        while curr != 0 {
            self.splay(curr);
            self.ch[curr as usize][1] = t;
            t = curr;
            curr = self.p[curr as usize];
        }
    }

    fn link(&mut self, child: u32, parent: u32) {
        self.access(child);
        self.splay(child);
        self.p[child as usize] = parent;
    }

    fn cut(&mut self, u: u32) {
        self.access(u);
        self.splay(u);
        let left = self.ch[u as usize][0];
        if left != 0 {
            self.p[left as usize] = 0;
            self.ch[u as usize][0] = 0;
        }
    }

    fn find_root(&mut self, x: u32) -> u32 {
        self.access(x);
        self.splay(x);
        let mut curr = x;
        while self.ch[curr as usize][0] != 0 {
            curr = self.ch[curr as usize][0];
        }
        self.splay(curr);
        curr
    }
}

