// Link-Cut Tree implementation for Rooted Trees
// We only need link (child->parent), cut (child->parent), and find_root.
struct LCT {
    p: Vec<usize>,
    ch: Vec<[usize; 2]>,
}

impl LCT {
    fn new(n: usize) -> Self {
        LCT {
            p: vec![0; n + 1],
            ch: vec![[0, 0]; n + 1],
        }
    }

    #[inline(always)]
    fn is_root(&self, x: usize) -> bool {
        let p = self.p[x];
        p == 0 || (self.ch[p][0] != x && self.ch[p][1] != x)
    }

    #[inline(always)]
    fn rotate(&mut self, x: usize) {
        let y = self.p[x];
        let z = self.p[y];
        let k = if self.ch[y][1] == x { 1 } else { 0 };

        if !self.is_root(y) {
            if self.ch[z][1] == y { self.ch[z][1] = x; } else { self.ch[z][0] = x; }
        }
        self.p[x] = z;

        self.ch[y][k] = self.ch[x][1 - k];
        if self.ch[x][1 - k] != 0 { self.p[self.ch[x][1 - k]] = y; }

        self.ch[x][1 - k] = y;
        self.p[y] = x;
    }

    fn splay(&mut self, x: usize) {
        while !self.is_root(x) {
            let y = self.p[x];
            let z = self.p[y];
            if !self.is_root(y) {
                if (self.ch[y][1] == x) ^ (self.ch[z][1] == y) {
                    self.rotate(x);
                } else {
                    self.rotate(y);
                }
            }
            self.rotate(x);
        }
    }

    fn access(&mut self, x: usize) {
        let mut t = 0;
        let mut curr = x;
        while curr != 0 {
            self.splay(curr);
            self.ch[curr][1] = t;
            t = curr;
            curr = self.p[curr];
        }
    }

    fn find_root(&mut self, x: usize) -> usize {
        self.access(x);
        self.splay(x);
        let mut curr = x;
        while self.ch[curr][0] != 0 {
            curr = self.ch[curr][0];
        }
        self.splay(curr);
        curr
    }

    fn link(&mut self, x: usize, y: usize) {
        self.access(x);
        self.splay(x);
        self.p[x] = y;
    }

    fn cut(&mut self, x: usize) {
        self.access(x);
        self.splay(x);
        let left = self.ch[x][0];
        if left != 0 {
            self.p[left] = 0;
            self.ch[x][0] = 0;
        }
    }
}

