// High-performance Input Scanner
struct Scanner {
    buffer: Vec<u8>,
    pos: usize,
}

impl Scanner {
    fn new() -> Self {
        let mut buffer = Vec::new();
        io::stdin().read_to_end(&mut buffer).unwrap();
        Self { buffer, pos: 0 }
    }

    #[inline(always)]
    fn next_u32(&mut self) -> u32 {
        let mut res = 0;
        while self.pos < self.buffer.len() && self.buffer[self.pos] <= 32 {
            self.pos += 1;
        }
        while self.pos < self.buffer.len() && self.buffer[self.pos] > 32 {
            res = res * 10 + (self.buffer[self.pos] - b'0') as u32;
            self.pos += 1;
        }
        res
    }

    #[inline(always)]
    fn next_usize(&mut self) -> usize {
        self.next_u32() as usize
    }
}

// Flattened LCT Implementation
// ch[u*2] is left child, ch[u*2+1] is right child
struct LCT {
    p: Vec<u32>,
    ch: Vec<u32>,
}

impl LCT {
    fn new(n: usize) -> Self {
        LCT {
            p: vec![0; n + 1],
            ch: vec![0; (n + 1) * 2],
        }
    }

    #[inline(always)]
    fn is_root(&self, x: usize) -> bool {
        let p = self.p[x] as usize;
        // p == 0 means x is a root of a represented tree (and aux tree)
        // OR x is a child of p in represented tree but p's children in aux tree don't include x
        p == 0 || (self.ch[p << 1] as usize != x && self.ch[(p << 1) | 1] as usize != x)
    }

    #[inline(always)]
    fn rotate(&mut self, x: usize) {
        let y = self.p[x] as usize;
        let z = self.p[y] as usize;
        let k = if self.ch[(y << 1) | 1] as usize == x { 1 } else { 0 };

        if !self.is_root(y) {
            if self.ch[(z << 1) | 1] as usize == y {
                self.ch[(z << 1) | 1] = x as u32;
            } else {
                self.ch[z << 1] = x as u32;
            }
        }
        self.p[x] = z as u32;

        let c = self.ch[(x << 1) | (1 - k)] as usize;
        self.ch[(y << 1) | k] = c as u32;
        if c != 0 { self.p[c] = y as u32; }

        self.ch[(x << 1) | (1 - k)] = y as u32;
        self.p[y] = x as u32;
    }

    fn splay(&mut self, x: usize) {
        while !self.is_root(x) {
            let y = self.p[x] as usize;
            let z = self.p[y] as usize;
            if !self.is_root(y) {
                if (self.ch[(y << 1) | 1] as usize == x) ^ (self.ch[(z << 1) | 1] as usize == y) {
                    self.rotate(x);
                } else {
                    self.rotate(y);
                }
            }
            self.rotate(x);
        }
    }

    fn access(&mut self, x: usize) {
        let mut t = 0;
        let mut curr = x;
        while curr != 0 {
            self.splay(curr);
            self.ch[(curr << 1) | 1] = t as u32;
            t = curr;
            curr = self.p[curr] as usize;
        }
    }

    fn link(&mut self, x: usize, y: usize) {
        self.access(x);
        self.splay(x);
        self.p[x] = y as u32;
    }

    fn cut(&mut self, x: usize) {
        self.access(x);
        self.splay(x);
        let left = self.ch[x << 1] as usize;
        if left != 0 {
            self.p[left] = 0;
            self.ch[x << 1] = 0;
        }
    }

    fn find_root(&mut self, x: usize) -> usize {
        self.access(x);
        self.splay(x);
        let mut curr = x;
        while self.ch[curr << 1] != 0 {
            curr = self.ch[curr << 1] as usize;
        }
        self.splay(curr);
        curr
    }
}

