    #[inline]
    fn update(&mut self, x: usize) {
        let left = self.ch[x][0];
        let right = self.ch[x][1];
        let sum_left = if left != 0 { self.sum[left] } else { 0 };
        let sum_right = if right != 0 { self.sum[right] } else { 0 };
        self.sum[x] = self.val[x] + self.vir[x] + sum_left + sum_right;
    }

    fn rotate(&mut self, x: usize) {
        let y = self.p[x];
        let z = self.p[y];
        let k = if self.ch[y][1] == x { 1 } else { 0 };

        if !self.is_root(y) {
            if self.ch[z][1] == y { self.ch[z][1] = x; } else { self.ch[z][0] = x; }
        }
        self.p[x] = z;

        self.ch[y][k] = self.ch[x][1 - k];
        if self.ch[x][1 - k] != 0 { self.p[self.ch[x][1 - k]] = y; }

        self.ch[x][1 - k] = y;
        self.p[y] = x;

        self.update(y);
        self.update(x);
    }

    fn splay(&mut self, x: usize) {
        self.push_all(x);
        while !self.is_root(x) {
            let y = self.p[x];
            let z = self.p[y];
            if !self.is_root(y) {
                if (self.ch[y][1] == x) ^ (self.ch[z][1] == y) {
                    self.rotate(x);
                } else {
                    self.rotate(y);
                }
            }
            self.rotate(x);
        }
    }

    fn access(&mut self, x: usize) {
        let mut t = 0;
        let mut curr = x;
        while curr != 0 {
            self.splay(curr);
            let right = self.ch[curr][1];
            if right != 0 {
                self.vir[curr] += self.sum[right];
            }
            if t != 0 {
                self.vir[curr] -= self.sum[t];
            }
            self.ch[curr][1] = t;
            self.update(curr);
            t = curr;
            curr = self.p[curr];
        }
    }

    fn make_root(&mut self, x: usize) {
        self.access(x);
        self.splay(x);
        self.rev[x] = !self.rev[x];
    }

    fn link(&mut self, x: usize, y: usize) {
        self.make_root(x);
        self.make_root(y);
        self.p[x] = y;
        self.vir[y] += self.sum[x];
        self.update(y);
    }

    fn cut(&mut self, x: usize, y: usize) {
        self.make_root(x);
        self.access(y);
        self.splay(y);
        if self.ch[y][0] == x {
            self.ch[y][0] = 0;
            self.p[x] = 0;
            self.update(y);
        }
    }

    fn query(&mut self, x: usize) -> u64 {
        self.make_root(x);
        self.sum[x]
    }

    fn add_val(&mut self, x: usize, v: u64) {
        self.make_root(x);
        self.val[x] += v;
        self.update(x);
    }

    fn sub_val(&mut self, x: usize, v: u64) {
        self.make_root(x);
        self.val[x] -= v;
        self.update(x);
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_whitespace();

    let n: usize = iter.next().unwrap().parse().unwrap();
