use std::io::{self, Read, Write};
use rayon::prelude::*;

// High-performance Input Scanner
struct Scanner {
    buffer: Vec<u8>,
    pos: usize,
}

impl Scanner {
    fn new() -> Self {
        let mut buffer = Vec::new();
        io::stdin().read_to_end(&mut buffer).unwrap();
        Self { buffer, pos: 0 }
    }

    #[inline(always)]
    fn next_u32(&mut self) -> u32 {
        let mut res = 0;
        while self.pos < self.buffer.len() && self.buffer[self.pos] <= 32 {
            self.pos += 1;
        }
        while self.pos < self.buffer.len() && self.buffer[self.pos] > 32 {
            res = res * 10 + (self.buffer[self.pos] - b'0') as u32;
            self.pos += 1;
        }
        res
    }

    #[inline(always)]
    fn next_usize(&mut self) -> usize {
        self.next_u32() as usize
    }
}

// Flattened LCT Implementation
// ch[u*2] is left child, ch[u*2+1] is right child
struct LCT {
    p: Vec<u32>,
    ch: Vec<u32>,
}

impl LCT {
    fn new(n: usize) -> Self {
        LCT {
            p: vec![0; n + 1],
            ch: vec![0; (n + 1) * 2],
        }
    }

    #[inline(always)]
    fn is_root(&self, x: usize) -> bool {
        let p = self.p[x] as usize;
        // p == 0 means x is a root of a represented tree (and aux tree)
        // OR x is a child of p in represented tree but p's children in aux tree don't include x
        p == 0 || (self.ch[p << 1] as usize != x && self.ch[(p << 1) | 1] as usize != x)
    }

    #[inline(always)]
    fn rotate(&mut self, x: usize) {
        let y = self.p[x] as usize;
        let z = self.p[y] as usize;
        let k = if self.ch[(y << 1) | 1] as usize == x { 1 } else { 0 };

        if !self.is_root(y) {
            if self.ch[(z << 1) | 1] as usize == y {
                self.ch[(z << 1) | 1] = x as u32;
            } else {
                self.ch[z << 1] = x as u32;
            }
        }
        self.p[x] = z as u32;

        let c = self.ch[(x << 1) | (1 - k)] as usize;
        self.ch[(y << 1) | k] = c as u32;
        if c != 0 { self.p[c] = y as u32; }

        self.ch[(x << 1) | (1 - k)] = y as u32;
        self.p[y] = x as u32;
    }

    fn splay(&mut self, x: usize) {
        while !self.is_root(x) {
            let y = self.p[x] as usize;
            let z = self.p[y] as usize;
            if !self.is_root(y) {
                if (self.ch[(y << 1) | 1] as usize == x) ^ (self.ch[(z << 1) | 1] as usize == y) {
                    self.rotate(x);
                } else {
                    self.rotate(y);
                }
            }
            self.rotate(x);
        }
    }

    fn access(&mut self, x: usize) {
        let mut t = 0;
        let mut curr = x;
        while curr != 0 {
            self.splay(curr);
            self.ch[(curr << 1) | 1] = t as u32;
            t = curr;
            curr = self.p[curr] as usize;
        }
    }

    fn link(&mut self, x: usize, y: usize) {
        self.access(x);
        self.splay(x);
        self.p[x] = y as u32;
    }

    fn cut(&mut self, x: usize) {
        self.access(x);
        self.splay(x);
        let left = self.ch[x << 1] as usize;
        if left != 0 {
            self.p[left] = 0;
            self.ch[x << 1] = 0;
        }
    }

    fn find_root(&mut self, x: usize) -> usize {
        self.access(x);
        self.splay(x);
        let mut curr = x;
        while self.ch[curr << 1] != 0 {
            curr = self.ch[curr << 1] as usize;
        }
        self.splay(curr);
        curr
    }
}

struct UnsafeSlice<T> {
    slice: *mut [T],
}
unsafe impl<T: Sync> Sync for UnsafeSlice<T> {}
impl<T> UnsafeSlice<T> {
    fn new(slice: &mut [T]) -> Self {
        Self { slice: slice as *mut [T] }
    }
    unsafe fn write(&self, idx: usize, value: T) {
        (*self.slice)[idx] = value;
    }
}

fn main() {
    let mut scanner = Scanner::new();
    let out = io::stdout();
    let mut out = io::BufWriter::new(out.lock());

    let n = scanner.next_usize();
    let m = scanner.next_usize();
    let q = scanner.next_usize();

    let mut adj = vec![Vec::new(); n + 1];
    for i in 1..n {
        let u = scanner.next_u32();
        let v = scanner.next_u32();
        adj[u as usize].push((v, i as u32));
        adj[v as usize].push((u, i as u32));
    }

    // BFS to establish parent-child relationships rooted at 1
    let mut parent = vec![0u32; n + 1];
    let mut edge_to_child = vec![0u32; n];
    let mut queue = std::collections::VecDeque::new();
    queue.push_back(1u32);
    let mut visited = vec![false; n + 1];
    visited[1] = true;

    while let Some(u) = queue.pop_front() {
        for &(v, idx) in &adj[u as usize] {
            if !visited[v as usize] {
                visited[v as usize] = true;
                parent[v as usize] = u;
                edge_to_child[idx as usize] = v;
                queue.push_back(v);
            }
        }
    }

    let mut lct = LCT::new(n);
    let mut ans = vec![1u32; n + 1];
    let mut removed = vec![0u32; n + 1];
    let mut is_active = vec![false; n];

    for _ in 0..m {
        let d = scanner.next_usize();
        let child = edge_to_child[d] as usize;
        let par = parent[child] as usize;

        if is_active[d] {
            // Cut
            let r = lct.find_root(par);
            let val = ans[r];
            ans[child] = val;
            removed[child] = val;
            lct.cut(child);
            is_active[d] = false;
        } else {
            // Link
            let r = lct.find_root(par);
            let gain = ans[child] - removed[child];
            ans[r] += gain;
            lct.link(child, par);
            is_active[d] = true;
        }
    }

    // Reconstruct the final active forest for propagation
    let mut final_children = vec![Vec::new(); n + 1];
    let mut roots = Vec::new();

    for i in 1..n {
        let child = edge_to_child[i] as usize;
        if is_active[i] {
            let par = parent[child] as usize;
            final_children[par].push(child as u32);
        } else {
            roots.push(child as u32);
        }
    }
    roots.push(1); // Root of the whole tree is always a component root

    let mut final_ans_vals = vec![0u32; n + 1];
    let unsafe_ans = UnsafeSlice::new(&mut final_ans_vals);

    // Parallel propagation
    roots.par_iter().for_each(|&r| {
        let val = ans[r as usize];
        let mut stack = Vec::new();
        stack.push(r);
        while let Some(u) = stack.pop() {
            unsafe { unsafe_ans.write(u as usize, val); }
            for &v in &final_children[u as usize] {
                stack.push(v);
            }
        }
    });

    for _ in 0..q {
        let c = scanner.next_usize();
        writeln!(out, "{}", final_ans_vals[c]).unwrap();
    }
}

