use std::io::{self, Read};
use rayon::prelude::*;

struct XorShift {
    state: u64,
}

impl XorShift {
    fn new(seed: u64) -> Self {
        Self { state: seed.max(1) }
    }
    fn next(&mut self) -> u64 {
        let mut x = self.state;
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        self.state = x;
        x
    }
}

#[derive(Clone, Copy)]
struct Node {
    l: u32,
    r: u32,
    p: u32,
    size: u32,
    prio: u64,
    dag_id: u32,
}

impl Node {
    fn new(prio: u64, dag_id: u32) -> Self {
        Self {
            l: 0, r: 0, p: 0,
            size: 1,
            prio,
            dag_id,
        }
    }
}

struct Treap {
    nodes: Vec<Node>,
    edge_map: Vec<(u32, u32)>,
    vertex_map: Vec<u32>,
    rng: XorShift,
}

impl Treap {
    fn new(n: usize) -> Self {
        let mut nodes = Vec::with_capacity(n + 2 * n + 100);
        nodes.push(Node::new(0, 0)); // Dummy 0
        let mut vertex_map = vec![0; n + 1];
        let mut rng = XorShift::new(123456789);

        for i in 1..=n {
            let idx = nodes.len() as u32;
            nodes.push(Node::new(rng.next(), i as u32));
            vertex_map[i] = idx;
        }

        Self {
            nodes,
            edge_map: vec![(0, 0); n], 
            vertex_map,
            rng,
        }
    }

    fn update(&mut self, u: u32) {
        if u == 0 { return; }
        let l = self.nodes[u as usize].l;
        let r = self.nodes[u as usize].r;
        let sz_l = if l != 0 { self.nodes[l as usize].size } else { 0 };
        let sz_r = if r != 0 { self.nodes[r as usize].size } else { 0 };
        self.nodes[u as usize].size = 1 + sz_l + sz_r;
        if l != 0 { self.nodes[l as usize].p = u; }
        if r != 0 { self.nodes[r as usize].p = u; }
    }

    fn split(&mut self, u: u32, k: u32) -> (u32, u32) {
        if u == 0 { return (0, 0); }
        let l = self.nodes[u as usize].l;
        let sz_l = if l != 0 { self.nodes[l as usize].size } else { 0 };

        if k <= sz_l {
            let (ll, rr) = self.split(l, k);
            self.nodes[u as usize].l = rr;
            self.nodes[u as usize].p = 0; 
            self.update(u);
            if ll != 0 { self.nodes[ll as usize].p = 0; }
            (ll, u)
        } else {
            let (ll, rr) = self.split(self.nodes[u as usize].r, k - 1 - sz_l);
            self.nodes[u as usize].r = ll;
            self.nodes[u as usize].p = 0;
            self.update(u);
            if rr != 0 { self.nodes[rr as usize].p = 0; }
            (u, rr)
        }
    }

    fn merge(&mut self, l: u32, r: u32) -> u32 {
        if l == 0 { return r; }
        if r == 0 { return l; }

        if self.nodes[l as usize].prio > self.nodes[r as usize].prio {
            let new_r = self.merge(self.nodes[l as usize].r, r);
            self.nodes[l as usize].r = new_r;
            self.update(l);
            l
        } else {
            let new_l = self.merge(l, self.nodes[r as usize].l);
            self.nodes[r as usize].l = new_l;
            self.update(r);
            r
        }
    }

    fn find_root(&self, mut u: u32) -> u32 {
        while self.nodes[u as usize].p != 0 {
            u = self.nodes[u as usize].p;
        }
        u
    }

    fn get_rank(&self, mut u: u32) -> u32 {
        let mut res = if self.nodes[u as usize].l != 0 { self.nodes[self.nodes[u as usize].l as usize].size } else { 0 };
        while self.nodes[u as usize].p != 0 {
            let p = self.nodes[u as usize].p;
            if self.nodes[p as usize].r == u {
                let sz_p_l = if self.nodes[p as usize].l != 0 { self.nodes[self.nodes[p as usize].l as usize].size } else { 0 };
                res += 1 + sz_p_l;
            }
            u = p;
        }
        res
    }

    fn reroot(&mut self, u_idx: u32) {
        let root = self.find_root(u_idx);
        let rank = self.get_rank(u_idx);
        if rank == 0 { return; } 

        let dag = self.nodes[root as usize].dag_id;
        let (l, r) = self.split(root, rank);
        let new_root = self.merge(r, l);
        self.nodes[new_root as usize].dag_id = dag;
    }

    fn link(&mut self, edge_idx: usize, u: usize, v: usize, new_dag_id: u32) {
        let n_uv = self.nodes.len() as u32;
        self.nodes.push(Node::new(self.rng.next(), 0));
        let n_vu = self.nodes.len() as u32;
        self.nodes.push(Node::new(self.rng.next(), 0));
        self.edge_map[edge_idx] = (n_uv, n_vu);

        let u_node = self.vertex_map[u];
        let v_node = self.vertex_map[v];

        self.reroot(u_node);
        self.reroot(v_node);

        let root_u = self.find_root(u_node);
        let root_v = self.find_root(v_node);

        let tmp = self.merge(root_u, n_uv);
        let tmp = self.merge(tmp, root_v);
        let final_root = self.merge(tmp, n_vu);

        self.nodes[final_root as usize].dag_id = new_dag_id;
    }

    fn cut(&mut self, edge_idx: usize) {
        let (n_uv, n_vu) = self.edge_map[edge_idx];
        let root = self.find_root(n_uv);
        let dag = self.nodes[root as usize].dag_id;

        let rank1 = self.get_rank(n_uv);
        let rank2 = self.get_rank(n_vu);

        let (first, second) = if rank1 < rank2 { (n_uv, n_vu) } else { (n_vu, n_uv) };
        let (r1, r2) = if rank1 < rank2 { (rank1, rank2) } else { (rank2, rank1) };

        let (temp, r) = self.split(root, r2 + 1);
        let (temp, _) = self.split(temp, r2);
        let (l, temp) = self.split(temp, r1 + 1);
        let (l, _) = self.split(l, r1);

        let new_root1 = self.merge(l, r);
        let new_root2 = temp;

        if new_root1 != 0 { self.nodes[new_root1 as usize].dag_id = dag; }
        if new_root2 != 0 { self.nodes[new_root2 as usize].dag_id = dag; }
    }

    fn get_dag(&self, u: usize) -> u32 {
        let node = self.vertex_map[u];
        let root = self.find_root(node);
        self.nodes[root as usize].dag_id
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_whitespace();

    let n: usize = iter.next().unwrap().parse().unwrap();
    let m: usize = iter.next().unwrap().parse().unwrap();
    let q: usize = iter.next().unwrap().parse().unwrap();

    let mut edges = Vec::with_capacity(n);
    edges.push((0, 0));
    for _ in 0..n-1 {
        let u: usize = iter.next().unwrap().parse().unwrap();
        let v: usize = iter.next().unwrap().parse().unwrap();
        edges.push((u, v));
    }

    let mut changes = Vec::with_capacity(m);
    for _ in 0..m {
        changes.push(iter.next().unwrap().parse::<usize>().unwrap());
    }

    let mut queries = Vec::with_capacity(q);
    for _ in 0..q {
        queries.push(iter.next().unwrap().parse::<usize>().unwrap());
    }

    let mut dag_parents = Vec::with_capacity(n + m + 1);
    dag_parents.push((u32::MAX, u32::MAX));
    for _ in 1..=n {
        dag_parents.push((u32::MAX, u32::MAX));
    }

    let mut treap = Treap::new(n);
    let mut is_active = vec![false; n];

    for &edge_idx in &changes {
        let (u, v) = edges[edge_idx];
        if !is_active[edge_idx] {
            let r_u = treap.find_root(treap.vertex_map[u]);
            let r_v = treap.find_root(treap.vertex_map[v]);

            if r_u != r_v {
                let d_u = treap.nodes[r_u as usize].dag_id;
                let d_v = treap.nodes[r_v as usize].dag_id;
                let new_dag = dag_parents.len() as u32;
                dag_parents.push((d_u, d_v));

                treap.link(edge_idx, u, v, new_dag);
            }
            is_active[edge_idx] = true;
        } else {
            treap.cut(edge_idx);
            is_active[edge_idx] = false;
        }
    }

    let mut query_targets = Vec::with_capacity(q);
    for &c in &queries {
        query_targets.push(treap.get_dag(c));
    }

    let total_dag_nodes = dag_parents.len();
    let chunk_size = 256; 
    let num_chunks = (n + chunk_size - 1) / chunk_size;

    let results: Vec<Vec<u32>> = (0..num_chunks).into_par_iter().map(|chunk_idx| {
        let start_bit = chunk_idx * chunk_size;
        let end_bit = std::cmp::min(start_bit + chunk_size, n);
        let width = end_bit - start_bit;
        if width == 0 { return Vec::new(); }

        let u64_count = (width + 63) / 64;
        let mut reach = vec![0u64; total_dag_nodes * u64_count];

        for i in 0..width {
            let source = start_bit + i + 1;
            let idx = source * u64_count + (i / 64);
            reach[idx] |= 1 << (i % 64);
        }

        for i in (n + 1)..total_dag_nodes {
            let (p1, p2) = dag_parents[i];
            let base_i = i * u64_count;

            if p1 != u32::MAX {
                let base_p1 = (p1 as usize) * u64_count;
                for k in 0..u64_count {
                    reach[base_i + k] |= reach[base_p1 + k];
                }
            }
            if p2 != u32::MAX {
                let base_p2 = (p2 as usize) * u64_count;
                for k in 0..u64_count {
                    reach[base_i + k] |= reach[base_p2 + k];
                }
            }
        }

        let mut chunk_counts = vec![0u32; total_dag_nodes];
        for i in 0..total_dag_nodes {
            let base = i * u64_count;
            let mut c = 0;
            for k in 0..u64_count {
                c += reach[base + k].count_ones();
            }
            chunk_counts[i] = c;
        }
        chunk_counts
    }).collect();

    for &target in &query_targets {
