use std::io::{self, Read, Write};
use rayon::prelude::*;

struct LCT {
    p: Vec<usize>,
    ch: Vec<[usize; 2]>,
    val: Vec<i64>,
    sum: Vec<i64>,
    vir: Vec<i64>,
    rev: Vec<bool>,
}

impl LCT {
    fn new(n: usize, initial_vals: &[i64]) -> Self {
        let mut lct = LCT {
            p: vec![0; n + 1],
            ch: vec![[0, 0]; n + 1],
            val: vec![0; n + 1],
            sum: vec![0; n + 1],
            vir: vec![0; n + 1],
            rev: vec![false; n + 1],
        };
        for i in 1..=n {
            lct.val[i] = initial_vals[i];
            lct.sum[i] = initial_vals[i];
        }
        lct
    }

    #[inline]
    fn is_root(&self, x: usize) -> bool {
        let p = self.p[x];
        p == 0 || (self.ch[p][0] != x && self.ch[p][1] != x)
    }

    #[inline]
    fn push(&mut self, x: usize) {
        if self.rev[x] {
            self.ch[x].swap(0, 1);
            let left = self.ch[x][0];
            let right = self.ch[x][1];
            if left != 0 { self.rev[left] = !self.rev[left]; }
            if right != 0 { self.rev[right] = !self.rev[right]; }
            self.rev[x] = false;
        }
    }

    fn push_all(&mut self, x: usize) {
        let mut stack = Vec::with_capacity(64);
        let mut curr = x;
        stack.push(curr);
        while !self.is_root(curr) {
            curr = self.p[curr];
            stack.push(curr);
        }
        while let Some(node) = stack.pop() {
            self.push(node);
        }
    }

    #[inline]
    fn update(&mut self, x: usize) {
        let left = self.ch[x][0];
        let right = self.ch[x][1];
        let sum_left = if left != 0 { self.sum[left] } else { 0 };
        let sum_right = if right != 0 { self.sum[right] } else { 0 };
        self.sum[x] = self.val[x] + self.vir[x] + sum_left + sum_right;
    }

    fn rotate(&mut self, x: usize) {
        let y = self.p[x];
        let z = self.p[y];
        let k = if self.ch[y][1] == x { 1 } else { 0 };

        if !self.is_root(y) {
            if self.ch[z][1] == y { self.ch[z][1] = x; } else { self.ch[z][0] = x; }
        }
        self.p[x] = z;

        self.ch[y][k] = self.ch[x][1 - k];
        if self.ch[x][1 - k] != 0 { self.p[self.ch[x][1 - k]] = y; }

        self.ch[x][1 - k] = y;
        self.p[y] = x;

        self.update(y);
        self.update(x);
    }

    fn splay(&mut self, x: usize) {
        self.push_all(x);
        while !self.is_root(x) {
            let y = self.p[x];
            let z = self.p[y];
            if !self.is_root(y) {
                if (self.ch[y][1] == x) ^ (self.ch[z][1] == y) {
                    self.rotate(x);
                } else {
                    self.rotate(y);
                }
            }
            self.rotate(x);
        }
    }

    fn access(&mut self, x: usize) {
        let mut t = 0;
        let mut curr = x;
        while curr != 0 {
            self.splay(curr);
            let right = self.ch[curr][1];
            if right != 0 {
                self.vir[curr] += self.sum[right];
            }
            if t != 0 {
                self.vir[curr] -= self.sum[t];
            }
            self.ch[curr][1] = t;
            self.update(curr);
            t = curr;
            curr = self.p[curr];
        }
    }

    fn make_root(&mut self, x: usize) {
        self.access(x);
        self.splay(x);
        self.rev[x] = !self.rev[x];
    }

    fn link(&mut self, x: usize, y: usize) {
        self.make_root(x);
        self.make_root(y);
        self.p[x] = y;
        self.vir[y] += self.sum[x];
        self.update(y);
    }

    fn cut(&mut self, x: usize, y: usize) {
        self.make_root(x);
        self.access(y);
        self.splay(y);
        if self.ch[y][0] == x {
            self.ch[y][0] = 0;
            self.p[x] = 0;
            self.update(y);
        }
    }

    fn query(&mut self, x: usize) -> i64 {
        self.make_root(x);
        self.sum[x]
    }

    fn add_val(&mut self, x: usize, v: i64) {
        self.make_root(x);
        self.val[x] += v;
        self.update(x);
    }
}

// Simple DSU for final component aggregation
struct DSU {
    parent: Vec<usize>,
    vals: Vec<i64>,
}

impl DSU {
    fn new(n: usize, initial_vals: &[i64]) -> Self {
        DSU {
            parent: (0..=n).collect(),
            vals: initial_vals.to_vec(),
        }
    }

    fn find(&mut self, i: usize) -> usize {
        if self.parent[i] == i {
            i
        } else {
            let p = self.parent[i];
            self.parent[i] = self.find(p);
            self.parent[i]
        }
    }

    fn union(&mut self, i: usize, j: usize) {
        let root_i = self.find(i);
        let root_j = self.find(j);
        if root_i != root_j {
            self.parent[root_i] = root_j;
            self.vals[root_j] += self.vals[root_i];
        }
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let mut iter = input.split_whitespace();

    let n: usize = iter.next().unwrap().parse().unwrap();
    let m: usize = iter.next().unwrap().parse().unwrap();
    let q: usize = iter.next().unwrap().parse().unwrap();

    let mut edges = Vec::with_capacity(n);
    edges.push((0, 0));

    for _ in 0..n-1 {
        let u: usize = iter.next().unwrap().parse().unwrap();
        let v: usize = iter.next().unwrap().parse().unwrap();
        edges.push((u, v));
    }

    // Initial values are 1 for all servers
    let mut init_vals = vec![0i64; n + 1];
    for i in 1..=n { init_vals[i] = 1; }

    let mut lct = LCT::new(n, &init_vals);

    let mut edge_vals = vec![(0i64, 0i64); n];
    let mut is_active = vec![false; n];

    // Process updates
    for _ in 0..m {
        let d: usize = iter.next().unwrap().parse().unwrap();
        let (u, v) = edges[d];

        if !is_active[d] {
            let (val_uv, val_vu) = edge_vals[d];
            lct.add_val(u, -val_uv);
            lct.add_val(v, -val_vu);
            lct.link(u, v);
            is_active[d] = true;
        } else {
            lct.cut(u, v);
            let res_v = lct.query(v);
            let res_u = lct.query(u);
            edge_vals[d] = (res_v, res_u);
            lct.add_val(u, res_v);
            lct.add_val(v, res_u);
            is_active[d] = false;
        }
    }

    // Final state computation
    // We have the final values in lct.val and the final active edges in is_active
    // We need to compute component sums.

    let final_vals = &lct.val;
    let mut dsu = DSU::new(n, final_vals);

    for i in 1..n {
        if is_active[i] {
            let (u, v) = edges[i];
            dsu.union(u, v);
        }
    }

    // Flatten DSU to prepare for parallel queries
    for i in 1..=n {
        dsu.find(i);
    }

    let parents = dsu.parent;
    let component_vals = dsu.vals;

    let queries: Vec<usize> = (0..q).map(|_| iter.next().unwrap().parse().unwrap()).collect();

    let results: Vec<i64> = queries.into_par_iter()
        .map(|c| component_vals[parents[c]])
        .collect();

    let mut out = io::stdout();
    let mut out_lock = io::BufWriter::new(out.lock());

    for res in results {
        writeln!(out_lock, "{}", res).unwrap();
    }
}

