// --- Fast IO ---
struct Scanner {
    buffer: Vec<u8>,
    ptr: *const u8,
    end: *const u8,
}

impl Scanner {
    fn new() -> Self {
        let mut buffer = Vec::new();
        io::stdin().read_to_end(&mut buffer).unwrap();
        let ptr = buffer.as_ptr();
        let end = unsafe { ptr.add(buffer.len()) };
        Self { buffer, ptr, end }
    }

    #[inline(always)]
    fn next_u32(&mut self) -> u32 {
        let mut res = 0;
        unsafe {
            while self.ptr < self.end && *self.ptr <= b' ' {
                self.ptr = self.ptr.add(1);
            }
            while self.ptr < self.end && *self.ptr > b' ' {
                res = res * 10 + (*self.ptr - b'0') as u32;
                self.ptr = self.ptr.add(1);
            }
        }
        res
    }

    #[inline(always)]
    fn next_usize(&mut self) -> usize {
        self.next_u32() as usize
    }
}

// --- LCT ---
// Rooted forest LCT. No make_root, no reverse.
// Uses unsafe indexing for speed.
struct LCT {
    p: Vec<u32>,
    ch: Vec<[u32; 2]>,
}

impl LCT {
    fn new(n: usize) -> Self {
        LCT {
            p: vec![0; n + 1],
            ch: vec![[0, 0]; n + 1],
        }
    }

    #[inline(always)]
    unsafe fn is_root(&self, x: usize) -> bool {
        let p = *self.p.get_unchecked(x) as usize;
        // Check if x is a child of p in the LCT structure
        if p == 0 {
            return true;
        }
        let ch = self.ch.get_unchecked(p);
        ch[0] as usize != x && ch[1] as usize != x
    }

    #[inline(always)]
    unsafe fn rotate(&mut self, x: usize) {
        let ptr = self.ch.as_mut_ptr();
        let p_ptr = self.p.as_mut_ptr();

        let y = *p_ptr.add(x) as usize;
        let z = *p_ptr.add(y) as usize;

        let ch_y = &mut *ptr.add(y);
        let k = if ch_y[1] as usize == x { 1 } else { 0 };

        if !self.is_root(y) {
            let ch_z = &mut *ptr.add(z);
            if ch_z[1] as usize == y { 
                ch_z[1] = x as u32; 
            } else { 
                ch_z[0] = x as u32; 
            }
        }
        *p_ptr.add(x) = z as u32;

        let ch_x = &mut *ptr.add(x);
        let c = ch_x[1 - k];

        // ch[y][k] = c
        (*ptr.add(y))[k] = c;
        if c != 0 { *p_ptr.add(c as usize) = y as u32; }

        // ch[x][1-k] = y
        (*ptr.add(x))[1 - k] = y as u32;
        *p_ptr.add(y) = x as u32;
    }

    unsafe fn splay(&mut self, x: usize) {
        while !self.is_root(x) {
            let y = *self.p.get_unchecked(x) as usize;
            let z = *self.p.get_unchecked(y) as usize;
            if !self.is_root(y) {
                let y_ch = self.ch.get_unchecked(y);
                let z_ch = self.ch.get_unchecked(z);
                // Zig-zig or Zig-zag
                if (y_ch[1] as usize == x) ^ (z_ch[1] as usize == y) {
                    self.rotate(x);
                } else {
                    self.rotate(y);
                }
            }
            self.rotate(x);
        }
    }

    unsafe fn access(&mut self, mut x: usize) {
        let mut t = 0;
        while x != 0 {
            self.splay(x);
            self.ch.get_unchecked_mut(x)[1] = t as u32;
            t = x;
            x = *self.p.get_unchecked(x) as usize;
        }
    }

    unsafe fn link(&mut self, child: usize, parent: usize) {
        self.access(child);
        self.splay(child);
        *self.p.get_unchecked_mut(child) = parent as u32;
    }

    unsafe fn cut(&mut self, u: usize) {
        self.access(u);
        self.splay(u);
        let left = self.ch.get_unchecked(u)[0] as usize;
        if left != 0 {
            *self.p.get_unchecked_mut(left) = 0;
            self.ch.get_unchecked_mut(u)[0] = 0;
        }
    }

    unsafe fn find_root(&mut self, mut x: usize) -> usize {
        self.access(x);
        self.splay(x);
        while {
            let left = self.ch.get_unchecked(x)[0] as usize;
            left != 0
        } {
            x = self.ch.get_unchecked(x)[0] as usize;
        }
        self.splay(x);
        x
    }
}

// Unsafe slice for parallel writing
struct UnsafeSlice<T> {
    slice: *mut [T],
}
unsafe impl<T: Sync> Sync for UnsafeSlice<T> {}
impl<T> UnsafeSlice<T> {
    fn new(slice: &mut [T]) -> Self {
        Self { slice: slice as *mut [T] }
    }
    unsafe fn write(&self, idx: usize, value: T) {
        (*self.slice)[idx] = value;
    }
}

fn main() {
    let mut scanner = Scanner::new();
    let stdout = io::stdout();
    let mut out = io::BufWriter::new(stdout.lock());

    let n = scanner.next_usize();
    let m = scanner.next_usize();
    let q = scanner.next_usize();

    // 1-based nodes
    // Build tree structure first
    let mut adj = vec![Vec::new(); n + 1];
    for i in 1..n {
        let u = scanner.next_u32();
        let v = scanner.next_u32();
        adj[u as usize].push((v, i as u32));
        adj[v as usize].push((u, i as u32));
    }

    // BFS to determine parent pointers and edge mapping
    let mut parent = vec![0u32; n + 1];
    let mut edge_to_child = vec![0u32; n];
    let mut queue = std::collections::VecDeque::new();
    queue.push_back(1);
    let mut visited = vec![false; n + 1];
    visited[1] = true;

    while let Some(u) = queue.pop_front() {
        for &(v, edge_idx) in &adj[u as usize] {
            if !visited[v as usize] {
                visited[v as usize] = true;
                parent[v as usize] = u;
                edge_to_child[edge_idx as usize] = v;
                queue.push_back(v);
            }
        }
    }

    // Process updates
    let mut lct = LCT::new(n);
    let mut ans = vec![1u32; n + 1];
    let mut removed = vec![0u32; n + 1];
    let mut is_active = vec![false; n];

    for _ in 0..m {
        let d = scanner.next_usize();
        let child = edge_to_child[d] as usize;
        let par = parent[child] as usize;

        unsafe {
            if is_active[d] {
                // Cut
                let r = lct.find_root(par);
                let val = *ans.get_unchecked(r);
                *ans.get_unchecked_mut(child) = val;
                *removed.get_unchecked_mut(child) = val;
                lct.cut(child);
                is_active[d] = false;
            } else {
                // Link
                let r = lct.find_root(par);
                let gain = *ans.get_unchecked(child) - *removed.get_unchecked(child);
                *ans.get_unchecked_mut(r) += gain;
                lct.link(child, par);
                is_active[d] = true;
            }
        }
    }

    // Final propagation
    // Build adjacency for final active edges
    let mut final_adj = vec![Vec::new(); n + 1];
    let mut roots = Vec::new();

    for i in 1..n {
        let child = edge_to_child[i] as usize;
        if is_active[i] {
            let par = parent[child] as usize;
            final_adj[par].push(child as u32);
        } else {
            roots.push(child as u32);
        }
    }
    roots.push(1);

    let mut final_ans_vals = vec![0u32; n + 1];
    let unsafe_ans = UnsafeSlice::new(&mut final_ans_vals);

    // Process each component in parallel
    roots.par_iter().for_each(|&r| {
        let r_idx = r as usize;
        let val = ans[r_idx];

        let mut stack = Vec::with_capacity(16);
        stack.push(r);

        while let Some(u) = stack.pop() {
            unsafe { unsafe_ans.write(u as usize, val); }
            for &v in &final_adj[u as usize] {
                stack.push(v);
            }
        }
    });

    for _ in 0..q {
        let c = scanner.next_usize();
        writeln!(out, "{}", final_ans_vals[c]).unwrap();
    }
}

