                *removed.get_unchecked_mut(child) = val;
                lct.cut(child);
                is_active[d] = false;
            } else {
                // Link
                let r = lct.find_root(par);
                let gain = *ans.get_unchecked(child) - *removed.get_unchecked(child);
                *ans.get_unchecked_mut(r) += gain;
                lct.link(child, par);
                is_active[d] = true;
            }
        }
    }

    // Final propagation
    // Build adjacency for final active edges
    let mut final_adj = vec![Vec::new(); n + 1];
    let mut roots = Vec::new();

    for i in 1..n {
        let child = edge_to_child[i] as usize;
        if is_active[i] {
            let par = parent[child] as usize;
            final_adj[par].push(child as u32);
        } else {
            roots.push(child as u32);
        }
    }
    roots.push(1);

    let mut final_ans_vals = vec![0u32; n + 1];
    let unsafe_ans = UnsafeSlice::new(&mut final_ans_vals);

    // Process each component in parallel
    roots.par_iter().for_each(|&r| {
        let r_idx = r as usize;
        let val = ans[r_idx];

        let mut stack = Vec::with_capacity(16);
        stack.push(r);

        while let Some(u) = stack.pop() {
            unsafe { unsafe_ans.write(u as usize, val); }
            for &v in &final_adj[u as usize] {
                stack.push(v);
            }
        }
    });

    for _ in 0..q {
        let c = scanner.next_usize();
        writeln!(out, "{}", final_ans_vals[c]).unwrap();
    }
